INSERT INTO transcript_chunks (lesson_id, chunk_text, start_time, end_time)
SELECT
    l.id AS lesson_id,
    segment.value->>'text' AS chunk_text,
    (segment.value->>'start')::numeric AS start_time,
    (segment.value->>'end')::numeric AS end_time
FROM lessons l
CROSS JOIN jsonb_array_elements(
    '[{"start":0,"end":4.8,"text":"So you just ran git merge or git pull and you got one of those dreaded merge conflicts."},{"start":4.8,"end":7.52,"text":"No! No!"},{"start":7.52,"end":12,"text":"In this video I''ll show you what I wish someone had explained to me when I started out using git."},{"start":12,"end":15.36,"text":"So first of all if you don''t have time right now to deal with the conflict"},{"start":15.36,"end":20.4,"text":"and you just want to abort the merge just run git merge abort which will just reset everything"},{"start":20.4,"end":24.64,"text":"to the same state it was before. Once you have more time and are ready to handle the conflict"},{"start":24.64,"end":29.52,"text":"you can just pull or merge again. In my example here I''m trying to merge the main branch into"},{"start":29.52,"end":34.4,"text":"the develop branch. To fix the merge conflict let''s first run git status. You''ll see that you''re"},{"start":34.4,"end":38.96,"text":"currently in a merge and you''ll see which files git wasn''t able to merge automatically. In my"},{"start":38.96,"end":45.2,"text":"example here git was able to auto merge the package.json file but not the other two files here."},{"start":45.2,"end":49.52,"text":"They''re conflicted so we have to merge them manually. I''ve already opened the javascript"},{"start":49.52,"end":54.08,"text":"file here in my text editor. I use visual studio code here but it really doesn''t matter which"},{"start":54.08,"end":59.36,"text":"editor you use. When git can''t auto merge a file it will put these angle brackets and"},{"start":59.36,"end":64.48,"text":"these equal signs into the file. These are called conflict markers. When I was still new to git"},{"start":64.48,"end":69.2,"text":"these conflict markers confused me quite a bit. I didn''t really understand what they meant and I"},{"start":69.2,"end":74.08,"text":"just tried to use the default buttons in my editor to fix things. I think it''s good to know that these"},{"start":74.08,"end":80.08,"text":"conflict markers are not part of the editor. Git will actually edit the file on disk and put these"},{"start":80.08,"end":85.12,"text":"angle brackets and equal signs into the file. It''s just that some editors display the file in a different"},{"start":85.12,"end":90.88,"text":"way making it easier to spot the conflict."}]'::jsonb
) AS segment
WHERE l.youtube_video_id = 'DloR0BOGNU0';

