INSERT INTO transcript_chunks (lesson_id, chunk_text, start_time, end_time)
SELECT
    l.id AS lesson_id,
    segment.value->>'text' AS chunk_text,
    (segment.value->>'start')::numeric AS start_time,
    (segment.value->>'end')::numeric AS end_time
FROM lessons l
CROSS JOIN jsonb_array_elements(
    '[{"start":0,"end":1.52,"text":"All right."},{"start":1.52,"end":2.68,"text":"Welcome to this seminar."},{"start":2.68,"end":4.48,"text":"It''s going to be about Git and GitHub, which"},{"start":4.48,"end":7.8,"text":"are technologies that you can use to do what''s called version control,"},{"start":7.8,"end":11.28,"text":"keeping track of different versions of your program, testing out new changes,"},{"start":11.28,"end":12.24,"text":"et cetera."},{"start":12.24,"end":12.76,"text":"All right."},{"start":12.76,"end":15.56,"text":"So before we get started, we''ll do a quick introduction"},{"start":15.56,"end":18.84,"text":"into what Git and GitHub is all about and what it can be used for."},{"start":18.84,"end":21.6,"text":"And then we''ll go more specifically into the command line commands"},{"start":21.6,"end":24.28,"text":"that you would use in order to use some of this technology"},{"start":24.28,"end":27.32,"text":"and leverage it for projects that you''re working on or projects that you''re"},{"start":27.32,"end":29.04,"text":"collaborating on with other people."},{"start":29.04,"end":30.68,"text":"So first of all, what is Git?"},{"start":30.68,"end":31.84,"text":"What can it do?"},{"start":31.84,"end":34.28,"text":"The first and one of the most important features for Git"},{"start":34.28,"end":36.96,"text":"is that it can keep track of changes to your code."},{"start":36.96,"end":40.08,"text":"So if you have code, you create a file, and maybe you''re making changes."},{"start":40.08,"end":42.4,"text":"Git will keep track of all of the different changes"},{"start":42.4,"end":44.6,"text":"that you''ve made to your code such that at any point,"},{"start":44.6,"end":47.64,"text":"you can kind of go back and see the history of whatever it is that you''ve"},{"start":47.64,"end":50.08,"text":"been working on to see what were your earlier changes"},{"start":50.08,"end":51.64,"text":"and when did you make those changes."},{"start":51.64,"end":54.24,"text":"And that can sometimes help when you''re going back and trying to debug"},{"start":54.24,"end":57.88,"text":"and figure out what went wrong at some stage in the code process."},{"start":57.92,"end":60.6,"text":"So that''s one thing that Git can be useful for."},{"start":60.6,"end":63.88,"text":"Another thing that it can be useful for is synchronizing code between different"},{"start":63.88,"end":66.84,"text":"people, especially when you''re collaborating with other people."},{"start":66.84,"end":70.76,"text":"Git is valuable for trying to make sure that your code potentially matches"},{"start":70.76,"end":72.92,"text":"the code that someone else is working on."},{"start":72.92,"end":75.88,"text":"And at any point, absolutely feel free to interrupt me if you have questions"},{"start":75.88,"end":79.32,"text":"and something doesn''t make sense and be happy to field questions as we go."},{"start":79.32,"end":82.88,"text":"So imagine that you and a collaborator are both"},{"start":82.88,"end":86.64,"text":"trying to work together kind of on the same piece of code at the same time."},{"start":86.64,"end":89.32,"text":"So maybe that code lives somewhere on some server."},{"start":89.32,"end":90.92,"text":"And there are a whole bunch of servers that"},{"start":90.92,"end":95.24,"text":"can host what we call Git repositories, just folders that contain files that"},{"start":95.24,"end":96.56,"text":"are tracked via Git."},{"start":96.56,"end":98.52,"text":"Git Hub is one example of that."},{"start":98.52,"end":102.4,"text":"So maybe both you and your partner need access to the same file."},{"start":102.4,"end":105.12,"text":"Maybe you both make changes to that same file."},{"start":105.12,"end":107.84,"text":"And what Git allows you to do is Git makes it very easy to then take"},{"start":107.84,"end":110.32,"text":"those changes that you both have made independently"},{"start":110.32,"end":113.32,"text":"and to kind of merge them back together when you push them back online"},{"start":113.32,"end":116.6,"text":"to the same file and then pull those back down to your own computers"},{"start":116.64,"end":120.52,"text":"so that you both have the latest changes, not only what you''ve changed on your file,"},{"start":120.52,"end":123.6,"text":"but also what a potential collaborator has made changes to as well."},{"start":123.6,"end":126.88,"text":"And you both have the most recent up-to-date version of the code."},{"start":126.88,"end":129.24,"text":"And so synchronizing code between different people"},{"start":129.24,"end":132.8,"text":"is another really valuable thing that Git can be used for."},{"start":132.8,"end":135.2,"text":"A third valuable thing that Git can be fantastic for"},{"start":135.2,"end":138.92,"text":"is to test changes to your code without losing the original."},{"start":138.92,"end":141.32,"text":"It''s all too common that I, before I started using Git,"},{"start":141.32,"end":143.88,"text":"would try making changes to code to try and make it better"},{"start":143.88,"end":146.48,"text":"and then suddenly find out that the code no longer works."},{"start":146.48,"end":149.96,"text":"And so my original solution to this was to do something like make a copy of my"},{"start":149.96,"end":153.36,"text":"original file, save the old one, and then make changes so that if it messed up,"},{"start":153.36,"end":156.24,"text":"I could go back to the original one and not lose the original."},{"start":156.24,"end":158.04,"text":"And that ends up getting very, very messy,"},{"start":158.04,"end":161.72,"text":"especially if you get into larger projects and working with multiple people."},{"start":161.72,"end":164.32,"text":"You''ll end up with a lot of different old versions,"},{"start":164.32,"end":166.12,"text":"and it might be hard to keep track of."},{"start":166.12,"end":169.76,"text":"So Git makes it very easy to save an original version of your code,"},{"start":169.76,"end":172.16,"text":"test out new changes that you might want to add,"},{"start":172.16,"end":174.84,"text":"and only when you''re sure that you like these changes that they work,"},{"start":174.84,"end":178.68,"text":"that you want to what''s called merge them back in with your original file,"},{"start":178.68,"end":181.64,"text":"can you merge them back with the original file that you were working on"},{"start":181.64,"end":183.24,"text":"in the first place."},{"start":183.24,"end":186.16,"text":"And the fourth and very valuable thing that Git can be useful for"},{"start":186.16,"end":189.52,"text":"is for reverting back changes to older versions of your code."},{"start":189.52,"end":192.44,"text":"Say you made a change to your code somewhere along the way"},{"start":192.44,"end":196.16,"text":"and realized later on that that''s not the change that you actually wanted to make"},{"start":196.16,"end":198.52,"text":"and that you would want to go back to an older version."},{"start":198.52,"end":202.12,"text":"Git makes it very easy as long as you know which version you want to go back to."},{"start":202.12,"end":205.6,"text":"You can just go back to that old version and kind of start over from wherever"},{"start":205.6,"end":206.84,"text":"you were previously."},{"start":206.84,"end":210.56,"text":"So that''s sort of an overview of kind of what Git is and the things"},{"start":210.56,"end":213.6,"text":"that Git can do for you if you leverage its functionality well."},{"start":213.6,"end":216.88,"text":"And now we''ll begin to go into the actual commands that you would need to use"},{"start":216.88,"end":221.44,"text":"and need to type in order to make all of this kind of work."},{"start":221.44,"end":223.84,"text":"Questions before we go on?"},{"start":223.84,"end":225.48,"text":"OK, fantastic."},{"start":225.48,"end":228,"text":"So first command that''ll be really valuable to know"},{"start":228,"end":230.04,"text":"is what''s called Git clone."},{"start":230.04,"end":232.16,"text":"Git clone is a command you would type at the command line"},{"start":232.16,"end":234.04,"text":"and I''ll show you how this works in a moment."},{"start":234.04,"end":239.84,"text":"And essentially what Git clone does is you type Git clone followed by some Git URL,"},{"start":239.84,"end":244.4,"text":"where that URL is the address of some GitHub repository."},{"start":244.4,"end":247.76,"text":"And remember, repository is just a collection of files and folders"},{"start":247.76,"end":249.72,"text":"that are being tracked by Git."},{"start":249.72,"end":253.32,"text":"And it''ll make a copy of that repository that lives somewhere on the internet,"},{"start":253.32,"end":254.64,"text":"potentially on GitHub."},{"start":254.64,"end":257.08,"text":"But there are also other services that do similar things."},{"start":257.12,"end":260.24,"text":"And it will make a copy of that repository on your computer."},{"start":260.24,"end":263.36,"text":"So you can begin to make changes on your own computer."},{"start":263.36,"end":267.64,"text":"And side note, you can also do something called creating a fork of a repository"},{"start":267.64,"end":271.68,"text":"where if someone else owns a repository online somewhere, you can fork it,"},{"start":271.68,"end":275.92,"text":"which just means you create kind of your own copy of that repository that also"},{"start":275.92,"end":277.44,"text":"lives online."},{"start":277.44,"end":279.76,"text":"But we''ll get to that potentially later."},{"start":279.76,"end":282.8,"text":"So if this is GitHub, imagine this being some kind of server."},{"start":282.8,"end":286.08,"text":"And this is a file that''s being tracked via Git in some Git repository."},{"start":286.08,"end":289.84,"text":"If I were to type Git clone followed by the URL of that repository,"},{"start":289.84,"end":292,"text":"then this file, I would clone it."},{"start":292,"end":294.28,"text":"And it would make a copy of the entire repository that"},{"start":294.28,"end":296.8,"text":"is now saved on my own computer."},{"start":296.8,"end":298.24,"text":"Make sense?"},{"start":298.24,"end":301.56,"text":"OK, fantastic."},{"start":301.56,"end":305,"text":"Next thing that''s important to know is a command called Git add."},{"start":305,"end":308.8,"text":"So Git add is what you would do after you''ve cloned a repository."},{"start":308.8,"end":311.52,"text":"And so now you have a copy of that repository on your computer."},{"start":311.52,"end":315.32,"text":"And say you''re making changes to that repository, changing the files,"},{"start":315.36,"end":316.52,"text":"changing the code."},{"start":316.52,"end":321.76,"text":"And now you want to say that the next time that Git saves a change"},{"start":321.76,"end":327.4,"text":"to this repository, you want Git to save the change that you made to that file."},{"start":327.4,"end":329.24,"text":"So it''s showing you what I mean by this."},{"start":329.24,"end":331,"text":"Let''s say that we''ve just cloned this file."},{"start":331,"end":333.36,"text":"So this file now exists on your computer."},{"start":333.36,"end":336.92,"text":"It''s being tracked by a Git repository."},{"start":336.92,"end":339.68,"text":"If I make a change to the code, maybe add a line to that code."},{"start":339.68,"end":343.48,"text":"And I want to say that get the next time you save a change to this repository,"},{"start":343.48,"end":345.6,"text":"I want you to track that change."},{"start":345.6,"end":348.84,"text":"You would say, Git add, followed by the name of the file,"},{"start":348.84,"end":351.24,"text":"whatever that file happens to be named."},{"start":351.24,"end":354.72,"text":"And then it would say changes to be committed."},{"start":354.72,"end":359.32,"text":"And it would track that this is a change that you now want to make to that code."},{"start":359.32,"end":362.4,"text":"So let me show you what that looks like really quickly."},{"start":362.4,"end":364.84,"text":"I have here a GitHub repository."},{"start":364.84,"end":369.08,"text":"So they usually live at some link like github.com slash some username."},{"start":369.08,"end":373.36,"text":"My username is bryanu28 slash whatever the name of the GitHub"},{"start":373.4,"end":374.24,"text":"repository is."},{"start":374.24,"end":377.2,"text":"In this case, this repository is just called Seminar."},{"start":377.2,"end":381.32,"text":"Up in the upper right-hand corner, you''ll see a button that says clone or download."},{"start":381.32,"end":385.96,"text":"And if you click on that link, it will give you a link that you can copy"},{"start":385.96,"end":389.36,"text":"in order to clone this repository to my own computer."},{"start":389.36,"end":390.88,"text":"And so I could copy this."},{"start":390.88,"end":392.96,"text":"And then I could go in to CS50 IDE."},{"start":392.96,"end":396.44,"text":"And then if I were to type git clone followed by that URL,"},{"start":396.44,"end":399.92,"text":"it would clone the repository and save it to my computer."},{"start":399.92,"end":402.76,"text":"In this case, I''ve already done it, so I''m not going to do it again."},{"start":402.8,"end":405.6,"text":"But you''ll see here I have this folder called Seminar."},{"start":405.6,"end":411.64,"text":"And that folder is just my copy of the repository that exists on GitHub."},{"start":411.64,"end":413.64,"text":"So we''ll take a look at the file that''s in here."},{"start":413.64,"end":417.04,"text":"There''s two files in here, but swap.c is the one that I''m interested in."},{"start":417.04,"end":419.48,"text":"You might recognize this file from a previous lecture."},{"start":419.48,"end":422.08,"text":"It was just the file where we kind of set two variables"},{"start":422.08,"end":424.92,"text":"equal to two different numbers in C, and we want to swap them."},{"start":424.92,"end":427.28,"text":"But what you''ll notice here is that this code is incomplete."},{"start":427.28,"end":430.76,"text":"It says swapping right now, but we don''t actually swap the values just yet."},{"start":430.76,"end":434.12,"text":"So what I''d like to do now is I''d like to add these chains."},{"start":434.12,"end":437.24,"text":"I''m going to change this code so that it actually swaps the two numbers."},{"start":437.24,"end":440.76,"text":"And then I want to git add those changes so that git"},{"start":440.76,"end":444.92,"text":"knows that this is a new version of the file that I want to save."},{"start":444.92,"end":447.96,"text":"So I''ll just quickly add the necessary code."},{"start":450.56,"end":453.64,"text":"And those three lines are going to swap the file."},{"start":453.64,"end":459.72,"text":"And so now, if I cd into the Seminar directory, what I can do"},{"start":459.76,"end":463.24,"text":"is I can add the changes that I just made."},{"start":463.24,"end":466.8,"text":"And git will then track those changes so I can save them in the future."},{"start":466.8,"end":469.52,"text":"And in fact, one kind of little tip that might be helpful"},{"start":469.52,"end":472.44,"text":"is that if I ever type git diff at the command line,"},{"start":472.44,"end":476.4,"text":"it will show me all of the changes that I''ve made that I haven''t tracked yet."},{"start":476.4,"end":478.72,"text":"So I type git diff, and it shows me down here"},{"start":478.72,"end":481.52,"text":"that these are the three lines highlighted in green that I''ve added."},{"start":481.52,"end":484.76,"text":"I added this in temp equals x, x equals y, and y equals temp."},{"start":484.76,"end":488.68,"text":"And those are now changes that the next time I add a file,"},{"start":488.72,"end":490.72,"text":"they''re going to be tracked by git."},{"start":490.72,"end":495.76,"text":"So I can do something like git add swap.c."},{"start":495.76,"end":498.96,"text":"And that will add the swap.c file as a file that I now"},{"start":498.96,"end":501.12,"text":"want to track the next time I save a change."},{"start":501.12,"end":503.44,"text":"So git add swap.c."},{"start":503.44,"end":508,"text":"And so that now has been added to the changes that I want to track."},{"start":508,"end":509.6,"text":"So what''s the next step?"},{"start":509.6,"end":511.88,"text":"The next step is called git commit."},{"start":511.88,"end":514.68,"text":"Once I''ve added all the files that I now want to save,"},{"start":514.68,"end":516.92,"text":"now I need to actually make the save."},{"start":516.92,"end":519.4,"text":"So git commit, you might think of the equivalent of telling"},{"start":519.4,"end":522.88,"text":"git to save a version of this repository."},{"start":522.88,"end":524.92,"text":"So the syntax looks something like this."},{"start":524.92,"end":528.16,"text":"You would type git commit followed by dash m,"},{"start":528.16,"end":530.12,"text":"and then in quotation marks, some message."},{"start":530.12,"end":532.28,"text":"And that message is just going to be usually"},{"start":532.28,"end":536,"text":"some summary of the changes that you''ve made in this particular change,"},{"start":536,"end":539,"text":"so that if anyone were to kind of go back and look at what we call the commit"},{"start":539,"end":541.48,"text":"history, they would be able to see all of the changes"},{"start":541.48,"end":544.88,"text":"and when you made those changes and what changes you made at any given stage"},{"start":544.88,"end":545.8,"text":"in this program."},{"start":545.8,"end":550.2,"text":"So that''s what git commit is, and it saves those new revisions of a repository"},{"start":550.2,"end":552.12,"text":"and kind of records a message along with it."},{"start":552.12,"end":556,"text":"And just as a side note, if you''d like to combine the adding and committing steps"},{"start":556,"end":558.88,"text":"together into one step, this command right here,"},{"start":558.88,"end":562.76,"text":"git commit dash a m, a for all, or a for add,"},{"start":562.76,"end":566.08,"text":"will automatically add all the files that you''ve changed"},{"start":566.08,"end":568.36,"text":"and also commit it with a commit message."},{"start":568.36,"end":571.6,"text":"So you can combine both of these steps together."},{"start":571.6,"end":573.04,"text":"So I''ll show you what this looks like."},{"start":573.04,"end":577.44,"text":"When I type git commit and follow it by kind of a message suggesting"},{"start":577.44,"end":580.96,"text":"what it is that I''ve changed, then what it will do is it will take my file"},{"start":580.96,"end":582.88,"text":"and it will save kind of a new version of it."},{"start":582.88,"end":585.36,"text":"It''ll save this version, which says that I''ve added a line."},{"start":585.36,"end":587.28,"text":"It saves the message along with the commit,"},{"start":587.28,"end":590.68,"text":"but it also still remembers that old version, such that if I ever wanted"},{"start":590.68,"end":593.48,"text":"to go back to that old version, I could still do that."},{"start":593.48,"end":595.76,"text":"So I''ll show you what that looks like right now."},{"start":595.76,"end":597.8,"text":"So I''m back here, and I''ve made these changes."},{"start":597.8,"end":598.84,"text":"I''ve already added them."},{"start":598.88,"end":604.4,"text":"So I can do git commit dash m, and then in quotation marks,"},{"start":604.4,"end":606.4,"text":"actually swap the values."},{"start":606.4,"end":609.4,"text":"And that''s going to be my message saying, here''s the change that I made"},{"start":609.4,"end":612.28,"text":"when I just made these changes to the code."},{"start":612.28,"end":617.28,"text":"And so I see this what''s called a commit hash, which is just an identifier"},{"start":617.28,"end":618.2,"text":"about the commit."},{"start":618.2,"end":621.6,"text":"And it says I''ve changed one file and added three lines, which is indeed true."},{"start":621.6,"end":624.12,"text":"I added three lines to this file in swap.c,"},{"start":624.12,"end":628.4,"text":"and those are the changes that I have just now saved."},{"start":628.44,"end":631.16,"text":"So what can I do now?"},{"start":631.16,"end":632.88,"text":"Git status is a helpful command."},{"start":632.88,"end":636.16,"text":"We''re at any stage in working on a Git repository."},{"start":636.16,"end":639.52,"text":"If you ever want to see what''s currently going on in the Git repository,"},{"start":639.52,"end":643.68,"text":"you can use git status to gain some kind of insight into what''s currently"},{"start":643.68,"end":647.76,"text":"happening, what are the changes that I''ve made to my current repository."},{"start":647.76,"end":652.96,"text":"And so the way that works is that if I were to type git status into the command line,"},{"start":652.96,"end":657.6,"text":"I would see a message show up that says, what is the current status of my repository?"},{"start":657.6,"end":661.36,"text":"And the message might look something like, on branch master,"},{"start":661.36,"end":665.08,"text":"and git has a feature, which we''ll get to in a moment, called branching,"},{"start":665.08,"end":668.4,"text":"which basically lets you keep track of different versions of your code."},{"start":668.4,"end":670.72,"text":"So you can have different separate tracks of your code."},{"start":670.72,"end":673.48,"text":"So if you want to test changes or try and implement new features,"},{"start":673.48,"end":676.84,"text":"you can do that separately from the main part of your code,"},{"start":676.84,"end":680.44,"text":"where master, we consider, to be the default code."},{"start":680.44,"end":682.44,"text":"And the second line here says, your branch"},{"start":682.44,"end":685.88,"text":"is ahead of origin master by one commit, which is just"},{"start":685.88,"end":689.88,"text":"kind of a fancy way of saying that that version up here on the server,"},{"start":689.88,"end":695.04,"text":"this version that we have is one commit or one version ahead of that version."},{"start":695.04,"end":700.4,"text":"So we''ve saved one change that the server up on GitHub doesn''t yet know about."},{"start":700.4,"end":701.96,"text":"Clear so far?"},{"start":701.96,"end":702.6,"text":"OK."},{"start":702.6,"end":704.24,"text":"And I''ll show you exactly what that looks like."},{"start":704.24,"end":708.16,"text":"I can type git status right now, and it will tell me that exact same thing."},{"start":708.16,"end":711.48,"text":"I''m currently on branch master, and CS50 IDE is really nice,"},{"start":711.48,"end":714.96,"text":"and that it actually tells me right here in my prompt what branch I''m currently on."},{"start":715.04,"end":716.28,"text":"I''m on the master branch."},{"start":716.28,"end":718.64,"text":"And it says that I''m ahead of origin master, which"},{"start":718.64,"end":724.84,"text":"is the version that lives up on GitHub by one commit, so one revision ahead."},{"start":724.84,"end":729.92,"text":"So now that I''m one revision ahead, how do I then take those changes"},{"start":729.92,"end":732.72,"text":"and what we call push them back up to GitHub,"},{"start":732.72,"end":736.44,"text":"so that the online version that can be accessible by anyone looking online"},{"start":736.44,"end":739.96,"text":"or accessible by collaborators who are also using the same online repository"},{"start":739.96,"end":740.96,"text":"can then see."},{"start":740.96,"end":744.48,"text":"And that is git push is the command that we would use."},{"start":744.48,"end":747.08,"text":"And so the syntax for that is just git push, which"},{"start":747.08,"end":751.68,"text":"will send whatever committed changes we''ve made up to the remote repository up on GitHub."},{"start":751.68,"end":756.44,"text":"I can be very explicit and state exactly what branch I want to push to,"},{"start":756.44,"end":760.96,"text":"as in git push origin master, meaning push these changes to the master branch."},{"start":760.96,"end":766.56,"text":"But generally, you wouldn''t need to do this for normal purposes."},{"start":766.56,"end":768.28,"text":"So I would say something like git push."},{"start":768.28,"end":771.6,"text":"And then this new change, the change that I made on my computer,"},{"start":771.6,"end":775.8,"text":"would then get pushed up to GitHub so that anyone looking online would then"},{"start":775.8,"end":777.92,"text":"be able to see those changes that I just made."},{"start":777.92,"end":780.04,"text":"And so I''ll show you what that looks like right now."},{"start":780.04,"end":782.28,"text":"If I go back here, so again, I did git status."},{"start":782.28,"end":784.92,"text":"I''m ahead by one commit, because right now I''ve"},{"start":784.92,"end":787.6,"text":"added these three lines that actually perform the swap."},{"start":787.6,"end":792.04,"text":"And on GitHub, if I were to look at swap.c, this is online on GitHub,"},{"start":792.04,"end":796,"text":"swap.c doesn''t have those lines right now on the online GitHub version."},{"start":796,"end":797.52,"text":"It just says swap in."},{"start":797.52,"end":801.12,"text":"But if I go back in to CS50 ID and I type in git push,"},{"start":801.12,"end":804.32,"text":"those will push those changes back up to GitHub."},{"start":804.32,"end":806.84,"text":"And if I go back to GitHub and refresh the page now,"},{"start":806.84,"end":809.88,"text":"I''ll see that indeed these three lines that I just added"},{"start":809.88,"end":811.36,"text":"have now been pushed up and online."},{"start":811.36,"end":813.36,"text":"And if you actually go to github.com."},{"start":813.36,"end":816.12,"text":"slash bryanu28 slash this whole link, you''ll"},{"start":816.12,"end":819.88,"text":"be able to see this exact same thing, because this repository is public."},{"start":819.88,"end":822.88,"text":"So those changes have been pushed online."},{"start":822.88,"end":825.16,"text":"Questions on how that worked?"},{"start":825.16,"end":826.52,"text":"Fantastic."},{"start":826.52,"end":828.24,"text":"OK."},{"start":828.24,"end":832.8,"text":"So now git pull is another valuable command."},{"start":832.8,"end":835.08,"text":"Git pull is kind of the opposite of git push."},{"start":835.08,"end":837.92,"text":"If git push means I made changes on my computer,"},{"start":837.92,"end":841.28,"text":"and I want to send them up to GitHub so that the online version knows about it,"},{"start":841.28,"end":845.32,"text":"git pull is GitHub contains a more recent version of the repository"},{"start":845.32,"end":846.88,"text":"than I have on my computer."},{"start":846.88,"end":849.28,"text":"And I''d like to take those changes from online"},{"start":849.28,"end":852.16,"text":"and pull them down onto my computer so that I"},{"start":852.16,"end":855.52,"text":"can see the most recent version of the repository that''s currently reflected"},{"start":855.52,"end":856.4,"text":"on GitHub."},{"start":856.4,"end":859.4,"text":"And so the way that would work is if someone were to make a third change"},{"start":859.4,"end":864.36,"text":"to this repository and my computer only had these two revisions to the repository,"},{"start":864.36,"end":866.56,"text":"I could say something like git pull."},{"start":866.56,"end":869.04,"text":"And this third change to the repository that was added"},{"start":869.04,"end":871.12,"text":"would then be pulled down onto my computer"},{"start":871.12,"end":875.72,"text":"so that my computer now has all the versions that are matched on GitHub."},{"start":875.72,"end":880.36,"text":"So I''ve actually set up a second IDE workspace."},{"start":880.36,"end":883.24,"text":"So this version has all the changes we just made."},{"start":883.24,"end":885,"text":"In this version of my workspace over here,"},{"start":885.04,"end":888.72,"text":"which is a completely different workspace, inside swap.c,"},{"start":888.72,"end":892.92,"text":"I haven''t updated it to the latest changes yet because I haven''t done a git pull."},{"start":892.92,"end":895.96,"text":"So it still says swapping, and it doesn''t have the latest version of the code."},{"start":895.96,"end":899.28,"text":"So if I want to pull from GitHub, get the latest version."},{"start":899.28,"end":902.28,"text":"I would cd into the seminar directory."},{"start":902.28,"end":904.52,"text":"And then I could say git pull."},{"start":904.52,"end":907.32,"text":"And so it will pull the latest changes from GitHub."},{"start":907.32,"end":911.36,"text":"And you''ll see that it says fast forwarding this swap.c file."},{"start":911.36,"end":914.08,"text":"It changed one file, added three lines."},{"start":914.08,"end":917.44,"text":"And indeed, if I go to swap.c now, that file that I just changed,"},{"start":917.44,"end":919.64,"text":"you''ll see that those three lines that were on GitHub"},{"start":919.64,"end":923.76,"text":"but weren''t on my computer before are now on my computer because I did git pull."},{"start":923.76,"end":926.84,"text":"And so those changes are now reflected there."},{"start":926.84,"end":928.6,"text":"Clear on that?"},{"start":928.6,"end":929.2,"text":"Fantastic."},{"start":932.28,"end":934.48,"text":"All right, let''s talk about merge conflicts."},{"start":934.48,"end":936.68,"text":"This is where it gets to, this is the part of git"},{"start":936.68,"end":938.44,"text":"that can often scare a lot of people."},{"start":938.44,"end":940.48,"text":"But don''t worry, it''s actually quite manageable."},{"start":940.48,"end":943.92,"text":"So here comes the question of, git seems to be very good at automatically"},{"start":943.92,"end":947,"text":"tracking what changes I''ve made to a file, where I''ve added new files,"},{"start":947,"end":951.44,"text":"where I''ve removed lines, where I''ve added new lines to code."},{"start":951.44,"end":955.56,"text":"But what happens if I''m working on code on a particular line,"},{"start":955.56,"end":960.04,"text":"and I make a change to line 28, say, and some collaborator also makes"},{"start":960.04,"end":965.12,"text":"a change to that same line, and we both try and push that code up to GitHub?"},{"start":965.12,"end":968.52,"text":"GitHub''s not going to be able to know what to do about that situation"},{"start":968.52,"end":973.48,"text":"because it doesn''t know which version of the code to believe, so to speak."},{"start":973.48,"end":975.48,"text":"So this creates what we call a merge conflict,"},{"start":975.48,"end":978.2,"text":"when in trying to combine two different versions of the repository,"},{"start":978.2,"end":981.12,"text":"there''s some sort of problem that git can''t automatically resolve."},{"start":981.12,"end":984.84,"text":"And so you, the programmer, need to figure out how to resolve that conflict."},{"start":984.84,"end":987.16,"text":"And so here''s what that might look like."},{"start":987.16,"end":991.52,"text":"Maybe if you try and git pull, and you''re pulling in new changes from GitHub,"},{"start":991.52,"end":995.96,"text":"but those changes conflict with changes that you''ve made on your computer,"},{"start":995.96,"end":997.84,"text":"you might get a message that looks like this."},{"start":997.88,"end":1000.8,"text":"Conflict, the merge conflict failed."},{"start":1000.8,"end":1004.8,"text":"You need to fix the conflicts and then commit the result."},{"start":1004.8,"end":1009.04,"text":"And so this might be what your file would look like after you get this merge conflict."},{"start":1009.04,"end":1014.4,"text":"You might get a situation where you have a whole bunch of lines of code,"},{"start":1014.4,"end":1018.2,"text":"and then this weird kind of series of less than signs followed by head,"},{"start":1018.2,"end":1020.96,"text":"a bunch of equal signs, and then a bunch of greater than signs"},{"start":1020.96,"end":1023.92,"text":"followed by some weird sequence of numbers and letters."},{"start":1023.92,"end":1026.48,"text":"This is kind of what a merge conflict might actually look like."},{"start":1026.52,"end":1029.52,"text":"And just to break this down for you, here''s what all this means."},{"start":1029.52,"end":1034.12,"text":"Everything between head and the set of equal signs"},{"start":1034.12,"end":1038.64,"text":"are all of the changes that you made that are in conflict,"},{"start":1038.64,"end":1041.2,"text":"so changes that you''ve made on your computer."},{"start":1041.2,"end":1045.36,"text":"Everything between all these equal signs and this series of greater than signs"},{"start":1045.36,"end":1048.56,"text":"are all of the changes from GitHub that you''re trying to pull down that"},{"start":1048.56,"end":1049.56,"text":"are in conflict."},{"start":1049.56,"end":1053.92,"text":"So what happened here seems to be that the online version seems to have said,"},{"start":1053.96,"end":1057.52,"text":"int b equals d0, but my version on my computer,"},{"start":1057.52,"end":1062.28,"text":"I''ve committed that int b should be equal to 2, and those were the same line."},{"start":1062.28,"end":1064.76,"text":"So when git tried to merge those two together,"},{"start":1064.76,"end":1066.64,"text":"it didn''t know which line to go with."},{"start":1066.64,"end":1069.36,"text":"And so that''s why we''re getting this conflict."},{"start":1069.36,"end":1073,"text":"And this random sequence of numbers and letters right there is the conflicting"},{"start":1073,"end":1073.36,"text":"commit."},{"start":1073.36,"end":1077.48,"text":"Every single commit gets a unique identifier, just a sequence of numbers"},{"start":1077.48,"end":1078.24,"text":"and letters."},{"start":1078.24,"end":1081.6,"text":"And so this is telling me which is the commit from GitHub that"},{"start":1081.6,"end":1084.72,"text":"is causing this conflict that is the reason why I''m not"},{"start":1084.72,"end":1086.44,"text":"able to merge these two together."},{"start":1086.44,"end":1088.72,"text":"And so what do you do in a situation like this?"},{"start":1088.72,"end":1091.16,"text":"To resolve this merge conflict, all you need to do"},{"start":1091.16,"end":1094.44,"text":"is get rid of this headline, the equal line, the greater than line,"},{"start":1094.44,"end":1097.56,"text":"and then figure out what to do about these conflicting lines."},{"start":1097.56,"end":1100.44,"text":"You might delete one set and only use the other."},{"start":1100.44,"end":1104.16,"text":"You might somehow find a way to combine the two."},{"start":1104.16,"end":1107.36,"text":"But in some way, you need to tell git what the actual version of the code"},{"start":1107.36,"end":1108.24,"text":"should look like."},{"start":1108.28,"end":1112.92,"text":"So in this case, we might get rid of all the lines except for b equals 2"},{"start":1112.92,"end":1116.52,"text":"because b equals 2 is the version that I know that I want."},{"start":1116.52,"end":1118.2,"text":"You can get rid of the extra space there."},{"start":1118.2,"end":1120.2,"text":"And after that, I could commit this file."},{"start":1120.2,"end":1123.24,"text":"And now that would be the version that''s saved."},{"start":1123.24,"end":1125.72,"text":"I''ve now resolved the merge conflict by specifically telling"},{"start":1125.72,"end":1128.84,"text":"git which version of the code that I want to use."},{"start":1128.84,"end":1130.92,"text":"So let''s try and create a merge conflict right now"},{"start":1130.92,"end":1133.72,"text":"so we can see what that looks like."},{"start":1133.72,"end":1138.2,"text":"In one version of my IDE, I''m going to take this x, which is right now 28."},{"start":1138.8,"end":1141.64,"text":"And I''m going to set it to pick a number, any number."},{"start":1141.64,"end":1142.64,"text":"51."},{"start":1142.64,"end":1143.64,"text":"51."},{"start":1143.64,"end":1147.8,"text":"And I''m going to git commit am."},{"start":1147.8,"end":1151.4,"text":"And I''ll say, so what I''m doing here is I''m adding this change that I just made"},{"start":1151.4,"end":1155.84,"text":"and committing it, saying I''m going to change x to 51."},{"start":1155.84,"end":1156.92,"text":"So I''ve made that commit."},{"start":1156.92,"end":1159.36,"text":"It notes that I''ve only changed one file."},{"start":1159.36,"end":1161.12,"text":"It says one insertion, one deletion."},{"start":1161.12,"end":1165.64,"text":"What that means is I deleted the line that says int x equals 50 or int x equals 28."},{"start":1165.64,"end":1167.96,"text":"And I added the line that says int x equals 51."},{"start":1167.96,"end":1169.6,"text":"It doesn''t know that I changed two characters."},{"start":1169.6,"end":1172.52,"text":"It knows that I got rid of a line and replaced it with a line."},{"start":1172.52,"end":1173.72,"text":"I can git push now."},{"start":1173.72,"end":1177.76,"text":"And so that change, changing x to 51, is now online."},{"start":1177.76,"end":1181.2,"text":"So if I go to GitHub and I refresh this right now, x is 28."},{"start":1181.2,"end":1186,"text":"Now I see that x is 51 because that''s the change that I just pushed."},{"start":1186,"end":1189.32,"text":"Now in this other version of the repository where x is still 28,"},{"start":1189.32,"end":1190.84,"text":"why don''t you pick a different number?"},{"start":1190.84,"end":1191.84,"text":"17."},{"start":1191.84,"end":1193.12,"text":"17."},{"start":1193.12,"end":1194.08,"text":"17."},{"start":1194.08,"end":1199.92,"text":"And I''m going to say, git commit am, change x to 17."},{"start":1199.92,"end":1202.04,"text":"So I''m saving that change."},{"start":1202.04,"end":1205.44,"text":"And let''s say now I wanted to pull the changes from GitHub."},{"start":1205.44,"end":1208.28,"text":"Make sure I have the latest version of the code."},{"start":1208.28,"end":1210.32,"text":"I''ve changed x to 17 here."},{"start":1210.32,"end":1215.04,"text":"The version on GitHub has a recent change that says we''ve changed x to be 51."},{"start":1215.04,"end":1217.6,"text":"So when I get pull, watch what''s going to happen."},{"start":1217.6,"end":1220.56,"text":"I''ll close this file for now, but I press get pull."},{"start":1220.56,"end":1225.12,"text":"And it says conflict, merge conflict in swap.c."},{"start":1225.12,"end":1226.52,"text":"The automatic merge failed."},{"start":1226.52,"end":1229.12,"text":"So git couldn''t merge these two files automatically."},{"start":1229.12,"end":1232.68,"text":"I need to fix the conflicts and then commit the results."},{"start":1232.68,"end":1235.28,"text":"So let''s open up swap.c and see what''s going on."},{"start":1235.28,"end":1241.72,"text":"And you''ll see kind of, oh, in CS50 ID, actually add some nice little markers"},{"start":1241.72,"end":1243.36,"text":"that help us understand what''s going on."},{"start":1243.36,"end":1246.6,"text":"But we see this head, and we see this commit hash,"},{"start":1246.6,"end":1248.16,"text":"and we see what the different versions are."},{"start":1248.16,"end":1249.16,"text":"This is my version."},{"start":1249.16,"end":1251.12,"text":"This is int x equals 17."},{"start":1251.12,"end":1252.8,"text":"And this is their version."},{"start":1252.8,"end":1254.4,"text":"It says int x equals 51."},{"start":1254.4,"end":1256.96,"text":"That''s the version that we just pulled down from GitHub."},{"start":1256.96,"end":1262.36,"text":"So I need to decide kind of which version of the code that I actually want to use."},{"start":1262.36,"end":1265.2,"text":"Maybe I don''t know, and maybe I just want to go with, I don''t know, the average of the two."},{"start":1265.2,"end":1268.2,"text":"We''ll do like, what is it, 34?"},{"start":1268.2,"end":1270.92,"text":"And then I would get rid of kind of these lines that are conflicting."},{"start":1275.48,"end":1279.08,"text":"Not too used to the syntax, but oh, here we go."},{"start":1279.12,"end":1284.4,"text":"So I would just say int x equals 34."},{"start":1284.4,"end":1286.24,"text":"And I''ll get rid of all those extra lines."},{"start":1286.24,"end":1289.76,"text":"And so I''ve now changed this code, gotten rid of all those excess lines,"},{"start":1289.76,"end":1293.12,"text":"and just replaced it with kind of the line that I actually want, in this case,"},{"start":1293.12,"end":1296.04,"text":"the one that says int x equals 34."},{"start":1296.04,"end":1300.36,"text":"At this point, I can do get status just to see what''s going on."},{"start":1300.36,"end":1303.12,"text":"It says that I have unmerged paths."},{"start":1303.12,"end":1306.56,"text":"I need to fix the conflicts and run get commit."},{"start":1306.56,"end":1310.88,"text":"I will do get commit, am, and I''ll say, I''m going to commit these changes."},{"start":1310.88,"end":1314.68,"text":"I just fixed the merge conflicts."},{"start":1314.68,"end":1316.16,"text":"So now it says I fixed it."},{"start":1316.16,"end":1318.4,"text":"I can now get push, which takes these changes."},{"start":1318.4,"end":1319.8,"text":"I just fixed the merge conflicts."},{"start":1319.8,"end":1321.88,"text":"I''m going to push them back up to GitHub."},{"start":1321.88,"end":1323.7,"text":"I get push."},{"start":1323.7,"end":1328.04,"text":"And now after that''s done, I can go back to GitHub, refresh the page,"},{"start":1328.04,"end":1329.64,"text":"and x is now 34."},{"start":1329.64,"end":1332.92,"text":"And this is my resolution to this merge conflict."},{"start":1332.92,"end":1334.84,"text":"Kind of a lot of stuff happening simultaneously,"},{"start":1334.84,"end":1336.32,"text":"but that makes sense."},{"start":1336.32,"end":1339.32,"text":"Any questions on how that merge conflict happened, why it happened,"},{"start":1339.32,"end":1342.84,"text":"or what we were able to do in order to fix it?"},{"start":1342.84,"end":1343.68,"text":"All good?"},{"start":1343.68,"end":1344.92,"text":"Fantastic."},{"start":1344.92,"end":1348.68,"text":"OK, let''s move on then."},{"start":1348.68,"end":1351.04,"text":"get log is another very useful feature."},{"start":1351.04,"end":1354.72,"text":"And get logs job is basically it will tell you kind of the history"},{"start":1354.72,"end":1357.4,"text":"of all of the commits that you have made previously."},{"start":1357.4,"end":1360.64,"text":"So it shows a history of the commits and their messages."},{"start":1360.64,"end":1363.68,"text":"So if I do something like get log and type that into my terminal,"},{"start":1363.68,"end":1366.28,"text":"then something like this will show up, where it will show me a history"},{"start":1366.28,"end":1367.8,"text":"of all of the commits that I''ve made."},{"start":1367.8,"end":1373.12,"text":"It will show me the kind of commit ID or the commit hash that identifies that commit."},{"start":1373.12,"end":1374.44,"text":"It will tell me who made that commit."},{"start":1374.44,"end":1376.48,"text":"So if multiple people are collaborating together,"},{"start":1376.48,"end":1380.16,"text":"it''ll tell you who made the change, when they made the change on a particular date."},{"start":1380.16,"end":1383.12,"text":"And then this message here is whatever you said was the commit message."},{"start":1383.12,"end":1385.56,"text":"So that''s why a commit message can be very, very important."},{"start":1385.56,"end":1389.04,"text":"Because when you use get log, you''ll see all of the changes that were made."},{"start":1389.04,"end":1391.68,"text":"And the message is a very good indicator as to what"},{"start":1391.68,"end":1394.16,"text":"was changed in this particular version."},{"start":1394.16,"end":1398.64,"text":"So make sure you use good commit messages if you''re going to use get."},{"start":1398.64,"end":1400.2,"text":"Questions on get log?"},{"start":1400.2,"end":1402.72,"text":"I''ll show you what that looks like in the actual terminal."},{"start":1402.72,"end":1405.72,"text":"I can type in get log at the terminal."},{"start":1405.72,"end":1408.72,"text":"And it will show me all these changes that I''ve made."},{"start":1408.72,"end":1413.24,"text":"So I added the swap file, changed x to 17, fixed these merge conflicts."},{"start":1413.24,"end":1414.24,"text":"Those are all the changes."},{"start":1414.24,"end":1419.12,"text":"And you can see kind of when I made those changes and who made those changes."},{"start":1419.12,"end":1420.96,"text":"Clear?"},{"start":1420.96,"end":1421.64,"text":"Fantastic."},{"start":1425.04,"end":1425.64,"text":"All right."},{"start":1425.64,"end":1429.48,"text":"So now let''s say I made a change, but I didn''t mean to make that change."},{"start":1429.48,"end":1433,"text":"And I want to kind of go back to a previous version of the code."},{"start":1433,"end":1434.56,"text":"That''s what get reset is for."},{"start":1434.56,"end":1436.24,"text":"That allows me to kind of roll back."},{"start":1436.24,"end":1437.24,"text":"These changes didn''t work."},{"start":1437.24,"end":1438.88,"text":"I want to go back to an older version."},{"start":1438.88,"end":1440.12,"text":"And here''s how that works."},{"start":1440.12,"end":1446.24,"text":"So recall that every one of our commits has a commit hash, some unique identifier"},{"start":1446.24,"end":1450.04,"text":"that says this is how we identify this particular change."},{"start":1450.08,"end":1451.96,"text":"And down here next to the commit messages,"},{"start":1451.96,"end":1457.04,"text":"I''ve included the first couple characters of those commit hashes."},{"start":1457.04,"end":1461.8,"text":"If I type get reset dash dash hard followed by some commit hash,"},{"start":1461.8,"end":1464.44,"text":"and usually you don''t need to include the entire commit hash"},{"start":1464.44,"end":1467.76,"text":"because usually it''s dozens upon dozens of characters, usually just"},{"start":1467.76,"end":1471.04,"text":"a couple characters, at least enough to uniquely identify that commit"},{"start":1471.04,"end":1474.88,"text":"so that no other commit has the same initial characters, is sufficient."},{"start":1474.88,"end":1478.44,"text":"If you type that, it will revert your code back to that previous version."},{"start":1478.44,"end":1481.8,"text":"And you will lose all of the changes that you''ve made since that version."},{"start":1481.8,"end":1486.12,"text":"So do this only if you were sure that you want to go back to that previous version."},{"start":1486.12,"end":1490.04,"text":"In addition to going back to a previous version in your commit history,"},{"start":1490.04,"end":1494.2,"text":"you can also go back to the version that currently exists on GitHub."},{"start":1494.2,"end":1497.56,"text":"So if there were a version on GitHub, which is our origin in this case,"},{"start":1497.56,"end":1500.96,"text":"the origin of the repository, and we''ve made changes on our computer,"},{"start":1500.96,"end":1504.12,"text":"and now we realize those changes really don''t work, I really want to go back,"},{"start":1504.12,"end":1509,"text":"you can use get reset dash dash hard origin slash master to go back"},{"start":1509,"end":1512.48,"text":"to the version that''s on GitHub and its master branch."},{"start":1512.48,"end":1515.6,"text":"And again, we''ve only been working on the master branch so far."},{"start":1515.6,"end":1518.92,"text":"So that''s the only thing that we really have to work with."},{"start":1518.92,"end":1524.64,"text":"So I could type get reset dash dash hard followed by 4761626,"},{"start":1524.64,"end":1530.88,"text":"where that is the beginning of the commit hash for this version of the repository."},{"start":1530.88,"end":1533.68,"text":"And again, if I don''t know what the identifier is,"},{"start":1533.68,"end":1535.92,"text":"I can always use get log, that code, the command that"},{"start":1535.92,"end":1539,"text":"shows me the history of all the commits that I''ve made along with when"},{"start":1539,"end":1542.08,"text":"I made any particular commit and what changes were made in that commit."},{"start":1542.08,"end":1544.28,"text":"So that can give me the identifier."},{"start":1544.28,"end":1548.32,"text":"And if I do get reset, then these changes that I''ve made after that file"},{"start":1548.32,"end":1552,"text":"will kind of go away and I''ll be left with this being the most recent version."},{"start":1552,"end":1554.92,"text":"And so that''s what I''m going to have left over."},{"start":1554.92,"end":1557.68,"text":"Any questions on that?"},{"start":1557.68,"end":1560.32,"text":"OK, let''s get into talking about branching."},{"start":1560.36,"end":1563.8,"text":"So branching is a very, very valuable feature in Git"},{"start":1563.8,"end":1566.92,"text":"that basically allows you in a single repository"},{"start":1566.92,"end":1570.04,"text":"to have a couple different versions of the code that"},{"start":1570.04,"end":1571.88,"text":"are going on simultaneously."},{"start":1571.88,"end":1574.68,"text":"So maybe you have one version of your code, your master branch, that''s"},{"start":1574.68,"end":1578.92,"text":"generally the one that works perfectly or that does what you need it to do."},{"start":1578.92,"end":1580.92,"text":"And maybe you want to add new features to your program"},{"start":1580.92,"end":1583.16,"text":"or you want to add something brand new to your code."},{"start":1583.16,"end":1586.6,"text":"But you don''t want to potentially mess up the master branch because that one"},{"start":1586.6,"end":1587.64,"text":"you know works."},{"start":1587.68,"end":1590.44,"text":"So one thing you can do is you can kind of branch off,"},{"start":1590.44,"end":1595.6,"text":"create a new branch that you''re making new changes to, testing out new features,"},{"start":1595.6,"end":1598.52,"text":"while keeping your original master branch identical."},{"start":1598.52,"end":1600.56,"text":"And then you can make commits to this new branch."},{"start":1600.56,"end":1603.52,"text":"You can roll back those commits and do all the same things"},{"start":1603.52,"end":1605.92,"text":"that we were just talking about previously in the seminar."},{"start":1605.92,"end":1609.68,"text":"And then only when you feel ready that this new branch has all of the things"},{"start":1609.68,"end":1613.48,"text":"that you want it to have and is ready to kind of become the official version,"},{"start":1613.48,"end":1617.12,"text":"can you then merge it back into the master branch so that you then have"},{"start":1617.12,"end":1618.88,"text":"the one working version."},{"start":1618.88,"end":1621.24,"text":"So let''s explore how you do that branching."},{"start":1621.24,"end":1624.56,"text":"So just to recap, branching is a version of the repository."},{"start":1624.56,"end":1626.76,"text":"Each branch has its own commit history."},{"start":1626.76,"end":1630.72,"text":"And each branch has its own kind of most recent version of the code."},{"start":1630.72,"end":1635.96,"text":"So git branch is the command that you would use in order to create a new branch."},{"start":1635.96,"end":1641,"text":"So if I just type git branch, it will show me all of the current branches"},{"start":1641,"end":1643.24,"text":"that I have on the repository."},{"start":1643.24,"end":1646.08,"text":"But if I want to create a new branch, I would type git branch"},{"start":1646.12,"end":1647.92,"text":"followed by the name of the branch."},{"start":1647.92,"end":1649.92,"text":"And I could just make up any branch name I want,"},{"start":1649.92,"end":1653.84,"text":"so long as it''s not a name that already exists as a branch."},{"start":1653.84,"end":1658.48,"text":"And then once I''ve created a new branch, if I want to switch to that new branch,"},{"start":1658.48,"end":1660.08,"text":"I would use git checkout."},{"start":1660.08,"end":1663.12,"text":"So git checkout, followed by the name of the branch,"},{"start":1663.12,"end":1668.32,"text":"will switch me to that new branch that I''m going to be working on that other branch."},{"start":1668.32,"end":1671.76,"text":"And side note, if you want to kind of combine these two steps to check out"},{"start":1671.76,"end":1673.96,"text":"a new branch and create it at the same time,"},{"start":1673.96,"end":1677.84,"text":"you can use git checkout dash b and then followed by a new branch name."},{"start":1677.84,"end":1681.2,"text":"And that will both create a new branch and it will switch you to it."},{"start":1681.2,"end":1683.56,"text":"That can just be a little time saving feature."},{"start":1683.56,"end":1686.2,"text":"So right now, I just have one version of the code."},{"start":1686.2,"end":1689.04,"text":"It''s the master branch, the original version by default."},{"start":1689.04,"end":1693.2,"text":"And if I were to type git branch tests, that would create for me"},{"start":1693.2,"end":1697.4,"text":"a new branch called tests that basically will just be a copy of master,"},{"start":1697.4,"end":1700.72,"text":"at least for the time being, creating that new version of the code."},{"start":1700.76,"end":1704.08,"text":"So then I can make new changes to this test."},{"start":1704.08,"end":1705.28,"text":"I can add files to it."},{"start":1705.28,"end":1706.56,"text":"I can make commits."},{"start":1706.56,"end":1709.68,"text":"So saving reversions of this tests branch."},{"start":1709.68,"end":1712.04,"text":"And then later, once test is the way I want it to be,"},{"start":1712.04,"end":1714.04,"text":"I can merge it back in with master."},{"start":1714.04,"end":1715.48,"text":"And so we''ll look at that right now."},{"start":1715.48,"end":1720.52,"text":"Git merges the command that we would use to merge two different branches together."},{"start":1720.52,"end":1722.36,"text":"And the way that works is like this."},{"start":1722.36,"end":1724.92,"text":"Git merge, followed by some branch name,"},{"start":1724.92,"end":1729.32,"text":"merges that branch with whatever branch I am currently on."},{"start":1729.32,"end":1733.04,"text":"So what that means is that if I am currently on the master branch"},{"start":1733.04,"end":1736.92,"text":"and the tests branch now has kind of a whole bunch of versions to the code"},{"start":1736.92,"end":1737.68,"text":"that have been made."},{"start":1737.68,"end":1740.12,"text":"So it''s got a whole bunch of files that have been changed."},{"start":1740.12,"end":1744.28,"text":"And I now want to take those changes and say,"},{"start":1744.28,"end":1746.28,"text":"I want to bring them into the master branch."},{"start":1746.28,"end":1750.28,"text":"Then the command that I would use here would be something like git merge tests."},{"start":1750.28,"end":1753.12,"text":"And that would take all these changes to the test branch."},{"start":1753.12,"end":1755.44,"text":"And it would merge them with the master branch,"},{"start":1755.44,"end":1759.32,"text":"so that the master branch now reflects all of those changes."},{"start":1759.32,"end":1762.64,"text":"Now, there may be the possibility that on the master branch,"},{"start":1762.64,"end":1766.64,"text":"I''ve made changes to the same lines of code that the test branch also made"},{"start":1766.64,"end":1767.56,"text":"the changes to."},{"start":1767.56,"end":1771.4,"text":"And in that case, when you try and merge tests into the master branch,"},{"start":1771.4,"end":1773.16,"text":"you''re going to run into another merge conflict."},{"start":1773.16,"end":1774.84,"text":"And we''ve talked about how to resolve those."},{"start":1774.84,"end":1777.92,"text":"But basically, it involves getting rid of those lines you don''t want"},{"start":1777.92,"end":1781,"text":"and then figuring out how to take the two kind of different versions of the code"},{"start":1781,"end":1783.48,"text":"and figure out which version you actually want."},{"start":1783.52,"end":1786.4,"text":"So that''s oftentimes a possibility that you''ll run into,"},{"start":1786.4,"end":1789.48,"text":"especially on larger projects where multiple people are working on the code"},{"start":1789.48,"end":1792.32,"text":"simultaneously and potentially working on different branches."},{"start":1792.32,"end":1794.76,"text":"It may very well be the case that merging two branches"},{"start":1794.76,"end":1797.48,"text":"can result in a merge conflict."},{"start":1797.48,"end":1800,"text":"So let''s take a look at how this might work."},{"start":1800,"end":1803.8,"text":"So as you can see right now, I''m on the master branch of this repository."},{"start":1803.8,"end":1806.96,"text":"And I can see this even more clearly if your terminal doesn''t display"},{"start":1806.96,"end":1809.84,"text":"what branch you''re on just by typing git branch."},{"start":1809.84,"end":1813.52,"text":"And that will tell me that there is only one branch in this repository"},{"start":1813.52,"end":1815.24,"text":"and it is called master."},{"start":1815.24,"end":1818.64,"text":"So let''s say I want to create a new branch."},{"start":1818.64,"end":1825.92,"text":"We''ll call it, let''s say I wanted to separate out this code, the code that"},{"start":1825.92,"end":1828.28,"text":"does the swapping, into its own function."},{"start":1828.28,"end":1830.36,"text":"But that seems like it has a potential to go wrong."},{"start":1830.36,"end":1831.56,"text":"It might not necessarily work."},{"start":1831.56,"end":1833.48,"text":"So I don''t want to just change this file."},{"start":1833.48,"end":1837.52,"text":"I want to create a new branch that will let me test out those changes"},{"start":1837.52,"end":1839.82,"text":"without worrying about whatever is happening in master."},{"start":1839.82,"end":1841.86,"text":"So I''m going to create a new branch via git branch."},{"start":1841.86,"end":1845.06,"text":"And I''ll call it function just because the purpose of this branch"},{"start":1845.06,"end":1849.3,"text":"is I''m going to be creating a new function in order to perform the swap."},{"start":1849.3,"end":1851.34,"text":"So I typed git branch function."},{"start":1851.34,"end":1854.22,"text":"And now if I were to type git branch, you''ll"},{"start":1854.22,"end":1857.38,"text":"see that I have two branches going here."},{"start":1857.38,"end":1859.02,"text":"I''ve got a master branch and it''s green."},{"start":1859.02,"end":1860.86,"text":"So that says that''s the branch I''m on right now."},{"start":1860.86,"end":1862.82,"text":"There''s also a function branch that appears now."},{"start":1862.82,"end":1864.66,"text":"That''s the branch that I''ve just created."},{"start":1864.66,"end":1869.22,"text":"And if I want to switch to that branch, I would type something like git checkout"},{"start":1869.26,"end":1870.7,"text":"function."},{"start":1870.7,"end":1873.58,"text":"And it says, switched to branch function."},{"start":1873.58,"end":1877.34,"text":"And so now if I type git branch, I would see there are two branches,"},{"start":1877.34,"end":1878.74,"text":"still function and master."},{"start":1878.74,"end":1881.22,"text":"But function is now the green one with the star next to it."},{"start":1881.22,"end":1883.46,"text":"That''s the branch that I''m currently on."},{"start":1883.46,"end":1885.34,"text":"So now I''m on this function branch."},{"start":1885.34,"end":1894.42,"text":"And I can add this swap function void swap int star a int star b."},{"start":1894.42,"end":1902.02,"text":"And int temp equals star a star a equals star b and star b equals temp."},{"start":1902.02,"end":1911.3,"text":"And I can now replace this with just swap address of x address of y."},{"start":1911.3,"end":1913.18,"text":"That should work, right?"},{"start":1913.18,"end":1914.14,"text":"Hopefully it works."},{"start":1914.14,"end":1916.38,"text":"I''m going to commit those changes."},{"start":1916.38,"end":1922.74,"text":"I''m going to say add a swap function."},{"start":1922.74,"end":1924.74,"text":"And so that change was just made."},{"start":1924.74,"end":1925.98,"text":"And so it says, one file changed."},{"start":1925.98,"end":1927.94,"text":"I added eight lines, removed three lines."},{"start":1927.94,"end":1931.7,"text":"And so that commit is there."},{"start":1931.7,"end":1936.86,"text":"But now if I type git branch, I can see I''m currently on the function branch."},{"start":1936.86,"end":1941.38,"text":"If I were to check out the master branch via git checkout master,"},{"start":1941.38,"end":1944.3,"text":"what you''ll notice is that swap.c changes."},{"start":1944.3,"end":1947.18,"text":"It changed back to the version that''s on the master branch."},{"start":1947.18,"end":1949.02,"text":"Because the master branch doesn''t have the new function."},{"start":1949.02,"end":1953.54,"text":"It just has these three lines of code that are right inside the main function."},{"start":1953.54,"end":1953.94,"text":"Watch again."},{"start":1953.94,"end":1959.18,"text":"If I git checkout back to the function branch, watch what happens to swap.c."},{"start":1959.18,"end":1963.1,"text":"It''ll just immediately show me, here''s the version that''s on the function branch."},{"start":1963.1,"end":1965.1,"text":"And so those are those changes."},{"start":1965.1,"end":1966.1,"text":"Question?"},{"start":1966.1,"end":1971.46,"text":"Will this work on any file system, say the Mac Finder?"},{"start":1971.46,"end":1971.66,"text":"Yeah."},{"start":1971.66,"end":1976.78,"text":"So on the Mac Finder, if you do a git checkout and maybe this new branch"},{"start":1976.82,"end":1978.9,"text":"has a file that didn''t exist on the other branch,"},{"start":1978.9,"end":1981.3,"text":"that file will appear in your file system."},{"start":1981.3,"end":1983.66,"text":"So it absolutely works."},{"start":1983.66,"end":1985.54,"text":"And so now maybe I''m happy with those changes."},{"start":1985.54,"end":1989.02,"text":"And I want to actually make sure it works."},{"start":1989.02,"end":1992.46,"text":"Make swap dot slash swap, 3450, 5034."},{"start":1992.46,"end":1993.02,"text":"Fantastic."},{"start":1993.02,"end":1994.06,"text":"That did, in fact, work."},{"start":1994.06,"end":1998.06,"text":"So now I feel comfortable merging those changes back into the master branch."},{"start":1998.06,"end":2001.82,"text":"So I''m going to go to the master branch via git checkout master."},{"start":2001.82,"end":2005.54,"text":"And notice once again, this is the version that''s currently in the master branch."},{"start":2005.58,"end":2008.78,"text":"And my function branch has that new commit that I want to merge in."},{"start":2008.78,"end":2012.82,"text":"If I type git merge function, what that''s going to do"},{"start":2012.82,"end":2016.3,"text":"is it''s going to take the changes on the function branch."},{"start":2016.3,"end":2018.26,"text":"And it will merge them into the master branch"},{"start":2018.26,"end":2021.82,"text":"so that that new commit, that version where I made the new function,"},{"start":2021.82,"end":2023.46,"text":"will now become part of master."},{"start":2023.46,"end":2025.06,"text":"And there shouldn''t be any merge conflicts"},{"start":2025.06,"end":2026.62,"text":"because I haven''t changed master."},{"start":2026.62,"end":2028.22,"text":"So I press return."},{"start":2028.22,"end":2029.06,"text":"It makes those changes."},{"start":2029.06,"end":2030.78,"text":"And now this is my master branch."},{"start":2030.78,"end":2032.3,"text":"And I have that swap function."},{"start":2032.3,"end":2034.62,"text":"And you can show if I type git branch,"},{"start":2034.62,"end":2036.42,"text":"I am still on the master branch."},{"start":2036.42,"end":2042.1,"text":"But that new function that I created in the function branch now exists in master."},{"start":2042.1,"end":2045.06,"text":"And at this point, if I wanted to, I could delete the function branch"},{"start":2045.06,"end":2046.18,"text":"because I no longer need it."},{"start":2046.18,"end":2051.5,"text":"And the command to do that is git branch dash capital D for delete"},{"start":2051.5,"end":2052.86,"text":"followed by the name of the branch."},{"start":2052.86,"end":2056.5,"text":"So git branch dash d function, deleted branch function."},{"start":2056.5,"end":2060.58,"text":"So now if I type git branch again, I only have the master branch."},{"start":2060.58,"end":2064.06,"text":"And if I were to get log to look at all the commits that I''ve made,"},{"start":2064.06,"end":2068.82,"text":"I would see that out of swap function is now there as a commit in the master"},{"start":2068.82,"end":2073.62,"text":"branch because I merged those commits into that particular branch."},{"start":2073.62,"end":2075.58,"text":"Any question on how that works?"},{"start":2075.58,"end":2078.34,"text":"And so merging and having branches is a very, very powerful tool."},{"start":2078.34,"end":2081.22,"text":"And I would highly recommend it when you''re working on your final projects"},{"start":2081.22,"end":2084.78,"text":"because if you want to kind of be a little bit ambitious and potentially"},{"start":2084.78,"end":2087.74,"text":"test new changes to the code, this can be a good way of making sure"},{"start":2087.74,"end":2090.66,"text":"that you still hold on to the original while still allowing yourself"},{"start":2090.66,"end":2094.02,"text":"the creative freedom to experiment and make changes and mess with the stuff"},{"start":2094.02,"end":2095.02,"text":"that you''ve already written."},{"start":2097.5,"end":2097.98,"text":"All right."},{"start":2097.98,"end":2102.7,"text":"And last thing I''ll kind of briefly touch on but won''t do a demonstration of"},{"start":2102.7,"end":2103.98,"text":"is something called pull request."},{"start":2103.98,"end":2107.22,"text":"This happens very frequently in open source projects especially."},{"start":2107.22,"end":2112.58,"text":"But if you''ve made a change to a repository either in a separate branch"},{"start":2112.58,"end":2115.38,"text":"or potentially in a fork, like I mentioned earlier, where a fork is"},{"start":2115.38,"end":2118.5,"text":"just kind of your version of someone else''s repository,"},{"start":2118.5,"end":2122.98,"text":"sometimes you may want to request to kind of merge those changes back"},{"start":2123.02,"end":2124.46,"text":"into the original version."},{"start":2124.46,"end":2128.5,"text":"And so this would be when you would submit a pull request as the terminology goes."},{"start":2128.5,"end":2130.3,"text":"And so if you hear that, know that all that means"},{"start":2130.3,"end":2134.26,"text":"is that you''ve made changes to some repository either in a different branch"},{"start":2134.26,"end":2136.62,"text":"or in a different forked repository altogether."},{"start":2136.62,"end":2138.86,"text":"And you would like to then kind of merge it back"},{"start":2138.86,"end":2140.94,"text":"into whatever the original version was."},{"start":2140.94,"end":2143.34,"text":"And this is typically done via a pull request."},{"start":2143.34,"end":2145.46,"text":"And GitHub has functionality built into it"},{"start":2145.46,"end":2149.26,"text":"to allow for pull requests to happen and to allow for whoever"},{"start":2149.26,"end":2151.78,"text":"owns a repository to kind of review pull requests,"},{"start":2151.78,"end":2153.78,"text":"look at the changes that people have made,"},{"start":2153.78,"end":2158.02,"text":"and either decide to approve or reject those changes."},{"start":2158.02,"end":2160.54,"text":"So once again, Git is a very valuable tool"},{"start":2160.54,"end":2163.02,"text":"that helps you kind of keep track of different changes to your code,"},{"start":2163.02,"end":2166.34,"text":"makes sure different collaborators can work together on the same repository,"},{"start":2166.34,"end":2169.78,"text":"makes sure you can be ambitious and test new changes without losing"},{"start":2169.78,"end":2172.7,"text":"the original copy of your code, and also allows you to, if you ever"},{"start":2172.7,"end":2176.06,"text":"do make a mistake, to go back to a previous version."},{"start":2176.06,"end":2178.66,"text":"So as long as you are kind of frequently making commits,"},{"start":2178.66,"end":2181.54,"text":"saving the work that you''re doing, this can be a very, very valuable tool"},{"start":2181.54,"end":2183.98,"text":"for keeping track of the different versions of your code"},{"start":2183.98,"end":2187.66,"text":"and making sure that your project is under control."},{"start":2187.66,"end":2191.18,"text":"I''ll take any questions now, but that''s what I had for you today."},{"start":2191.18,"end":2192.18,"text":"All good?"},{"start":2192.18,"end":2192.98,"text":"All right, fantastic."},{"start":2192.98,"end":2195.66,"text":"Thank you both for coming."},{"start":2195.66,"end":2196.16,"text":"Yeah."},{"start":2196.16,"end":2198.16,"text":"Question."},{"start":2198.16,"end":2202.34,"text":"Can you walk through quickly what happens when we do a submit50 on our P6?"},{"start":2202.34,"end":2202.94,"text":"Oh, yeah."},{"start":2202.94,"end":2208.94,"text":"So submit50 is, OK, let me make sure I''m remembering this correctly."},{"start":2209.34,"end":2212.9,"text":"Submit50 is basically what that''s happening is every time you submit50"},{"start":2212.9,"end":2220.02,"text":"something, you are submitting kind of a new branch to your submit50 repository."},{"start":2220.02,"end":2223.58,"text":"So when you typed in something like submit50 pset7, what was happening"},{"start":2223.58,"end":2227.18,"text":"is behind the scenes, we were creating a new branch called pset7,"},{"start":2227.18,"end":2231.38,"text":"and we were kind of pushing all of those changes to GitHub as a brand new branch."},{"start":2231.38,"end":2233.66,"text":"So if you were ever to go to github.com."},{"start":2233.66,"end":2237.66,"text":"slash submit50 slash your username, that in itself is a repository."},{"start":2237.7,"end":2239.86,"text":"Each student in the class has a repository."},{"start":2239.86,"end":2244.74,"text":"And within that repository, there are branches for each of the different times"},{"start":2244.74,"end":2245.5,"text":"you submit50."},{"start":2245.5,"end":2250.06,"text":"So there''s a submit50 for Mario, there''s a submit50 for 15,"},{"start":2250.06,"end":2253.46,"text":"there''s a submit50 for the test, and each one of those are just different branches"},{"start":2253.46,"end":2256.62,"text":"that are named with whatever the name of the problem is and the name of the problems"},{"start":2256.62,"end":2259.1,"text":"that are the name of the test."},{"start":2259.1,"end":2262.3,"text":"And so whenever you do a submit50, it pushes those to a new branch."},{"start":2262.3,"end":2266.46,"text":"And then what we do is we tag those changes as a new release such that it"},{"start":2266.46,"end":2269.98,"text":"makes it easy for us to kind of look at all of the changes that you''ve made."},{"start":2269.98,"end":2273.9,"text":"We didn''t go into tagging and releases in this seminar, but it''s just yet"},{"start":2273.9,"end":2276.7,"text":"another way of kind of keeping track of different versions of code and"},{"start":2276.7,"end":2278.62,"text":"keeping track of different changes to it."},{"start":2278.62,"end":2283.22,"text":"And it''ll release to say a big, big moment in the quotation where"},{"start":2283.22,"end":2286.02,"text":"that this is working is narrowing."},{"start":2286.02,"end":2287.98,"text":"Yeah, yeah, that''s typically what it would be used for exactly."},{"start":2287.98,"end":2291.34,"text":"And so when you submit something, that''s kind of our semantic equivalent of saying"},{"start":2291.34,"end":2294.98,"text":"that you''ve now supposedly gotten your problems at working,"},{"start":2295.02,"end":2296.94,"text":"and this is the version that you want graded."},{"start":2296.94,"end":2298.54,"text":"And it''s so we''ll tag those."},{"start":2298.54,"end":2300.3,"text":"That''s kind of the way it works."},{"start":2300.3,"end":2300.78,"text":"Good question, though."},{"start":2302.5,"end":2303.38,"text":"Okay, thank you so much."}]'::jsonb
) AS segment
WHERE l.youtube_video_id = 'MJUJ4wbFm_A';

