INSERT INTO transcript_chunks (lesson_id, chunk_text, start_time, end_time)
SELECT
    l.id AS lesson_id,
    segment.value->>'text' AS chunk_text,
    (segment.value->>'start')::numeric AS start_time,
    (segment.value->>'end')::numeric AS end_time
FROM lessons l
CROSS JOIN jsonb_array_elements(
    '[{"start":0,"end":7.04,"text":"In this Microsoft Excel dashboard course, you''ll learn how to transform raw data into insightful"},{"start":7.04,"end":14.24,"text":"interactive visualizations. This course will walk you through designing dynamic charts and building"},{"start":14.24,"end":20.4,"text":"professional dashboards that enhance data storytelling. With hands-on exercises, you''ll master the"},{"start":20.4,"end":26.88,"text":"tools and techniques needed to create compelling data visualizations in Excel, and you''ll be equipped"},{"start":26.96,"end":32.8,"text":"to present data in a way that drives informed decision-making. Me here from Office Tech Skill"},{"start":32.8,"end":34.24,"text":"developed this course."},{"start":34.24,"end":38.64,"text":"Truggling to find the perfect chart to represent your data? Let''s unlock the secret of Excel"},{"start":38.64,"end":43.12,"text":"charts together. Today I''ll walk you through the various chart types available in Excel and how to"},{"start":43.12,"end":48.08,"text":"use the right one for your data. Hi, I''m Meet Kamdar, your tutor at officetechskill.com,"},{"start":48.08,"end":52.08,"text":"where we specialize in helping professionals upgrade their text skills to enhance productivity"},{"start":52.08,"end":56.48,"text":"and efficiency in the workplace. Let''s discuss various chart types that you can implement"},{"start":56.48,"end":62.24,"text":"within Excel. The topics we are going to cover in this section include column chart, bar chart,"},{"start":62.24,"end":68.88,"text":"line chart, pie donut chart, XY scatter plot chart, area chart, radar chart, stock chart,"},{"start":68.88,"end":74.32,"text":"histogram chart, parietal chart, waterfall chart, box and whisker chart, treemap chart,"},{"start":74.32,"end":78.48,"text":"map chart, recommended chart. Now let''s discuss what is a column chart."},{"start":78.48,"end":83.44,"text":"Column charts are drawn with the rectangular bars of various lengths we present in different"},{"start":83.44,"end":88.4,"text":"values. There are different types of column charts such as cluster chart, stack column chart,"},{"start":88.4,"end":93.6,"text":"and 100% stack column chart. Cluster column charts use color to differentiate the column,"},{"start":93.6,"end":98.8,"text":"whereas the stack column chart use varying thickness or colors for each column. Column"},{"start":98.8,"end":103.68,"text":"charts are an effective means of displaying data, variation over a period, or comparing"},{"start":103.68,"end":108.4,"text":"various elements. Typically, the categories are placed on one axis and the value on another,"},{"start":108.4,"end":114,"text":"allowing for a clear visualization of changes or updates with each comparison point in the"},{"start":114,"end":119.6,"text":"narrative. So currently we have a data set which has sales by month for two products,"},{"start":119.6,"end":124.32,"text":"which is product one and product two. So column chart is an excellent candidate for this kind of"},{"start":124.32,"end":129.92,"text":"data set. We''ll select first the data set, press control A, we''ll go to insert, we''ll go to recommended"},{"start":129.92,"end":138.4,"text":"charts, we''ll go to all charts, we''ll go to column, and then we can select a cluster column chart."},{"start":142.88,"end":148.4,"text":"Now we can add the chart and access title. The chart title is already there. Now we can add the"},{"start":148.4,"end":160.48,"text":"access title as well. Expand the chart. So we can add the chart title as product one versus"},{"start":162.24,"end":167.44,"text":"product two sales."},{"start":168.4,"end":181.6,"text":"The y axis is sales and x axis is the month."},{"start":184.4,"end":190.88,"text":"Now we can change the color of the bars. So for product one, we can just select the blue bar"},{"start":190.88,"end":195.76,"text":"and now change the color, right mouse click on the bar and change this to red."},{"start":198.24,"end":203.28,"text":"Same thing with the orange bar, right mouse click on it and change the color to gray."},{"start":209.52,"end":214.96,"text":"Your column chart is ready. If you want to change the chart type, you can go to the chart design"},{"start":215.68,"end":223.12,"text":"tab, then select change chart type. So if you want to change from cluster column to stack column,"},{"start":224.16,"end":230.64,"text":"you can simply click on this and press OK. Or you can change it to some other style that you prefer."},{"start":233.2,"end":238.56,"text":"Now let''s try to understand bar chart. Bar chart is drawn with rectangular bars of various lengths"},{"start":238.56,"end":244.4,"text":"representing different values. It is often used to compare two or more discrete values. The size of"},{"start":244.4,"end":249.36,"text":"the rectangle relates to the magnitude of the value it represents. So the taller indicates"},{"start":249.36,"end":254.08,"text":"the greater value than shorter ones. There are different types of bar chart such as cluster,"},{"start":254.08,"end":259.68,"text":"stacked 100% stack bar charts. Bar charts are used color to differentiate the bars,"},{"start":259.68,"end":264.8,"text":"whereas the stack bar charts use varying thickness or colors for each bar. Now let''s go back to the"},{"start":264.8,"end":271.2,"text":"Excel, go to the bar chart time. Over here, we again have the same data, which is data for sales"},{"start":271.2,"end":276.08,"text":"by month for product one and product two. Now we can use this data set to create a bar chart."},{"start":276.08,"end":281.68,"text":"So select the data, click on insert, go to recommended charts, go to all charts, click on bar"},{"start":283.12,"end":284.96,"text":"and then select cluster bar chart."},{"start":288.8,"end":295.36,"text":"Go to the plus sign, add the access title and now you can change the name from chart title to product one"},{"start":295.36,"end":305.92,"text":"versus product two sales. The access title is going to be month"},{"start":311.36,"end":313.44,"text":"and the access title will be sales."},{"start":316.72,"end":320.24,"text":"Now we can change the color of the bar, right mouse click on the blue bar,"},{"start":320.56,"end":329.52,"text":"go to fill and we can change that to gray and right click on the orange bar,"},{"start":330.8,"end":338.4,"text":"select fill and we can change that to red. Your cluster bar chart is ready. Now if you want to"},{"start":338.4,"end":344.64,"text":"change from cluster bar to stack bar chart, you can just go to the chart design, go to change chart"},{"start":344.64,"end":353.2,"text":"type and then you can select stack bar or you can select 100% stack bar depending on whatever"},{"start":353.2,"end":359.28,"text":"your preferences, press OK. As you see now the chart type is changed. Now let''s try to understand"},{"start":359.28,"end":364.16,"text":"what is line chart. Line chart is a type of chart that distrails information as a series of data"},{"start":364.16,"end":368.96,"text":"point. It is also known as time series chart line charts are a type of chart that expresses"},{"start":368.96,"end":373.84,"text":"information as a series of data points line charts are good for showing how something has changed"},{"start":373.84,"end":378.4,"text":"or comparing two different things. There are different types of line charts such as line"},{"start":378.4,"end":384,"text":"stacked 100% stack line with markers stacked line with markers and 100% stack line with markers"},{"start":384,"end":388.48,"text":"chart. Now let''s go back to the Excel, go to the line chart tab. Again, we have the same data by"},{"start":388.48,"end":394.32,"text":"month product sales for product one and product two. Now we will select this data set and create a"},{"start":394.32,"end":400.4,"text":"line chart, go to recommended charts, go to all charts, go to line and we''ll select line chart,"},{"start":400.4,"end":407.12,"text":"press OK. And now we''ll go to the plus sign, add the access title."},{"start":409.28,"end":412.4,"text":"We''ll change the title for Y access to sales"},{"start":415.04,"end":424.48,"text":"and change the title for X access to month and we''ll change the color of the line. First,"},{"start":424.48,"end":433.52,"text":"we''ll add the chart title. So make it product one versus product two"},{"start":436.96,"end":446.08,"text":"sales. So go to line one or product one, go to the product two line, right mouse click"},{"start":446.96,"end":449.68,"text":"and go to outline and select gray color."},{"start":453.44,"end":459.6,"text":"Go to the blue line, right mouse click, go to the outline tab and select red."},{"start":462.4,"end":467.28,"text":"And now your line chart is ready. This is a simple line chart. Now let''s try to understand"},{"start":467.28,"end":472.4,"text":"pie donut chart. Pie donut chart are typically used to show the proportional contribution of"},{"start":472.4,"end":477.68,"text":"each component to an overall chart. The pie chart is a variation of circle graph or pie graph,"},{"start":477.68,"end":482.56,"text":"also known as circle chart where each slice is drawn as a circle segment based on the"},{"start":482.56,"end":488.4,"text":"angle swept out of its radius to the center point. Pie charts are used in finance and statistical"},{"start":488.4,"end":493.84,"text":"field. Certain types of reports such as progress report, graphic displays with limited space for"},{"start":493.84,"end":498.64,"text":"text. They''re often thought to be difficult to read by humans because our eyes do not naturally"},{"start":498.64,"end":503.28,"text":"follow an arc. Still, they can be read more effectively if labeled with their respective"},{"start":503.28,"end":508.72,"text":"values. Let''s go back to the Excel, go to the pie chart tab and now we''ll insert a pie chart."},{"start":508.72,"end":515.04,"text":"Press control A, go to insert, select recommended charts, go to all charts, go to pie,"},{"start":516,"end":522.16,"text":"click on the pie chart, press okay. As you see the pie chart is created. Now we can add data labels"},{"start":522.16,"end":527.28,"text":"to understand what is the revenue for each pie. Now we can also create a donut chart. So you can"},{"start":527.28,"end":540.4,"text":"just copy this chart and paste right next to it. Go to chart design, go to change chart type and you"},{"start":540.4,"end":547.12,"text":"can select donut chart, press okay. Now let''s try to understand XY scatterplot chart. This"},{"start":547.12,"end":552.48,"text":"scatterplot chart is a graph that shows an association between two variables. For example,"},{"start":552.48,"end":557.92,"text":"when the graph is called an XY chart, you can see the relationship between two variables on one"},{"start":557.92,"end":563.2,"text":"graph. When one variable can be plotted on the x-axis, the other one can be plotted on y-axis."},{"start":563.2,"end":567.6,"text":"The scatterplot can show whether there is a correlation between two variables. It also"},{"start":567.6,"end":572.96,"text":"shows how strong the correlation might be making it easier for readers to understand what they''re"},{"start":572.96,"end":579.04,"text":"looking at. So let''s go to Excel, go to XY chart and now we''ll use the same data set which is"},{"start":579.12,"end":584.32,"text":"sales by month for product one and product two. Press control A, go to insert, click on recommended"},{"start":584.32,"end":590.8,"text":"charts, go to all charts, go to XY scatterplot chart and then select scatter with smooth lines"},{"start":590.8,"end":604.4,"text":"and markers. Press okay. Insert the title, access title, provide the chart name to product one"},{"start":604.64,"end":613.76,"text":"versus product two sales title for y-axis title for x-axis month."},{"start":615.52,"end":622.16,"text":"Your chart is ready. Now you can experiment with other XY charts by creating a duplicate chart."},{"start":623.68,"end":628.96,"text":"So we''ll create a duplicate chart. We''ll go to chart design, change chart type"},{"start":629.92,"end":636.08,"text":"and then you can select any chart you want for XY. We''ll select this chart for example"},{"start":636.8,"end":641.92,"text":"and now you can compare between two charts and see which one works best for you. Now let''s try to"},{"start":641.92,"end":647.6,"text":"understand area chart. An area chart is created by plotting the data on vertical, i-axis and the"},{"start":647.6,"end":653.36,"text":"category on the horizontal axis. The total area under each graph can be calculated by adding"},{"start":653.36,"end":658.16,"text":"up all the areas under each rectangle stacked above each other. The height of each rectangle"},{"start":658.24,"end":663.84,"text":"corresponds to each relative value or frequency about different rectangles or bars stacked below"},{"start":663.84,"end":668.72,"text":"it. It is a graphical depiction on the number of frequency of observation in different categories."},{"start":668.72,"end":673.92,"text":"Let''s go to the spreadsheet, go to the area chart time. Now we''ll create a"},{"start":673.92,"end":680.8,"text":"area chart for this data set. So select control A, go to insert, go to recommended charts,"},{"start":680.8,"end":686.8,"text":"go to all charts, go on the area and then select this chart. Press okay. Click on the plus sign"},{"start":687.44,"end":698,"text":"and add the axis title. Provide the title name as product one versus product two, sales."},{"start":700.88,"end":702.48,"text":"The y-axis will be sales"},{"start":706.48,"end":708.64,"text":"and the x-axis is going to be the month."},{"start":709.12,"end":718.48,"text":"Now if you want to look at other area charts, you can just simply copy and paste right next to it."},{"start":720,"end":725.92,"text":"Now you can change the chart style. So click on this chart, go to chart design, go to"},{"start":727.12,"end":733.04,"text":"change chart type and now you can select any chart you want. So if I want to select stacked area"},{"start":733.04,"end":739.28,"text":"chart, press okay. Now you can compare and see which one suits you need. Now let''s try to understand"},{"start":739.28,"end":745.36,"text":"radar chart. Radar chart diagram can simultaneously visualize three or more data sets. It is typically"},{"start":745.36,"end":751.2,"text":"used to compare qualitative data but also can be used for quantitative data. The radar chart may"},{"start":751.2,"end":756.32,"text":"seem intimidating but it is straightforward to use. So this chart is helpful when you have multiple"},{"start":756.32,"end":762,"text":"time series or different dimensions on the same chart. So let''s go back to the Excel, go to the"},{"start":762,"end":768.32,"text":"radar chart time. So now we have the sales for three products a month. Select all the data,"},{"start":768.32,"end":774.72,"text":"go to insert, go to recommended charts, go to all charts, go to radar and click on okay."},{"start":775.76,"end":782.56,"text":"Now you can add the title as product comparison, sales."},{"start":784.64,"end":789.04,"text":"You can expand the chart to make it more visible. You can create a duplicate chart"},{"start":789.04,"end":793.6,"text":"and select other radar chart. See a side by side comparison of which chart"},{"start":793.6,"end":799.2,"text":"puts better. So select the duplicate chart, go to chart design, go to change chart type."},{"start":801.12,"end":808.16,"text":"You can select this chart or you can select radar with markers. Press okay. Now let''s try to"},{"start":808.16,"end":813.28,"text":"understand the stock chart. Stock chart is a visual representation of historical data. It helps to"},{"start":813.28,"end":819.2,"text":"quickly overview of what has happened and identify patterns and trends. Stock chart are handy for"},{"start":819.2,"end":824.08,"text":"investors who want to know how their assets perform. They can help them make better financial"},{"start":824.08,"end":828.48,"text":"decisions and react quickly when the market shifts. When to use a stock chart in Excel,"},{"start":828.48,"end":833.36,"text":"there are various reasons to utilize a stock chart in Excel such as tracking the performance of"},{"start":833.36,"end":838.48,"text":"investment, the stock market, identifying trend lines and determine support and resistance level."},{"start":838.48,"end":843.12,"text":"Using the stock chart can aid in making informed decisions. Now let''s go to the Excel,"},{"start":843.12,"end":848.48,"text":"go to the stock chart tab. Now we have a data of a particular stock, which has price point and the"},{"start":848.48,"end":853.44,"text":"market was open, the highest value of the day, the lowest value of the day, closing value of the day"},{"start":853.44,"end":858.08,"text":"and the adjusted closing value of the day. Also we have the volume and we have the data by dates."},{"start":858.08,"end":864.64,"text":"Now we want to create a stock chart which has a value of high, low and close and we want to see it"},{"start":864.64,"end":872.4,"text":"by date. So we''ll select these four columns. So it''s going to be date, high, low and close."},{"start":872.4,"end":878.96,"text":"So now go to recommended charts, go to all charts, go to stock, press OK."},{"start":884.32,"end":887.04,"text":"You can change the chart title to high, low, close."},{"start":894.96,"end":898.32,"text":"You can include the access title."},{"start":901.92,"end":904.16,"text":"So this is going to be price on the y-axis"},{"start":908.24,"end":910.16,"text":"and on the x-axis is going to be the date."},{"start":917.68,"end":921.84,"text":"You can change the chart style by clicking on the chart, go to chart design"},{"start":922.16,"end":930.4,"text":"and you can select style to as an option. You can add a line for high and low to see how the trend"},{"start":931.2,"end":938.16,"text":"changes over day. So click on the top part of the line and then go to line."},{"start":938.96,"end":944.8,"text":"Then you can select a solid line. We can change the color to gray, go to the bottom part,"},{"start":945.68,"end":950.32,"text":"select the bottom part which is now you want to add a line for low,"},{"start":951.6,"end":958.64,"text":"select solid line and then select yellow. As you see now it has a gray line for high"},{"start":958.64,"end":966.16,"text":"and yellow line for low and the circle represents the closing price of the stock."},{"start":966.16,"end":970.4,"text":"Now let''s try to understand the histogram chart. The histogram chart is a graphical"},{"start":970.4,"end":974.24,"text":"representation of the breakdowns of the data set into different categories."},{"start":974.24,"end":979.36,"text":"The histogram chart is a graph that displays the frequency distribution of data typically"},{"start":979.36,"end":986.64,"text":"split into categories. So for example, it can show how different sets are distributed in frequency."},{"start":986.64,"end":993.36,"text":"Let''s go back to Excel, go to the histogram chart tag. We have the data by customer and my profit."},{"start":993.92,"end":999.44,"text":"So now we can use a histogram in order to put the profit into different buckets because it''s a"},{"start":999.44,"end":1005.68,"text":"range. So it can put into different buckets. We can group the customer into that bucket. So select"},{"start":1005.68,"end":1013.84,"text":"the data set, go to insert, go to recommended charts, go to all charts, go to histogram and press OK."},{"start":1016.16,"end":1023.84,"text":"As you see, Excel has automatically created the grouping. We can add the chart title as customer"},{"start":1024.72,"end":1036.4,"text":"profit range. You can also add the data labels, click on the chart, go to plus sign and then add"},{"start":1036.4,"end":1042.88,"text":"data labels. So currently now the range is not visible. So you can just expand the chart."},{"start":1044.8,"end":1047.04,"text":"So you can see the highest and the lowest value."},{"start":1047.84,"end":1056.88,"text":"Currently there are six bins. Now you can customize the bins. You can select the lowest and the highest"},{"start":1056.88,"end":1064.16,"text":"value based on your need. So if you click on the values on the X axis, you have the option"},{"start":1065.84,"end":1072.72,"text":"to select the bin. So there are six categories broken into 280,000. So you can change this"},{"start":1072.8,"end":1077.36,"text":"to 300,000 and then press OK."},{"start":1083.44,"end":1090.64,"text":"It has changed the range from zero to 300,000. You can provide the bin width or also you can"},{"start":1090.64,"end":1100.8,"text":"provide the number of bins and it will calculate and select the range. So press enter and now you"},{"start":1100.8,"end":1107.2,"text":"see there are five bins instead of six. So you can customize based on your need."},{"start":1107.2,"end":1112,"text":"Let''s try to understand what is a Pareto chart. Pareto chart is a graphical representation of the"},{"start":1112,"end":1118.32,"text":"80-20 principle. It plots a cumulative percentage of events or outcomes found on vertical axis and"},{"start":1118.32,"end":1123.52,"text":"the frequency or rate of these events on a horizontal axis. A Pareto chart is a great way to"},{"start":1123.52,"end":1128.8,"text":"understand what matters most in a given category. It is easy to understand chart that people can"},{"start":1128.8,"end":1133.76,"text":"use to identify and prioritize their efforts or decide what they want to focus on to achieve"},{"start":1133.76,"end":1138.64,"text":"better results. It helps to determine where to put most of your time and resources by looking at the"},{"start":1138.64,"end":1145.76,"text":"top priorities. We have data by region with total transaction. So now we''ll use Pareto chart to"},{"start":1145.76,"end":1152.08,"text":"understand which region has the highest transaction. So select the data, go to insert, go to recommended"},{"start":1152.08,"end":1159.84,"text":"charts, go to all charts, go to histogram and then select Pareto chart. Click OK. You can expand"},{"start":1159.84,"end":1171.28,"text":"the chart and provide the chart name as transaction count by region. As you see Europe has the highest"},{"start":1171.28,"end":1176.24,"text":"transaction. So this will tell a user that they need to place more emphasis on Europe and sub-saharan"},{"start":1176.24,"end":1180.72,"text":"Africa since they both have the highest transactions. Now let''s try to understand what is waterfall"},{"start":1181.28,"end":1187.04,"text":"chart. Waterfall chart is a type of chart that shows how various levels of one or more variables"},{"start":1187.04,"end":1192.88,"text":"stack up against each other. It is also known as high-rap, kikal, barcraft because it depicts the"},{"start":1192.88,"end":1199.28,"text":"data in water form or hierarchical form. Shareholding companies typically use waterfall charts to direct"},{"start":1199.28,"end":1204.72,"text":"cash flow during a financial year. The chart is divided into months with each waterfall chart showing"},{"start":1204.72,"end":1209.76,"text":"the available funds for that month. Now let''s go to Excel and implement this chart. Go to the"},{"start":1209.76,"end":1216.32,"text":"waterfall chart tab. The data set shows the date and the daily profit. So now we''ll use waterfall"},{"start":1216.32,"end":1222.32,"text":"chart to understand this data. So select the data, go to insert, go to recommended charts, go to"},{"start":1222.32,"end":1228.4,"text":"waterfall, click OK. The chart is created. Now we can change the chart title to daily profit."},{"start":1230.72,"end":1239.04,"text":"So click on the legend for increase. Go to the color icon and change from solid. Go to solid."},{"start":1239.76,"end":1244.88,"text":"Now change it to green. Click on the decrease legend. Go to the color icon. Go to solid fill"},{"start":1245.76,"end":1250.96,"text":"and change it to red. The bars are more visible and you can see where the profit has increased"},{"start":1250.96,"end":1256.48,"text":"or decreased based on the date. Let''s try to understand box and whisker chart. Box and whisker"},{"start":1256.48,"end":1263.04,"text":"chart represents the data distribution. The vertical line above and below boxes represents the"},{"start":1263.04,"end":1270.64,"text":"maximum and the minimum value. The box shows the value between the 25th through 75th percentile and"},{"start":1270.64,"end":1276,"text":"the horizontal line represents the 58th percentile. And now we will create a box and whisker chart based"},{"start":1276,"end":1282.8,"text":"on this data set. So click on insert. Go to recommended charts. Go to all charts. Select box"},{"start":1282.8,"end":1289.76,"text":"and whiskers. Click OK. And now you see the chart is created. We can add the title as transaction by"},{"start":1289.76,"end":1303.76,"text":"region. And we can also add the access title. Select the plus sign. Take a mark on the access"},{"start":1303.76,"end":1315.76,"text":"title. The y axis will be called transaction. The x axis will be called region. We can change the"},{"start":1315.76,"end":1321.76,"text":"color of the bars, make it yellow so it''s more visible. We can also select more data label options."},{"start":1322.4,"end":1328.8,"text":"Go to the number drop down and go to general and select number. You can reduce the decimal to zero"},{"start":1328.8,"end":1334.4,"text":"and as you see the decimals are removed. The minimum value, maximum value, the median, the 25th"},{"start":1334.4,"end":1340.56,"text":"percentile and the 75th percentile and also the 50th percentile. I can expand the chart to make"},{"start":1340.56,"end":1350,"text":"the data more visible and the data labels. As you see now after expanding the chart, the data looks"},{"start":1350,"end":1355.44,"text":"more visible. The line on the bottom shows the minimum value. The line on the top shows the"},{"start":1355.44,"end":1365.12,"text":"maximum value. 57 is the 25th percentile. X is the average. 78 is the median. 58th percentile."},{"start":1365.12,"end":1370.96,"text":"And 90 is the 75th percentile. Let''s try to understand the tree map chart. A tree map chart"},{"start":1370.96,"end":1375.68,"text":"is a way to visualize the hierarchy. For example, it is often used to display the proportion of"},{"start":1375.68,"end":1381.12,"text":"different values in a data set. Tree map can be drawn as squares or rectangles in nested within"},{"start":1381.12,"end":1386.64,"text":"one another to provide greater detail. IE more extensive and smaller rectangles can be drawn"},{"start":1386.64,"end":1391.36,"text":"inside one another. So when to use a tree map chart, tree map provides a quick and easy way to"},{"start":1391.36,"end":1397.2,"text":"summarize large amounts of hierarchical data. When plotting nodes, the dimensions are configured"},{"start":1397.2,"end":1403.52,"text":"based on numerical values assigned per node. This makes identifying trends between all categories"},{"start":1403.52,"end":1408.4,"text":"much more straightforward in comparing one type with another or even among different groups within"},{"start":1408.4,"end":1414.24,"text":"the same leaf branch hierarchy. Now let''s go to the Excel file. Over here we have three columns."},{"start":1414.24,"end":1419.44,"text":"This is essentially a hierarchical data. The first level is the region. The second level is the country."},{"start":1419.52,"end":1424.8,"text":"And we want to find out the revenue for each country. Select all the data, click on insert."},{"start":1425.52,"end":1434.32,"text":"Go to recommended charts. Go to all charts. Go to tree map. Click on the tree map. Press okay."},{"start":1434.32,"end":1441.28,"text":"The tree map chart is created. You can expand the chart. Now we can add the title sales by country."},{"start":1442.24,"end":1451.2,"text":"And we can move the legend to bottom. Now the chart is more visible. The data is broken by"},{"start":1452.08,"end":1458,"text":"region. So the yellow one is Europe. The navy blue is sub-Saharan Africa. The light blue is Middle"},{"start":1458,"end":1463.36,"text":"Eastern North Africa. The gray is Central America and Caribbean. And then the boxes are divided"},{"start":1463.36,"end":1469.44,"text":"based on the value of the sales. So in Europe, Serbia has the highest sales. In sub-Saharan"},{"start":1469.44,"end":1474.32,"text":"Africa, Benin has the highest sales. In Middle East and North Africa, Libya has the highest sales."},{"start":1474.88,"end":1479.52,"text":"So anyone looking at this tree map chart can easily figure it out which region and which"},{"start":1479.52,"end":1485.04,"text":"country has the highest sales. Let''s understand map chart. Map charts are a visual representation"},{"start":1485.04,"end":1490,"text":"of data in a geographical context. They help display data comparison between the region and"},{"start":1490,"end":1495.84,"text":"distribution points across the globe. Map chart provides visual representation of data on geographic"},{"start":1495.84,"end":1501.52,"text":"regions that are challenging to understand with table formats. Map charts can show anything from"},{"start":1501.52,"end":1507.76,"text":"demographics, comparative statistics or any other data time that would be difficult to see in a table"},{"start":1507.76,"end":1513.12,"text":"firm. Map charts are also accessible for use to read and understand because they give clear and"},{"start":1513.12,"end":1518.4,"text":"concise information. And now select the data. We have the same data from the tree map chart which"},{"start":1518.4,"end":1525.28,"text":"is region, country and revenue. Select all the data. Go to insert. Go to recommended charts."},{"start":1526.24,"end":1535.44,"text":"Go to all charts. Select map and now press OK. And now you can see the revenue by country."},{"start":1535.44,"end":1540.56,"text":"Let me expand the chart. The country with the darkest color has the highest sale and the"},{"start":1540.56,"end":1546.08,"text":"country with the lightest color has the lowest sales. So now we can change the title to sales by"},{"start":1546.08,"end":1553.84,"text":"country. And we''ll change the color. Go to the brush sign and then select color and then you"},{"start":1553.84,"end":1559.04,"text":"can select this color palette. You can also add the data labels that would provide you with the"},{"start":1559.04,"end":1565.12,"text":"values. Now let''s try to understand recommended charts. The recommended charts feature in itself"},{"start":1565.12,"end":1570.08,"text":"is a function that allows user to automatically generate additional types of chart that are not"},{"start":1570.08,"end":1575.6,"text":"available in the ribbon. Three things can cause a chart to be generated. User selected data,"},{"start":1575.6,"end":1580.08,"text":"data from external source, dynamic data, meaning there''s no need for user intervention."},{"start":1580.72,"end":1584.8,"text":"This feature generates and displays a list of recommended charts and graph"},{"start":1584.8,"end":1590.4,"text":"based on your data selection. The list is displayed under insert, recommended charts."},{"start":1590.4,"end":1596.4,"text":"So now let''s go to the Excel file and now select the data again. Go to insert. Go to recommended"},{"start":1596.4,"end":1602.16,"text":"charts and over here you get a list of recommended chart that Excel provides you and you can select"},{"start":1602.16,"end":1607.12,"text":"any one of these charts based on your requirement. So there you have it, a comprehensive tutorial on"},{"start":1607.12,"end":1611.52,"text":"mastering Excel chart types. Now I''m going to show you how to customize your Excel chart to make"},{"start":1611.52,"end":1615.44,"text":"them look professional and impactful. You can download the file from the description. The"},{"start":1615.44,"end":1620.08,"text":"topics we are going to cover in this video, we''ll start with organizing your data. Next,"},{"start":1620.08,"end":1625.68,"text":"we''ll select the best chart type. Then we''ll apply chart styles and template. Then we can adjust the"},{"start":1625.68,"end":1631.76,"text":"chart elements and the labels. We can use data labels and grid lines to enhance your chart. We''ll"},{"start":1631.76,"end":1636.32,"text":"apply color themes and palettes. We''ll discuss how you can utilize combination chart and secondary"},{"start":1636.4,"end":1641.52,"text":"access. We''ll show where you can incorporate trend lines. We''ll discuss different chart elements"},{"start":1641.52,"end":1646.4,"text":"that you can apply. And finally, we''ll go through some best practices for chart customization. So"},{"start":1646.4,"end":1651.6,"text":"before diving into customization, it''s essential to understand that you need to organize your data."},{"start":1651.6,"end":1656.56,"text":"So go back to Excel. First, we want to ensure your data is organized in a tabular format. You have"},{"start":1656.56,"end":1662.08,"text":"the column headers on the top and there are no blank rows or columns in your data set. To make"},{"start":1662.16,"end":1667.2,"text":"your data easier to reference when creating and updating charts, you can put this data into a"},{"start":1667.2,"end":1673.04,"text":"name range. So we''ll just select this data from A1 through C13. We''ll go to the formula tab and then"},{"start":1673.04,"end":1679.68,"text":"click on define name range. And in our case, the range is already created. So if I select edit,"},{"start":1679.68,"end":1686,"text":"you can provide a name range. So you can name it as sales data and click OK. So anytime now you"},{"start":1686,"end":1691.36,"text":"want to refer to the data, you can just use this, the name, which is sales data. Now we want to choose"},{"start":1691.36,"end":1698.56,"text":"the best chart type for this data. So go to insert. In our case, we''ll select column chart because this"},{"start":1698.56,"end":1705.12,"text":"data type is better suited to show in a column chart. So I''ll just select a cluster column chart"},{"start":1705.12,"end":1710.48,"text":"because we want to compare two different products side by side. Now we want to apply some chart"},{"start":1710.48,"end":1715.76,"text":"styles. And also we can discuss some templates that you can use. So if you click on the chart,"},{"start":1715.76,"end":1720.8,"text":"you can go to the chart design tab and over here you have options to select any of the chart style."},{"start":1720.8,"end":1725.84,"text":"I''ll just keep it default. Next, we''ll adjust some chart elements and labels. So if you click on this"},{"start":1725.84,"end":1731.44,"text":"plus sign, you can click on access style, you can change the legend on the top, make it on the top."},{"start":1732.08,"end":1737.36,"text":"You can remove the grid lines. And now we can also change the name of the chart. So we''ll make it as"},{"start":1737.36,"end":1743.92,"text":"monthly sales product one versus product two. This is called revenue. And this is called month."},{"start":1744.8,"end":1750,"text":"Now you can enhance the chart look by adding the data labels or data tables and grid lines. So if I"},{"start":1750,"end":1754.8,"text":"click on the chart again, if I click on data labels, you''ll see the data or you''ll see the value for"},{"start":1754.8,"end":1759.68,"text":"each and every bar, but then you''ll have to expand the chart or you can use data table instead of"},{"start":1759.68,"end":1763.84,"text":"labels. You can select data table and this will show all the values on the bottom. So it''s more"},{"start":1763.84,"end":1769.68,"text":"organized and clean. You can also add a grid line. So you know exactly that becomes easier to analyze."},{"start":1769.68,"end":1775.44,"text":"You can apply color theme and palettes. So Excel has already a lot of prebuilt colors and palettes"},{"start":1775.44,"end":1780.24,"text":"that you can utilize. So if you click on the plus sign or click on the brush icon, you can select"},{"start":1780.24,"end":1785.12,"text":"go to color and then you can select any of the color palettes that you like. You can also go to"},{"start":1785.12,"end":1790.64,"text":"chart design and select it from there and you can select from here as well. It''s one the same thing,"},{"start":1790.64,"end":1795.84,"text":"just different ways of accessing. Let''s say if I don''t like the color that''s being displayed or"},{"start":1796.16,"end":1800.56,"text":"in the color palette, you can also manually change it by clicking on the bar and this will select"},{"start":1800.56,"end":1804.72,"text":"all the bars and then you can go to home and then you can just simply choose the color of your"},{"start":1804.72,"end":1809.28,"text":"choice. So I''ll select black and I''ll select the other one as orange or make it gray."},{"start":1810.56,"end":1815.36,"text":"We can also implement some advanced techniques. We can use combination charts and secondary"},{"start":1815.36,"end":1819.84,"text":"access to look at the same data in a different way. So you can click on this chart, go to change"},{"start":1819.84,"end":1825.76,"text":"chart or go to chart design, select change chart type. You can go to chart design, select change"},{"start":1825.76,"end":1830.72,"text":"make this combo and over here you can select that you want the product one to be a column and product"},{"start":1830.72,"end":1836.24,"text":"two be as shown as line. So this is how your data would show. So click OK. And as you see,"},{"start":1836.24,"end":1840.8,"text":"you can add secondary access. Your secondary access is showing here, which is product two."},{"start":1840.8,"end":1845.68,"text":"You can change the color by simply clicking on the bar and you can also change the color of the"},{"start":1845.68,"end":1850.88,"text":"line can go to format, go to shape outline and then select any color of your choice. You can"},{"start":1850.88,"end":1855.52,"text":"also incorporate trend line if you want to see how the data is trending over a particular period"},{"start":1855.52,"end":1860.32,"text":"of time. So let''s say if you want to find out what''s the trend for product one, you can just"},{"start":1860.32,"end":1864.48,"text":"simply click on the plus sign, click on the trend line and this will give you the option. If you"},{"start":1864.48,"end":1868.24,"text":"want to see the trend line for product one or product two, so I''ll select product one. And as"},{"start":1868.24,"end":1872.96,"text":"you see, the trend line is slightly increasing. It''s more or less the same. If you want to change"},{"start":1872.96,"end":1876.72,"text":"some formatting of the trend line, you can right mouse click on the trend line and click on format"},{"start":1876.72,"end":1881.52,"text":"trend line. And you will see this dialog box will open up currently showing linear trend line. You"},{"start":1881.52,"end":1886.64,"text":"can change it to exponential logarithmic polynomial power. So depending on your choice, I''ll stick"},{"start":1886.64,"end":1893.92,"text":"to linear. You can apply additional chart elements or you can customize the chart elements by just"},{"start":1893.92,"end":1898.4,"text":"simply clicking on the chart, go to chart design and then go to the drop down of the chart elements."},{"start":1898.4,"end":1903.12,"text":"And over here, you have more options based on any changes you want to make to ensure your customized"},{"start":1903.12,"end":1908.32,"text":"charts are effective and professional. You can follow some of these best practices for customization."},{"start":1908.32,"end":1913.52,"text":"First, you want to prioritize clarity and simplicity by removing unnecessary chart elements such as"},{"start":1913.52,"end":1918,"text":"redundant label and you want to focus on the key message that you want to convey. Next, you want to"},{"start":1918,"end":1923.52,"text":"use clear and concise style for your chart and also for your access. So the person who is looking"},{"start":1923.52,"end":1928.8,"text":"at your chart can easily understand the context of your data. Next, you want to choose the appropriate"},{"start":1928.88,"end":1933.44,"text":"chart type and data ranges that accurately represents your data and insight, avoiding"},{"start":1933.44,"end":1938.56,"text":"distorting or misrepresenting data by using misleading chart types or scale can send the"},{"start":1938.56,"end":1943.12,"text":"wrong message to the person who''s looking at your chart. Consider your target audience and tailor"},{"start":1943.12,"end":1948.32,"text":"your chart design and formatting use colors, font styles that are easy to read and interpret. Now,"},{"start":1948.32,"end":1953.28,"text":"I''m going to show you how to create an engaging and effective Excel dashboard, a crucial skill for"},{"start":1953.28,"end":1957.76,"text":"any data driven professional. So you will be building this dashboard as you see in the screen."},{"start":1957.76,"end":1963.04,"text":"This is a very fast paced video where I won''t go into the nuts and bolts of each and every"},{"start":1963.04,"end":1968.08,"text":"detail. I''m just going to show you how to build this dashboard from scratch. You can download"},{"start":1968.08,"end":1972.72,"text":"the file from the description. The topics we are going to cover in this video will start off with"},{"start":1972.72,"end":1977.76,"text":"understanding interactive Excel dashboard, then we''ll plan for your Excel dashboard, then we''ll"},{"start":1977.76,"end":1983.84,"text":"collect and prepare your data, we''ll create a pivot table for data analysis, we''ll visualize the data"},{"start":1983.84,"end":1989.04,"text":"through charts and graphs, we''ll increase the interactivity with Excel features, and we''ll"},{"start":1989.04,"end":1994.64,"text":"finally assemble all the components into a dashboard. Interactive dashboards in Excel are a type of"},{"start":1994.64,"end":2000.4,"text":"dashboard that allows you to track and measure key performance indicators and metrics. They provide"},{"start":2000.4,"end":2006.08,"text":"visual representation of complex data making it easier to understand and analyze. With interactive"},{"start":2006.08,"end":2011.44,"text":"dashboards, you can change data inputs, filter data, drill down into specific details to gain"},{"start":2011.44,"end":2016.88,"text":"insight and make data driven decisions. Next, we need to plan your Excel dashboard. Before creating"},{"start":2016.88,"end":2021.2,"text":"an Excel dashboard, it''s essential to understand the needs and expectation of your target audience"},{"start":2021.2,"end":2026.16,"text":"consider who will be using the dashboard and what information they need to make informed decisions."},{"start":2026.16,"end":2030.88,"text":"Clearly, defend the objectives of your dashboard and ensure they align with your organization''s goal."},{"start":2030.88,"end":2036.48,"text":"For this tutorial, we treat a revenue dashboard with a small e-commerce business focusing on key"},{"start":2036.48,"end":2041.36,"text":"metrics like revenue order, customer acquisition. The target audience with this dashboard will be"},{"start":2041.44,"end":2046.24,"text":"sales and marketing team who will use the insight to optimize the product performance,"},{"start":2046.24,"end":2051.92,"text":"customer acquisition strategy, and overall business growth. In this tutorial, you will use a zip"},{"start":2051.92,"end":2058.96,"text":"file that contains data related to yearly sales data, customer, item type, location, order priority,"},{"start":2058.96,"end":2064.96,"text":"and sales channel. You will see all this data in a zip folder. Now let us clean and organize the data."},{"start":2065.04,"end":2068.08,"text":"So open a blank Excel workbook, go to data,"},{"start":2071.36,"end":2078.32,"text":"click on get data, click on from file, click on Excel workbook, click on the zip folder where"},{"start":2078.32,"end":2089.2,"text":"you''ve extracted the data, and then select 2014 sales data. Let''s select the 2014 sales data,"},{"start":2090,"end":2094.48,"text":"click on import, and you will see a dialog box, click on sheet one, click on transform data,"},{"start":2095.04,"end":2097.76,"text":"and now your power query dialog box will open up."},{"start":2100.88,"end":2107.28,"text":"Our power query editor will open up. Now we''ll just rename this to 2014 sales data."},{"start":2108,"end":2112.8,"text":"So right mouse click, click on rename, and we''ll rename this to 2014 sales data."},{"start":2115.44,"end":2122.4,"text":"Click on close in load two, and then select only create connection. Now we''ll repeat the"},{"start":2122.4,"end":2130.16,"text":"same process for each Excel file. So go to get data from file, from Excel workbook, click on 2015"},{"start":2130.16,"end":2138.56,"text":"sales data, click on import. Now the dialog box will show up, click on sheet one, click on transform"},{"start":2138.56,"end":2146.08,"text":"data. This will load the data into power query editor, and now we''re ringing this as 2015 sales data."},{"start":2146.32,"end":2156.08,"text":"Again, select close in load two, only create connection, click okay. Now go to get data from"},{"start":2156.08,"end":2163.12,"text":"file from Excel workbook. Now 2016 import, click on sheet one, transform data. Now the data will"},{"start":2163.12,"end":2172,"text":"load into power query editor. Rename this one, 2016 sales data, select close in load two,"},{"start":2172.72,"end":2183.84,"text":"select only create connection, from file from Excel workbook, 2017 sales data, import,"},{"start":2183.84,"end":2188.24,"text":"click on sheet one, transform data, rename this to 2017 sales data,"},{"start":2195.12,"end":2196.32,"text":"select close in load two,"},{"start":2196.48,"end":2206.48,"text":"only create connection, click okay. Click on get data from file from Excel workbook,"},{"start":2207.76,"end":2216.72,"text":"2018 sales data, click on import, click on sheet one, transform data, rename this to"},{"start":2217.44,"end":2224.08,"text":"2018 sales data, select close in load two,"},{"start":2226.96,"end":2232.16,"text":"only create connection, click okay. Click on get data from file from Excel workbook,"},{"start":2234.08,"end":2243.6,"text":"from 2019 sales data, click import, click on sheet one, transform data, rename this 2019 sales data,"},{"start":2246.88,"end":2256.08,"text":"select close in load two, click only create connection,"},{"start":2260.32,"end":2268.16,"text":"get data from Excel workbook, click on 2020 sales data, import, click on sheet one,"},{"start":2268.72,"end":2275.52,"text":"select transform data, rename this to 2020 sales data,"},{"start":2279.6,"end":2280.96,"text":"click on close in load two,"},{"start":2285.6,"end":2290.56,"text":"click on only create connection, again get data from file Excel workbook,"},{"start":2290.64,"end":2302.4,"text":"click on 2021 sales data, import, click on sheet one, transform data, rename this,"},{"start":2303.44,"end":2310.4,"text":"make it 2021 sales data, click on close in load two,"},{"start":2312.08,"end":2317.12,"text":"now all your sales data are loaded for each and every year, now we''ll do the same thing for"},{"start":2317.12,"end":2322.72,"text":"other Excel files, so go to get data from file from Excel workbook, click on customer,"},{"start":2323.68,"end":2329.68,"text":"click on sheet one, click on transform data, and we''ll call this as dim customer,"},{"start":2332.32,"end":2338.4,"text":"dim is dimension, I''ll explain the concept of dim in fact, once we import all the data into the"},{"start":2338.4,"end":2344.08,"text":"power query, so now let us go back to data, click on get data from file from Excel workbook,"},{"start":2344.08,"end":2352,"text":"let us import item type, click import, click on sheet one, transform data, rename this to dim"},{"start":2352,"end":2358.8,"text":"item type, select close in load two, select only create connection, click okay,"},{"start":2361.04,"end":2369.2,"text":"click on get data from file from Excel workbook, click on location, import, click on sheet one,"},{"start":2369.2,"end":2375.2,"text":"click on transform data, rename this to dim location, click on close in load two,"},{"start":2376.48,"end":2378.4,"text":"select only create connection, click okay,"},{"start":2381.12,"end":2388.4,"text":"go to get data from Excel workbook, select order priority, click import, click on sheet one,"},{"start":2388.4,"end":2393.28,"text":"click on transform data, rename this to dim order priority,"},{"start":2394.24,"end":2408.64,"text":"select close in load two, click on only create connection, click on get data from file excel"},{"start":2408.64,"end":2424.4,"text":"workbook, and select sales channel, import, rename this to dim, or click on sheet one,"},{"start":2424.4,"end":2435.36,"text":"click on transform data, rename this to dim,"},{"start":2437.44,"end":2445.28,"text":"sales channel, click on close in load two, select only create connection, click okay,"},{"start":2446.24,"end":2452.72,"text":"now let us append all this data into a single power query, we''ll combine the data from 2014"},{"start":2452.72,"end":2460.48,"text":"all the way to 2021, go to get data, go to launch power query editor, so click on 2014 sales data"},{"start":2460.48,"end":2469.52,"text":"query, click on append query, click on append query is new, and now we''ll select all the queries,"},{"start":2469.52,"end":2477.28,"text":"so go to three or more tables, and we''ll select 2015 through 2021, click on add, click okay,"},{"start":2478,"end":2482.24,"text":"now this is appended all the data from all these queries into a single query,"},{"start":2482.24,"end":2488.8,"text":"so we''ll rename this, call it fact sales transaction, now we want to filter out certain"},{"start":2488.8,"end":2496.48,"text":"columns, so we''ll go to choose columns, click on choose columns, let us remove all the duplicates,"},{"start":2496.48,"end":2501.44,"text":"so just select all the data by pressing control A, right mouse click, and click on remove duplicates,"},{"start":2501.52,"end":2508.32,"text":"now we can load all this data into a data model, so right mouse click on dim customer,"},{"start":2508.88,"end":2515.2,"text":"click on load two, and then select add this to the data model, click okay, and now the data is loaded,"},{"start":2515.2,"end":2521.76,"text":"do the same thing for item type, load two, add this to the data model, click okay, same thing over"},{"start":2521.76,"end":2530,"text":"here, same thing for order priority as well, click on load two, add this to the data model, click okay,"},{"start":2531.68,"end":2540.72,"text":"same thing over here, and also you want to load this the fact sales transaction into the data"},{"start":2540.72,"end":2547.92,"text":"model, so click on load two, add this to the data model, now we''ll create a pivot table for data"},{"start":2547.92,"end":2554,"text":"analysis, pivot tables are a powerful tool for data analysis in Excel that allows you to summarize"},{"start":2554,"end":2558.32,"text":"reports and analyze large amounts of data, this enables you to organize, manipulate,"},{"start":2558.32,"end":2564.4,"text":"visualize your data in a pivot table format, so now first we''ll build the data model and write"},{"start":2564.4,"end":2569.84,"text":"DAX and then we''ll build a pivot table, so let us go back to Excel, first you want to make sure that"},{"start":2569.84,"end":2578.56,"text":"your power pivot tab is enabled, so you can do that by simply clicking on file, options, click on add-ins,"},{"start":2579.92,"end":2585.36,"text":"and then select com add-ins, from the drop down click on go, and you will see the power pivot"},{"start":2585.36,"end":2589.76,"text":"option, if it''s enabled or disabled, so you can just enable it and click okay, and then you should"},{"start":2589.76,"end":2595.28,"text":"see it on the ribbon on the top, so now we''ll first create relationships between these tables,"},{"start":2595.28,"end":2599.6,"text":"so you can go to the diagram view, and over here you will see all the tables that we loaded from"},{"start":2599.6,"end":2606,"text":"power query to the data model, so we''ll keep the fact table in the middle and all the other tables"},{"start":2606,"end":2616.64,"text":"right next to each other, or surrounding the fact table, so now we''ll build relationships between"},{"start":2616.64,"end":2622.24,"text":"the fact table and the dimension table, whereas in fact table it stores the measurement, matrix,"},{"start":2622.24,"end":2628.08,"text":"or facts related to the business operation, so for example over here we see the details related to"},{"start":2628.08,"end":2633.68,"text":"sales transactions such as units sold, unit price, unit cost, total revenue, total cost, total profit,"},{"start":2633.68,"end":2638.08,"text":"star schema, which is what we call this a star schema where the fact table is in the middle,"},{"start":2638.08,"end":2643.28,"text":"and all the dimensions are surrounding the fact table, and the dimension table contains the description"},{"start":2643.28,"end":2648.4,"text":"of the objects that are that in the fact table, it provides information about dimensions such as"},{"start":2648.4,"end":2654.96,"text":"value, characteristics, keys, for example, if we connect the customer ID from the fact table to"},{"start":2654.96,"end":2660.24,"text":"the dimension table, now it has created a relationship when I drag this, so if I want to pull any"},{"start":2660.24,"end":2665.28,"text":"information about a particular customer, I can look at their ID on the fact table, and then I can"},{"start":2665.28,"end":2670.88,"text":"find out their email address, their job title, and their first name and last name, so this ID,"},{"start":2670.88,"end":2676.56,"text":"customer ID is the bridge between the fact table and the dimension table, so for example if I want"},{"start":2676.56,"end":2683.28,"text":"to find out like how many people with this job title purchased a particular product, so this is"},{"start":2683.28,"end":2689.44,"text":"where the customer ID will help to identify, help to connect, I can simply do a count of customer"},{"start":2689.44,"end":2695.28,"text":"ID and in the pivot table, which will give me the breakdown of count by each job title,"},{"start":2695.28,"end":2700.88,"text":"and this is where customer ID will bridge the connection, the customer ID is the primary key"},{"start":2700.88,"end":2706.4,"text":"which is unique to each record, so you will not find the same customer ID twice in the"},{"start":2706.4,"end":2711.52,"text":"dim customer table, each row will be unique, now let us create the relationship between all these"},{"start":2711.52,"end":2716.72,"text":"tables, so I''ll drag the item type, with the item type ID in the dimensions type table,"},{"start":2716.72,"end":2722,"text":"do the same for location ID, I''ll do the same for order priority, and do the same for sales channel"},{"start":2722,"end":2728.56,"text":"ID, now this is what we call the star schema because it looks in a shape of a star, where the"},{"start":2728.56,"end":2732.88,"text":"fact table is in the middle and the dimension tables are surrounding it, so the fact table in"},{"start":2732.88,"end":2738.16,"text":"the middle helps us to measure different KPIs and help us visualize different charts, and the"},{"start":2738.16,"end":2743.04,"text":"dimension table helps us to look at the data from different angles, so for example if I want to look"},{"start":2743.04,"end":2747.28,"text":"at what are the different order priorities, so I want a count of different order priorities,"},{"start":2747.28,"end":2752.8,"text":"so I can use the order priority column in the dim order priority table, and then I can get a count"},{"start":2752.8,"end":2757.6,"text":"of the transaction ID, so this will break down the total number of order priorities by different"},{"start":2757.6,"end":2762.8,"text":"account of total order priorities by different order priority category, and the same thing with"},{"start":2762.8,"end":2767.68,"text":"region, so if I want to find out what is the total revenue across different countries, I can use the"},{"start":2767.68,"end":2773.04,"text":"location ID to find out exactly how to get some of the total revenue across different countries,"},{"start":2773.6,"end":2779.2,"text":"as we move on to the next section of writing DAX and doing pivot table, you will understand the"},{"start":2779.2,"end":2784.24,"text":"concept of how these tables are linked together, and how it helps in terms of generating a pivot table,"},{"start":2784.8,"end":2791.84,"text":"go to the data view, and go to fact sales transaction, and over here we want to get the total revenue,"},{"start":2791.84,"end":2797.12,"text":"so we''ll write the DAX code, this is the place where you can write the DAX code, so click anywhere"},{"start":2797.12,"end":2804.08,"text":"in any of the cell, and over here we''ll type in revenue, colon, and we''ll type in a sum,"},{"start":2805.44,"end":2810.88,"text":"and type in total revenue, you need a equal to after the colon, click on the tick mark,"},{"start":2811.6,"end":2818.16,"text":"and as you see the calculation has generated a total revenue, so we can format this, we can add"},{"start":2818.16,"end":2825.52,"text":"the dollar sign, and we can remove the decimal, so this was one of the KPIs, now we''ll write the"},{"start":2825.52,"end":2832.64,"text":"code for the next KPA which is number of orders, so we''ll write over here, I''ll call this as number"},{"start":2833.2,"end":2844.32,"text":"of orders colon equal to, and the formula for this is count transaction ID,"},{"start":2847.44,"end":2852.48,"text":"so DAX will automatically create intelligence which will give you a suggestion of all the"},{"start":2852.48,"end":2860.16,"text":"fees that you can choose from, click on the tick mark, and if you expand this you will see the value,"},{"start":2861.44,"end":2866.96,"text":"I''ll just provide thousand separator and remove the decimal, and now I''ll add the third formula which"},{"start":2866.96,"end":2874.64,"text":"is average revenue per order, so I''ll type in average revenue per order, and the formula for"},{"start":2874.64,"end":2884.32,"text":"that is going to be divide revenue, so it''s this DAX formula divided by this, so that''s how we''ll get"},{"start":2884.32,"end":2891.84,"text":"the average order, average revenue per order, so revenue, and then we''ll get the number of orders,"},{"start":2891.84,"end":2898.08,"text":"close the bracket, click on the tick mark, and as you see the value is generated, now let us assign"},{"start":2898.08,"end":2903.84,"text":"a dollar sign, remove the decimal, now we''ll generate the pivot table directly from the data model,"},{"start":2903.92,"end":2909.12,"text":"from the power pivot editor, the good thing about writing the DAX code is you don''t need to format"},{"start":2909.12,"end":2913.6,"text":"every time in the pivot table, in the values section, and the good thing is you can use this"},{"start":2913.6,"end":2918.72,"text":"measure anywhere in the pivot table, once we have created the relationship in the diagram view,"},{"start":2918.72,"end":2923.92,"text":"you can use this measure across different tables, now let us go through the steps of creating the"},{"start":2923.92,"end":2931.76,"text":"pivot table, so go to pivot table and then select pivot table, and this will give you the option"},{"start":2931.76,"end":2937.04,"text":"to select new or existing worksheet, I''ll select existing worksheet, and the range for this is"},{"start":2937.04,"end":2945.28,"text":"going to be cell A1, click on okay, click okay, and now we will create three different KPIs or"},{"start":2945.28,"end":2952.08,"text":"pivot table for all the KPIs, so if you open fact sales transaction, just drag all the KPIs into"},{"start":2952.08,"end":2958.56,"text":"the values, now for our e-commerce sales dashboard, let us create pivot table summarizing revenue by"},{"start":2958.56,"end":2963.04,"text":"sales channel, so again go back to the data model or click on manage,"},{"start":2965.84,"end":2971.52,"text":"click on pivot table, again pivot table, click on existing worksheet, go to cell E1, click okay,"},{"start":2972.64,"end":2978.48,"text":"click okay, and you will see the dim sales channel,"},{"start":2981.04,"end":2986.16,"text":"so put this in the rows, and then you can add the revenue in the values, so as you see these"},{"start":2986.16,"end":2990.64,"text":"are two different tables, we are getting sales channel from the dim sales channel table, and"},{"start":2990.64,"end":2995.28,"text":"we are getting the revenue which is stored in the fact sales transaction table, and as you see it"},{"start":2995.28,"end":3000.64,"text":"has created the pivot table, the reason is because we have created the relationship, we go to manage,"},{"start":3000.64,"end":3004.96,"text":"and as you see there is a relationship between the sales channel ID in the dimension table"},{"start":3004.96,"end":3010.16,"text":"and the sales channel ID in the fact table which is here, and that''s what I was talking to you about,"},{"start":3010.16,"end":3014.56,"text":"once you create the relationship, you can use, you can mix and match data from different tables"},{"start":3014.56,"end":3019.76,"text":"in a single pivot table, and as you will see you will use this revenue measure across other"},{"start":3019.76,"end":3025.52,"text":"pivot tables as well, so you can reuse this measure again and again, so now click on pivot table again,"},{"start":3025.52,"end":3031.04,"text":"now I''ll create a third pivot table which is the revenue by item type, so click on existing worksheet,"},{"start":3031.04,"end":3040.64,"text":"put this in cell A4, click okay, click okay, and click on dim item type in the rows and revenue"},{"start":3040.64,"end":3046.08,"text":"in the values, again as you see we are using two different fields from two different tables,"},{"start":3046.08,"end":3050,"text":"that''s because of the relationship that we''ve created, and also the measure has been reused"},{"start":3050,"end":3054.24,"text":"in this table, in this pivot table, and also in this pivot table, so that''s the beauty about"},{"start":3054.24,"end":3058.56,"text":"power pivot where you can create relationships, where you can write that, where you can reuse"},{"start":3058.56,"end":3066.08,"text":"these measures again and again, so let us go back to manage, again go to pivot table, pivot table,"},{"start":3066.64,"end":3078,"text":"click on existing worksheet, go to cell H1, click on okay, click okay, and now we need the revenue"},{"start":3078,"end":3084.48,"text":"by order priority, so click on order priority, track order priority in rows and we''ll get the revenue"},{"start":3087.52,"end":3093.44,"text":"in the values field, so now let us change the labels, so over here we''ll make this as sales"},{"start":3093.44,"end":3102.64,"text":"channel, we''ll remove the grand total, so go to design, and off for rows and columns, again we''ll"},{"start":3102.64,"end":3112.24,"text":"make this as order priority, and remove the grand total, again we''ll do the same for item type,"},{"start":3114.56,"end":3121.2,"text":"and remove the grand total, design, off for rows and columns, next is we want to visualize the"},{"start":3121.2,"end":3126.56,"text":"data using charts and graphs, visualization is the key important component for creating an interactive"},{"start":3126.56,"end":3131.44,"text":"Excel dashboard, charts and graph provide a visual representation of the data making it easier to"},{"start":3131.44,"end":3135.68,"text":"understand and to analyze trends, patterns, and relationship, selecting the appropriate chart"},{"start":3135.68,"end":3140,"text":"type is crucial for effective communication, communicating your data insight, different"},{"start":3140,"end":3144.88,"text":"chart types are suited for different purpose and data structures, some common chart types,"},{"start":3144.88,"end":3150.48,"text":"and their uses include a column and a bar chart which compares values across categories or show"},{"start":3150.48,"end":3155.92,"text":"trends over time, line chart displays continuous data or show changes over time, pie chart shows"},{"start":3155.92,"end":3160.72,"text":"the composition of proportion of the whole, the scatter plot chart visualizes relationship between"},{"start":3160.72,"end":3165.92,"text":"two variables, and the area chart demonstrates the magnitude of change over time or across"},{"start":3165.92,"end":3172.08,"text":"categories, for our e-commerce sales dashboard we''ll create a pie chart showing revenue by sales,"},{"start":3172.08,"end":3177.92,"text":"this will help us to identify, click on the channel, which is sales channel, click on insert,"},{"start":3178.08,"end":3188.48,"text":"click on pivot chart, and click on pie, click okay, and this will generate your pie chart,"},{"start":3188.48,"end":3194.32,"text":"now let us create another chart for our sales dashboard, now we want to create a column chart"},{"start":3194.32,"end":3199.12,"text":"to show the revenue by order priority, this will help us to identify which order priority is"},{"start":3199.12,"end":3205.2,"text":"performing better, so click on the order priority, click on insert, click on pivot charts, and then"},{"start":3205.2,"end":3210.08,"text":"select the cluster column, click okay, and your cluster column chart is ready, and next chart we"},{"start":3210.08,"end":3214.56,"text":"need is the bar chart showing the revenue of item type, this will help us to identify which"},{"start":3214.56,"end":3220.64,"text":"item type is performing better, so click on the pivot table, click on insert, click on pivot chart,"},{"start":3220.64,"end":3227.92,"text":"click on pivot chart again, click on bar, click on okay, now we want to customize the chart elements"},{"start":3227.92,"end":3233.92,"text":"for maximum impact, first we''ll add the descriptive title and access label, next we''ll adjust the chart"},{"start":3233.92,"end":3239.12,"text":"colors and style, then we''ll add data labels, then we''ll customize the chart layout in the background,"},{"start":3239.92,"end":3243.76,"text":"so click on the pivot table, first we will hide all the field buttons,"},{"start":3245.68,"end":3249.28,"text":"and then we''ll click on the plus sign, we''ll make sure all these are unable,"},{"start":3250.72,"end":3258.8,"text":"we''ll rename the chart title to sales channel distribution,"},{"start":3259.2,"end":3265.52,"text":"and instead of the revenue, we want this to be a percentage, we''ll click on the label options and"},{"start":3265.52,"end":3269.44,"text":"instead of value we''ll select the percentage, same thing for this one, instead of value we''ll"},{"start":3269.44,"end":3274.32,"text":"select this as percentage, and in the number we''ll select this as percentage, and there will be 2"},{"start":3274.32,"end":3284.64,"text":"decimal, and now we''ll also change the color, so for online we''ll select this as yellow,"},{"start":3285.6,"end":3293.92,"text":"so click on the legend, click on home, and then click on more colors,"},{"start":3294.96,"end":3304.08,"text":"click on custom colors, and the hex code we want to apply is f0a500, click okay,"},{"start":3304.96,"end":3310.8,"text":"and now this will change it to yellow, and we want this one as black, so we''ll change this to"},{"start":3311.52,"end":3321.44,"text":"more colors, click on custom, and this will be called 1991919, click okay,"},{"start":3324.4,"end":3330.08,"text":"and we''ll also change the color of the text of this one to white, and your pie chart is ready,"},{"start":3330.08,"end":3333.52,"text":"and now let us customize the column chart, so click on the column chart,"},{"start":3334,"end":3343.04,"text":"click on the plus sign, and we''ll add the access title, we''ll remove the legends,"},{"start":3344.08,"end":3355.12,"text":"we''ll hide all the field buttons, and we''ll change the name of the chart title, we''ll call this as"},{"start":3355.12,"end":3368.24,"text":"revenue by order priority, this will be called order priority, and this will be called revenue,"},{"start":3370.56,"end":3376.08,"text":"and we''ll change the color of the bar to black, so select the column,"},{"start":3376.88,"end":3380.96,"text":"click on the color that you selected before,"},{"start":3383.92,"end":3390.48,"text":"and now we''ll make changes to the bar chart, so we''ll remove all the field buttons, click on the"},{"start":3390.48,"end":3398.16,"text":"plus sign, we''ll add the access title, we''ll remove the legend, and we''ll rename this to"},{"start":3398.96,"end":3409.12,"text":"revenue by item type, and this will be called item type,"},{"start":3412.8,"end":3419.68,"text":"and this will be revenue, we''ll also add change the color, so click on the bars,"},{"start":3420.64,"end":3428.32,"text":"click on home, and we''ll select the yellow color, we''ll also add the data labels,"},{"start":3428.32,"end":3434.48,"text":"so click on plus sign, add data labels, and we''ll do the same for the column chart, add data labels,"},{"start":3436.16,"end":3441.68,"text":"so we need to create three KPIs, one for revenue, total orders, and average dollar per order,"},{"start":3442.48,"end":3447.52,"text":"so we''ll use the pivot table to build the KPIs, so we already have the KPI values,"},{"start":3447.52,"end":3450.48,"text":"now we just need to insert a rectangle, so go to insert,"},{"start":3453.44,"end":3462.8,"text":"click on illustration, click on shapes, and then select the shape, we''ll add the shape here,"},{"start":3466.32,"end":3470.96,"text":"so we''ll copy this three times, or two times, we need three shapes in total,"},{"start":3471.68,"end":3479.2,"text":"so we''ll change the color for each, so one will be gray, so go to shape format,"},{"start":3479.84,"end":3485.28,"text":"go to shape fill, go to more fill colors, go to custom,"},{"start":3487.28,"end":3494.48,"text":"now the hex code we want is BF, BF, BF, click okay,"},{"start":3495.44,"end":3502.72,"text":"this will turn into a gray color, now we want this one to be the black,"},{"start":3504.48,"end":3509.92,"text":"so this should be in your recent colors, and we want this one to be yellow,"},{"start":3509.92,"end":3516.88,"text":"this should also be in your recent colors, the yellow one, so now we''ll insert the value,"},{"start":3517.52,"end":3521.84,"text":"so click on the formula bar, so the first value we want is the revenue,"},{"start":3521.84,"end":3526.72,"text":"so we''ll provide the cell reference in the formula bar, which is A2, press enter,"},{"start":3528.64,"end":3530.24,"text":"so you want to make this center aligned,"},{"start":3533.2,"end":3540.88,"text":"make this bold, we''ll do the same for this one, click on the formula bar equal to,"},{"start":3542.4,"end":3549.52,"text":"and we want this to be the number of orders, which is going to be cell B2, press enter,"},{"start":3552.8,"end":3556.48,"text":"the text for this one should be white color, so change the text color,"},{"start":3563.2,"end":3567.76,"text":"make this center aligned, do the same for this one,"},{"start":3569.6,"end":3576.08,"text":"click on the formula bar equal to, and click on average revenue per order, enter,"},{"start":3576.16,"end":3586,"text":"make this center aligned, make this bold, you should make this one also as bold,"},{"start":3589.04,"end":3594.64,"text":"and now we need to insert the box, which will be the name of the KPI, so go to insert,"},{"start":3594.64,"end":3599.6,"text":"so we''ll insert a text box, click on text, and then click on box,"},{"start":3600.16,"end":3605.92,"text":"call this as revenue,"},{"start":3608.72,"end":3611.68,"text":"make this bold, and center aligned,"},{"start":3614.48,"end":3616,"text":"so copy paste this twice,"},{"start":3616.56,"end":3628.32,"text":"this will be called total orders,"},{"start":3630.56,"end":3638.72,"text":"and this will be called average dollar per order, now we need to group these two,"},{"start":3646.08,"end":3649.36,"text":"do the same for this one as well, group these two shapes,"},{"start":3652.24,"end":3653.68,"text":"also we''ll do the same for this one,"},{"start":3656.24,"end":3659.52,"text":"the reason we are grouping is now because once you move this shape,"},{"start":3660.24,"end":3666.32,"text":"both the shapes will move together, so now your KPI is ready, in this section we will explore"},{"start":3666.32,"end":3671.28,"text":"how to enhance interactivity in your Excel dashboards, using features such as slicers and"},{"start":3671.84,"end":3676.32,"text":"timeline, these features allow you to interact with the dashboard, filter data, explore different"},{"start":3676.32,"end":3682,"text":"aspects of the data, so slicers and timelines are powerful Excel features that allow you to"},{"start":3682,"end":3687.36,"text":"use it to interact with and filter pivot table data quickly and intuitively, they provide a way"},{"start":3687.36,"end":3692.88,"text":"to visual, way to select and deselect data points instantly updating the connected charts and table,"},{"start":3693.6,"end":3698.56,"text":"slicers are used to filter categorical data such as product category or customer segments,"},{"start":3698.56,"end":3704,"text":"while as the timeline helps us to filter the continuous data range allowing user to focus"},{"start":3704,"end":3710.96,"text":"on specific time periods, there are few benefits of using the slicer and timelines, first one it"},{"start":3710.96,"end":3716.56,"text":"improves the user experience, slicers and timelines provide an intuitive and visual way to the user"},{"start":3716.56,"end":3721.44,"text":"to interact with data making it easier to explore and analyze information, it also increases data"},{"start":3721.44,"end":3726.48,"text":"flexibility, users can quickly filter data to focus on specific subset by uncovering inside that"},{"start":3726.48,"end":3731.36,"text":"might be hidden in aggregate data, connected charts and tables automatically update when the"},{"start":3731.36,"end":3738.32,"text":"slices or timeline is selected providing real-time insights, also it enhances the visual appeal,"},{"start":3738.32,"end":3742.72,"text":"a well-designed slicer and timeline adds a professional polished look to your dashboard,"},{"start":3742.72,"end":3748.72,"text":"now let us create the step-by-step slicers and timelines, so go back to Excel and we''ll click"},{"start":3748.72,"end":3759.6,"text":"on the pivot table item type, click on insert, click on timeline, click on order date and now"},{"start":3759.6,"end":3767.04,"text":"this will give you a timeline slicer, so we''ll change the color from this to gray,"},{"start":3770.8,"end":3775.6,"text":"since we don''t have the gray option we''ll create a customs time, so we''ll right mouse click on this"},{"start":3775.68,"end":3782.08,"text":"and make this as duplicate, so now we can create our own template, so we''ll call this as gray"},{"start":3783.76,"end":3795.2,"text":"timeline, we''ll select selected time block, format this, select more colors custom, make this as"},{"start":3795.6,"end":3805.36,"text":"bf, bf, bf, click okay, click okay and we''ll select unselected time block,"},{"start":3807.44,"end":3812.88,"text":"we don''t need to change anything here, then we''ll select selected time block, we''ll change this to"},{"start":3812.96,"end":3820.4,"text":"more colors, we''ll make this as bf, bf, bf, click okay"},{"start":3824.64,"end":3830.96,"text":"and now we''ll select this slicer or this timeline, as you see it has changed the color to gray,"},{"start":3832.08,"end":3839.68,"text":"now we need to add another slicer for country, so we''ll just select this pivot table, go to design"},{"start":3839.76,"end":3846.08,"text":"or go to pivot table analyze, click on insert slicer and then we''ll select under dim location,"},{"start":3846.08,"end":3853.84,"text":"we''ll select the country, click okay and we''ll change the color this to gray, which is this one"},{"start":3855.52,"end":3862.4,"text":"and now we need to connect all the tables to these slicers and timeline, so we''ll click on slicer,"},{"start":3862.4,"end":3869.28,"text":"click on report connection and you want to select all the pivot tables, so if you filter"},{"start":3869.28,"end":3872.88,"text":"or if you select any of the country, it will filter the data for each and every"},{"start":3873.52,"end":3879.68,"text":"pivot table and also it will reflect on the chart as well, so click okay, we''ll do the same thing for"},{"start":3879.68,"end":3886.64,"text":"the timeline slicers, go to timeline, click on report connection, expand this and select all the pivot tables,"},{"start":3888.56,"end":3894.56,"text":"click all of them and then click okay, now if you select any particular year or month,"},{"start":3895.52,"end":3902,"text":"you''ll see the numbers will change and the chart will also reflect that change, now all the components"},{"start":3902,"end":3906.16,"text":"of the dashboard are ready, now we just need to assemble it, now that you have created the pivot"},{"start":3906.16,"end":3910.8,"text":"table, spirit charts and added interactivity with slicers and timelines, it''s time to assemble all"},{"start":3910.8,"end":3916.4,"text":"the components into a cohesive excel dashboard, an effective dashboard layer should be intuitive,"},{"start":3916.4,"end":3921.04,"text":"visually appealing and optimized for the user''s needs, when assembling your dashboard components"},{"start":3921.04,"end":3925.6,"text":"consider the following design principles, you want to prioritize the information hierarchy,"},{"start":3925.6,"end":3930.8,"text":"place the most important insight in the KPI, in the prominent location, use size, colors and position"},{"start":3930.8,"end":3936.56,"text":"to guide the user''s attention to key elements, next you want to maintain visual consistency using"},{"start":3936.56,"end":3942.48,"text":"a consistent color scheme, font family and sizing throughout the dashboard, align elements to create"},{"start":3942.48,"end":3946.64,"text":"a clean and organized look, you want to maximize the white space, you want to avoid overcrowding"},{"start":3946.64,"end":3951.12,"text":"your dashboard with too much information, for our e-commerce dashboard, we''ll arrange the component"},{"start":3951.12,"end":3957.2,"text":"as follows, we''ll copy paste all the chart slicers and KPIs into a new tab and organize all the visuals"},{"start":3957.2,"end":3964.32,"text":"as shown below and insert a text box with the text called revenue dashboard, so we''ll call this tab as"},{"start":3964.32,"end":3973.92,"text":"pivot and we''ll create another tab called dashboard and now we''ll copy paste all the charts, KPIs,"},{"start":3974.88,"end":3984.64,"text":"slicers, timeline slicer, copy and just paste it here and now we''ll reorganize this tab,"},{"start":3984.64,"end":3989.2,"text":"so first we''ll place all the KPIs on the top, so we place this over here"},{"start":4004.08,"end":4006,"text":"and we''ll place the third KPI over here,"},{"start":4008.88,"end":4012.96,"text":"we''ll put the country slicer over here,"},{"start":4016.16,"end":4029.2,"text":"we''ll expand this, we''ll put the pivot chart slicer here,"},{"start":4029.36,"end":4037.92,"text":"we''ll place the column chart over here right next to the pivot, right next to the PI chart"},{"start":4048.56,"end":4050.88,"text":"and we''ll place the timeline slicer on the bottom"},{"start":4051.52,"end":4064.96,"text":"and we''ll add the bar chart on the bottom, we''ll minimize this"},{"start":4068.88,"end":4070.56,"text":"then we can expand this"},{"start":4081.28,"end":4088.24,"text":"and now all the elements of the dashboard look organized, now we just need to add the text box,"},{"start":4088.24,"end":4095.36,"text":"so go to insert, click on text, click on text box, we''ll just add it on the top"},{"start":4097.28,"end":4103.28,"text":"and we''ll call this as revenue dashboard,"},{"start":4104,"end":4108.4,"text":"put it center aligned, we''ll make this as bold"},{"start":4112.8,"end":4118.64,"text":"and now we just need to change the reference for this from cell A2 to we need to reference this"},{"start":4118.64,"end":4125.2,"text":"back to the pivot table which is in pivot chart or in pivot tab, so we''ll call, we''ll reference this"},{"start":4125.2,"end":4129.44,"text":"in cell A2, press enter, same thing for this one"},{"start":4133.28,"end":4138.08,"text":"we''ll make sure this is bold"},{"start":4140.4,"end":4143.44,"text":"and again reference this from C2 to pivot"},{"start":4144.08,"end":4153.68,"text":"TAM C2, reference it to pivot C2, press enter and make this bold"},{"start":4158.24,"end":4163.2,"text":"and now if you filter you should see these values also change, previously it was"},{"start":4163.2,"end":4169.12,"text":"referencing to this sheet all the cells, that''s why when you click on any one of the countries"},{"start":4169.12,"end":4173.68,"text":"the data would not filter because we had the incorrect reference, now we''ll go to the view tab"},{"start":4173.68,"end":4179.68,"text":"and remove the grid lines, formula bars and herrings, now your dashboard is ready, now you"},{"start":4179.68,"end":4184.72,"text":"select any particular country or select for any particular years or months, so if I select"},{"start":4185.52,"end":4189.76,"text":"let''s say 2014 this will filter the data for that particular country and that particular year"},{"start":4190.48,"end":4195.6,"text":"or you can just select year or for which you will see the data for all the countries and all the years,"},{"start":4195.6,"end":4200.08,"text":"so there you have it, your tutorial on creating dynamic excel dashboard and before you go I have"},{"start":4200.08,"end":4204.16,"text":"a special offer for you, if you found this tutorial helpful and want to dive deeper into mastering"},{"start":4204.16,"end":4208.64,"text":"excel, check out my free excel course, the link is in the description below, don''t forget to like,"},{"start":4208.64,"end":4213.12,"text":"share and subscribe for more tips and tutorials and drop in the comments below if this video was"},{"start":4213.12,"end":4215.6,"text":"helpful to you, so I can create more videos like these"},{"start":4219.76,"end":4221.22,"text":"you"}]'::jsonb
) AS segment
WHERE l.youtube_video_id = 'VV8iRJ-DS0A';

