INSERT INTO transcript_chunks (lesson_id, chunk_text, start_time, end_time)
SELECT
    l.id AS lesson_id,
    segment.value->>'text' AS chunk_text,
    (segment.value->>'start')::numeric AS start_time,
    (segment.value->>'end')::numeric AS end_time
FROM lessons l
CROSS JOIN jsonb_array_elements(
    '[{"start":0,"end":5.4,"text":"Hi and welcome students. In this computer fundamentals video I''m going to be going over the keyboard and mouse."},{"start":5.4,"end":10.44,"text":"I''ll go over some tips and tricks for beginners as well as some shortcuts for more advanced users."},{"start":10.44,"end":11.52,"text":"Let''s get started."},{"start":11.52,"end":17.48,"text":"Alright, so over here at the top row of our keyboard we see some different keys starting with Escape."},{"start":17.48,"end":21.92,"text":"I don''t use Escape too often, but these function keys I do use regularly."},{"start":21.92,"end":26.36,"text":"F5 can be used on any web page to automatically refresh the page."},{"start":26.52,"end":31.48,"text":"F7 can be used within Microsoft Office to check spelling and grammar."},{"start":31.48,"end":36.36,"text":"Over here along the right side you''ll see a print screen button. This is how you would take a screenshot."},{"start":36.36,"end":39.8,"text":"You could actually press the Windows key which is down here in the bottom left,"},{"start":39.8,"end":43.8,"text":"plus the print screen key to take a screenshot within Windows 10."},{"start":43.8,"end":48.96,"text":"Alright, next up we''ll start with this area here which is our main keyboard area."},{"start":48.96,"end":55.76,"text":"When you''re computing you want to keep your left hand, especially when you''re typing, on A, S, D and F."},{"start":55.96,"end":61.96,"text":"You want to keep your right hand while typing on J, K, L and the semicolon button."},{"start":61.96,"end":66.72,"text":"This is what''s called the home row. That''s where you keep your fingers when you type."},{"start":66.72,"end":71.6,"text":"Along the top area of this rectangle here you''re going to see the number keys."},{"start":71.6,"end":73.56,"text":"I don''t ever use these number keys."},{"start":73.56,"end":78.92,"text":"If you''re going to type something and you have the number keys available over here on the right side,"},{"start":78.92,"end":83.96,"text":"you''re going to want to use those number keys as opposed to these ones over here because it''ll be faster."},{"start":84.16,"end":90.16,"text":"I hardly ever use these number keys, but if you hold down SHIFT while you press any of these number keys,"},{"start":90.16,"end":92.36,"text":"it''ll actually choose the icon above it."},{"start":92.36,"end":95.16,"text":"Above the one we see an exclamation point."},{"start":95.16,"end":99.56,"text":"If you hold down SHIFT and press 1, and notice there''s SHIFT on both sides of the keyboard,"},{"start":99.56,"end":104.36,"text":"so you could use your left or your right hand, you could get any of these number keys,"},{"start":104.36,"end":108.56,"text":"special characters, up at the top of the number keys."},{"start":108.96,"end":114.16,"text":"The Backspace button is to delete a character to the left."},{"start":114.16,"end":121.96,"text":"That''s very important because the character to the left of wherever you''re at on your Word document or any document."},{"start":121.96,"end":124.76,"text":"If you want to delete the character to the left, use Backspace."},{"start":124.76,"end":127.96,"text":"I''ll go over deleting the character to the right in just a minute."},{"start":127.96,"end":130.76,"text":"Tab can be used for a variety of shortcuts."},{"start":130.76,"end":136.56,"text":"For instance, ALT and Tab will switch you Windows between your Windows operating system."},{"start":136.76,"end":143.96,"text":"It''s also used in Microsoft Office for moving you across your page just a little bit, so it''s mostly used for indentation."},{"start":143.96,"end":149.96,"text":"You then see all of your character keys up here along the rest of this row, as well as backslash."},{"start":149.96,"end":151.36,"text":"Then you see Caps Lock."},{"start":151.36,"end":157.56,"text":"Anytime you press Caps Lock, it''s going to automatically capitalize all the words in your text."},{"start":157.56,"end":165.56,"text":"So just make sure that if you use Caps Lock, most of the time it''ll turn on this Caps Lock light indicator right over here."},{"start":165.56,"end":168.16,"text":"That will turn that on."},{"start":168.16,"end":173.36,"text":"So you have to make sure that if you use Caps Lock and you turn it on, you turn it back off when you''re done."},{"start":173.36,"end":176.56,"text":"As I said, the next row is your home row followed by the Enter key."},{"start":176.56,"end":179.56,"text":"Most of the time you can press the Enter key to finalize a selection."},{"start":179.56,"end":183.56,"text":"So don''t forget to use the Enter key rather than clicking things like OK."},{"start":183.56,"end":189.56,"text":"Again, one of the goals when we''re computing is to keep our hands on the keyboard rather than the mouse."},{"start":189.56,"end":194.56,"text":"Because as you keep your hands on the keyboard and you learn those shortcuts, it''s actually going to save you a lot of time."},{"start":195.56,"end":200.56,"text":"Because you won''t be constantly moving your hand back and forth between your mouse and your keyboard."},{"start":200.56,"end":202.56,"text":"Next up you have the Shift key."},{"start":202.56,"end":210.56,"text":"The Shift key can be used to capitalize letters and it''s also used in a variety of different shortcuts."},{"start":210.56,"end":215.56,"text":"So down here along the bottom row you''ll see Control."},{"start":215.56,"end":222.56,"text":"Control key is the main shortcut key in a Windows computer and it''s used for a variety of different things."},{"start":222.56,"end":226.56,"text":"For instance, Control E in Word is to Center."},{"start":226.56,"end":228.56,"text":"Control R is to write a line."},{"start":228.56,"end":230.56,"text":"Control U is to underline."},{"start":230.56,"end":232.56,"text":"Control I is to italicize."},{"start":232.56,"end":234.56,"text":"Control P is to print."},{"start":234.56,"end":236.56,"text":"Control A is to select all."},{"start":236.56,"end":238.56,"text":"Control S is to save."},{"start":238.56,"end":242.56,"text":"Control F is to find."},{"start":242.56,"end":245.56,"text":"Control Z is to undo."},{"start":245.56,"end":247.56,"text":"Control X is to cut."},{"start":247.56,"end":249.56,"text":"Control C is to copy."},{"start":249.56,"end":251.56,"text":"Control V is to paste."},{"start":251.56,"end":253.56,"text":"Control B is to bold."},{"start":253.56,"end":256.56,"text":"Control N is to create a new document."},{"start":256.56,"end":263.56,"text":"And so as you can see the Control key handles a lot of different shortcuts within Windows."},{"start":263.56,"end":271.56,"text":"I was naming mostly Microsoft Office shortcuts there, but you can use them throughout the Windows 10 operating system."},{"start":271.56,"end":273.56,"text":"Next up you''ll see the Windows key."},{"start":273.56,"end":277.56,"text":"Windows key is super useful for opening up your start menu and searching for things."},{"start":277.56,"end":283.56,"text":"So if you ever want to search for a file in Windows 10, you just hit the Windows key and start typing the name of the file."},{"start":283.56,"end":290.56,"text":"And that will allow you to search for different programs, okay, programs or files or folders."},{"start":290.56,"end":295.56,"text":"The Alt key, again, Alt and Tab used together, switch to your Windows."},{"start":295.56,"end":298.56,"text":"Spacebar, we know what that does. That creates a space in your documents."},{"start":298.56,"end":305.56,"text":"You''ll see another Alt key on the right side, another Windows key on the right side, and another Control key on the right side."},{"start":305.56,"end":308.56,"text":"I mostly use the left side for these keys though."},{"start":308.56,"end":314.56,"text":"Over here these are six keys above our arrow keys, and these six keys do a variety of different things."},{"start":314.56,"end":317.56,"text":"For instance, Home will usually take you to the beginning of a line."},{"start":317.56,"end":321.56,"text":"Control plus Home will take you to the beginning of a document."},{"start":321.56,"end":329.56,"text":"Page Up will scroll your page up, okay, automatically, so you don''t need to use the scroll wheel on your keyboard, or sorry, on your mouse."},{"start":329.56,"end":334.56,"text":"Over here, Delete will usually delete things to the right."},{"start":334.56,"end":341.56,"text":"So as Backspace deletes things to the left, Delete will delete items to the right in most cases, okay."},{"start":341.56,"end":345.56,"text":"End, if you press End, it will take you to the end of a line."},{"start":345.56,"end":349.56,"text":"If you hold Control and press End, it will take you to the end of a document."},{"start":349.56,"end":356.56,"text":"Over here is Page Down, that''s how you scroll down, and you''ll see the arrow keys that will move you around while you''re using the Windows operating system."},{"start":356.56,"end":359.56,"text":"On the right side over here, you''ll see Number Lock."},{"start":359.56,"end":365.56,"text":"Sometimes people turn this on, and then if you turn on Number Lock, it will allow you to use the numbers."},{"start":365.56,"end":369.56,"text":"If it''s off, it won''t allow you to use these numbers over here."},{"start":369.56,"end":373.56,"text":"Not sure why it''s even an option, but there it is."},{"start":373.56,"end":377.56,"text":"Then you see Divide, that''s also your slash right there."},{"start":377.56,"end":385.56,"text":"You have Divide, Multiply, which is the asterisk, Minus, which is a dash, and Plus, which is your addition right there."},{"start":385.56,"end":387.56,"text":"Then you see Enter to finalize."},{"start":387.56,"end":390.56,"text":"Basically, you need everything over here for calculations and computing."},{"start":390.56,"end":398.56,"text":"Whenever my students are entering in numbers in something like Excel, I always recommend that they use this area over here,"},{"start":398.56,"end":403.56,"text":"which is your number pad as opposed to these numbers over here, which take a lot longer to type out."},{"start":403.56,"end":412.56,"text":"Finally, you have Zero, and then you also have the Dot, so that''s going to be your decimal."},{"start":412.56,"end":416.56,"text":"Finally, you have Enter, which finalizes your selection."},{"start":416.56,"end":419.56,"text":"That is your keyboard right there."},{"start":419.56,"end":428.56,"text":"I know I went over a lot right there, so feel free to re-watch the video or go back to where I was talking about the certain section of the keyboard to go over that."},{"start":428.56,"end":430.56,"text":"Finally, the mouse."},{"start":430.56,"end":434.56,"text":"The mouse has a lot less functionality than the keyboard."},{"start":434.56,"end":438.56,"text":"That''s why I recommend using keyboard shortcuts as opposed to using your mouse."},{"start":439.56,"end":443.56,"text":"There''s a couple things that are common with the mouse, and that''s this area here."},{"start":443.56,"end":446.56,"text":"This is clicking. Clicking is always on the left side."},{"start":446.56,"end":453.56,"text":"If I ever refer to in any of my tutorials to click on something, that''s just one single click and release."},{"start":453.56,"end":460.56,"text":"Another option is to click and drag, and so that''s when you click on something and you hold the left side down."},{"start":460.56,"end":463.56,"text":"That''s going to be your click and drag."},{"start":463.56,"end":467.56,"text":"Finally, on the left side here, you also have the option for double clicking."},{"start":467.56,"end":471.56,"text":"That''s two repeated clicks really fast, the one-two."},{"start":471.56,"end":474.56,"text":"That usually selects items."},{"start":474.56,"end":477.56,"text":"That will be double clicking."},{"start":477.56,"end":480.56,"text":"Make sure when you are double clicking to keep your mouse perfectly still."},{"start":480.56,"end":484.56,"text":"Don''t move it at all, otherwise it will register as two single clicks."},{"start":484.56,"end":486.56,"text":"Next up, you have the scroll wheel here."},{"start":486.56,"end":491.56,"text":"Most common uses for the scroll wheel are to scroll up and to scroll down."},{"start":491.56,"end":496.56,"text":"These two things allow you to scroll web pages or any application up and down."},{"start":496.56,"end":499.56,"text":"Those are your two uses for the scroll wheel."},{"start":499.56,"end":503.56,"text":"There is a third use where you can actually click down on your scroll wheel."},{"start":503.56,"end":509.56,"text":"If you push down and you have that functionality on your mouse, it will actually do things like open up web links."},{"start":509.56,"end":517.56,"text":"If you have a link on a website that you want to open up in a new tab, you push down on the scroll wheel and it will open up in a new tab."},{"start":518.56,"end":522.56,"text":"That''s a very cool use for that scroll wheel as well that most people don''t know about."},{"start":522.56,"end":529.56,"text":"Finally, the right side menu or the right click is always referred to as right click."},{"start":529.56,"end":534.56,"text":"Whereas clicking is automatically assumed it''s left, so I''ll never say left click in a tutorial."},{"start":534.56,"end":536.56,"text":"Right click, I will say."},{"start":536.56,"end":538.56,"text":"Right click is way less common."},{"start":538.56,"end":544.56,"text":"Some new computer users, beginners who are starting out on computers insist on right clicking on things."},{"start":544.56,"end":548.56,"text":"Typically you''ll do that with your middle finger on your right hand."},{"start":548.56,"end":550.56,"text":"That one is way less common."},{"start":550.56,"end":553.56,"text":"It''s really only used to open up sub menus."},{"start":553.56,"end":555.56,"text":"Clicking is your default."},{"start":555.56,"end":558.56,"text":"Typically we don''t right click too often."},{"start":558.56,"end":564.56,"text":"I know I went over a lot in this video and it''s some good things to keep in mind if you''re a beginner at computers."},{"start":564.56,"end":570.56,"text":"Hopefully this video is helpful for you and it will help you use your keyboard and mouse a little bit more efficiently."},{"start":570.56,"end":575.56,"text":"If I didn''t cover specific keys, that''s because I don''t use those keys very often."},{"start":575.56,"end":580.56,"text":"Not much point on covering something that is not super useful on the keyboard."},{"start":580.56,"end":587.56,"text":"If there is any questions that you have, please put it in the comment section below and I''ll do my best to respond to you."},{"start":587.56,"end":592.56,"text":"If you found the video useful, please put a thumbs up on the video and consider subscribing to the channel."},{"start":592.56,"end":595.56,"text":"If you have any questions, again put them in the comment section below."},{"start":595.56,"end":598.56,"text":"Thank you so much for watching and have a great rest of your day."}]'::jsonb
) AS segment
WHERE l.youtube_video_id = 'vKauB_ui598';

