INSERT INTO transcript_chunks (lesson_id, chunk_text, start_time, end_time)
SELECT
    l.id AS lesson_id,
    segment.value->>'text' AS chunk_text,
    (segment.value->>'start')::numeric AS start_time,
    (segment.value->>'end')::numeric AS end_time
FROM lessons l
CROSS JOIN jsonb_array_elements(
    '[{"start":0,"end":5.44,"text":"This course is a computer basics course for people who are brand new to using computers."},{"start":5.44,"end":9.44,"text":"It''s also great for people who have some knowledge but just want to fill in some gaps."},{"start":9.44,"end":13.72,"text":"There are a variety of topics and you can use the time codes in the description to skip"},{"start":13.72,"end":15.96,"text":"right to the topic you want to learn about."},{"start":15.96,"end":19.68,"text":"This course was developed by GCFglobal.org."},{"start":30,"end":59,"text":"The computer sees data as ones and zeros, but it knows how to combine them into much more complex things, such as a photo, movie, website, game, and much more."},{"start":60,"end":65,"text":"Computers use a combination of hardware and software."},{"start":65,"end":75,"text":"Hardware is any physical part of the computer, which includes the internal components and the external parts, like the monitor and keyboard."},{"start":75,"end":85,"text":"Software is any set of instructions that tells the hardware what to do, such as a web browser, media player, or word processor."},{"start":85,"end":90,"text":"When most people say computer, they''re talking about a personal computer."},{"start":90,"end":100,"text":"This can be a desktop computer or a laptop, which has basically the same capabilities but in a more portable package."},{"start":100,"end":103,"text":"Personal computers come in a few different styles."},{"start":103,"end":108,"text":"The most common type uses the Windows operating system."},{"start":109,"end":117,"text":"Macs or Macintosh computers feature the Mac OS operating system, while Chromebooks run on Chrome OS."},{"start":117,"end":124,"text":"Smartphones and other mobile devices mostly use the iOS or Android operating systems."},{"start":124,"end":129,"text":"We''ll talk more about operating systems in a later video."},{"start":130,"end":133,"text":"Computers come in many other shapes and sizes."},{"start":133,"end":145,"text":"TVs, game consoles, and even appliances like refrigerators can have built-in computers, although they may not do everything a desktop or laptop can."},{"start":145,"end":150,"text":"There''s another type of computer that plays an important role in our lives."},{"start":150,"end":151,"text":"Servers."},{"start":151,"end":156,"text":"A server sends information to other computers on a network."},{"start":156,"end":165,"text":"In fact, every time you use the internet, web servers deliver the webpages that you want to see to your computer."},{"start":165,"end":172,"text":"Servers are also used in many offices to store and share files."},{"start":172,"end":181,"text":"As you can see, there are many types of computers out there, and each one plays a part in our modern world."},{"start":182,"end":186,"text":"Every computer has its own set of buttons and ports."},{"start":186,"end":193,"text":"In this video, we''re going to talk about some of the most common ones, including what they''re for and how to recognize them."},{"start":193,"end":197,"text":"Some buttons are universal, like the power button."},{"start":197,"end":209,"text":"Depending on the type of computer you have, it may be on the front, on the back behind the screen, or even on the inside when you open the lid."},{"start":210,"end":214,"text":"The power socket is where you''ll connect the power cord."},{"start":214,"end":220,"text":"If you have a laptop, you''ll have a charging port instead."},{"start":220,"end":226,"text":"Most computers provide more than one USB port, so you can plug in any device you might need."},{"start":226,"end":231,"text":"Keyboards, printers, and USB drives are all common examples."},{"start":232,"end":240,"text":"Some computers even have USB-C ports, which can be used for many different things, not just plugging in devices."},{"start":240,"end":245,"text":"Laptops, for instance, often use the format for the charging port."},{"start":245,"end":250,"text":"If you have a desktop, you''ll use the monitor port to connect the monitor."},{"start":250,"end":257,"text":"There are quite a few types of monitor connections, ranging from HDMI to the USB-C style we just mentioned."},{"start":257,"end":263,"text":"If you have a laptop, you can connect a separate monitor as long as you have the right equipment."},{"start":263,"end":267,"text":"Just look for the display port and plug in the appropriate cable."},{"start":267,"end":272,"text":"The Ethernet port lets you connect to the internet if you''re not using Wi-Fi."},{"start":272,"end":278,"text":"All you need is an Ethernet cable, which you can then connect to your modem or router."},{"start":278,"end":284,"text":"If your computer has an audio jack, you can use it to plug in wired headphones or speakers."},{"start":284,"end":290,"text":"You may or may not have a disk drive, depending on how old your computer is and who makes it."},{"start":290,"end":296,"text":"The disk drive can be used to insert a CD, a DVD, or a Blu-ray disk."},{"start":296,"end":303,"text":"If you have ports that look like this, they''re for older peripherals like mice, keyboards, and printers."},{"start":303,"end":310,"text":"Newer versions of these devices usually connect via USB or wirelessly."},{"start":310,"end":314,"text":"That covers the basics of buttons and ports."},{"start":314,"end":318,"text":"Of course, every computer is different, and technology is always changing."},{"start":318,"end":323,"text":"To find out what options you have, take a closer look at your computer."},{"start":328,"end":335,"text":"There are many different types of computers, but they all use similar parts to operate."},{"start":335,"end":345,"text":"In this video, we''re going to show you what these parts are and what they''re used for, starting with a standard desktop model."},{"start":345,"end":349,"text":"The computer case holds the main components of the computer."},{"start":349,"end":353,"text":"This is where the actual processing happens."},{"start":353,"end":364,"text":"Today, most cases are what we call tower cases, which means they stand up vertically, but they can also come in other shapes and sizes."},{"start":364,"end":368,"text":"To view things on your computer, you''ll need a monitor."},{"start":368,"end":378,"text":"The monitor uses the video processor inside your computer case to display images, text, and other content."},{"start":378,"end":388,"text":"Most monitors have an LCD or LED display, both of which are very thin so they don''t take up much space."},{"start":389,"end":397,"text":"All-in-one models are even more compact since they combine the monitor and the computer case into a single unit."},{"start":397,"end":402,"text":"To interact with your computer, you''ll need a keyboard and a mouse."},{"start":402,"end":409,"text":"Keyboards come in many different styles, including wireless and ergonomic."},{"start":409,"end":418,"text":"The mouse is used to control the mouse pointer on this screen so you can click and interact with your computer."},{"start":418,"end":423,"text":"Most mice detect movement using an optical sensor on the bottom."},{"start":423,"end":428,"text":"Underneath, you''ll find a small electronic eye."},{"start":428,"end":443,"text":"Laptops combine all of these things into one that includes the components that are normally inside the computer case, plus a built-in screen, keyboard, and touchpad."},{"start":443,"end":450,"text":"The touchpad is a small touch-sensitive area that takes the place of a traditional mouse."},{"start":450,"end":456,"text":"It lets you control the mouse pointer using a drawing motion with your finger."},{"start":456,"end":462,"text":"Laptops offer the best of both worlds when it comes to portability."},{"start":462,"end":476,"text":"You can use them on the go thanks to the built-in battery, or you can connect a separate monitor, keyboard, and mouse, effectively turning your laptop into a desktop."},{"start":476,"end":480,"text":"So those are the basic parts of any computer setup."},{"start":480,"end":494,"text":"As you can see, each part plays an important role, which you''ll come to understand as you spend more and more time with your computer."},{"start":494,"end":501,"text":"You may already know that there are many important parts inside a computer, but what exactly do they do?"},{"start":501,"end":507,"text":"Let''s take a look inside and learn about the various components that make a computer work."},{"start":507,"end":514,"text":"Whether it''s a desktop computer or a laptop, every computer has a large circuit board called a motherboard."},{"start":514,"end":523,"text":"This contains some of the most important parts of the computer, such as the CPU, also known as the central processing unit, or processor."},{"start":523,"end":530,"text":"The CPU can be considered the brain of the computer because it processes information and carries out commands."},{"start":530,"end":538,"text":"Since it tends to get hot, it''s covered by a piece of metal called a heat sink, which draws heat away from the processor."},{"start":538,"end":544,"text":"The motherboard also contains the computer''s RAM, or random access memory."},{"start":544,"end":549,"text":"This is the short-term memory that the computer uses whenever it''s performing calculations."},{"start":549,"end":556,"text":"However, you cannot store your files there because the RAM is cleared when you shut off the computer."},{"start":557,"end":564,"text":"The hard drive provides long-term storage, keeping all of the computer''s data even when it''s turned off."},{"start":564,"end":576,"text":"Many hard drives use a magnetic platter to store data, but many newer computers have solid state drives, which are faster and more durable, but also more expensive."},{"start":576,"end":583,"text":"On many desktop computers, the motherboard has expansion slots that allow you to upgrade by adding expansion cards."},{"start":583,"end":591,"text":"You can add a video card to get better graphics performance, or you can add a wireless card to connect to your wireless home network."},{"start":591,"end":595,"text":"Most laptops, however, don''t have expansion slots."},{"start":595,"end":599,"text":"Of course, the computer''s components need electricity to run."},{"start":599,"end":606,"text":"The power supply unit is designed to take power from the wall outlet and send it to all of the different components that need power."},{"start":606,"end":611,"text":"Laptops also contain a built-in battery that lets you use them anywhere."},{"start":611,"end":619,"text":"A computer is a pretty complex machine, but now that you''ve seen what goes on inside, it should be a little less mysterious."},{"start":626,"end":631,"text":"If you''re thinking of buying a computer, you may have wondered, is a laptop right for me?"},{"start":631,"end":635,"text":"Depending on how you plan to use it, the answer may be yes."},{"start":635,"end":642,"text":"In this video, we''ll look at some of the ways that a laptop is different from a desktop to help you decide."},{"start":642,"end":649,"text":"The biggest difference is portability. Laptops have to be small and light so that you can pick them up and take them with you."},{"start":649,"end":655,"text":"Since all of the basic parts are built in, setting up a laptop is as easy as opening it."},{"start":655,"end":662,"text":"The downside is that the monitor is usually smaller than a desktop monitor, so you''ll have less screen space."},{"start":663,"end":666,"text":"Another important difference is that laptops use a battery."},{"start":666,"end":673,"text":"The battery can provide power to the laptop when you''re on the go, and it will recharge whenever it''s plugged in."},{"start":673,"end":680,"text":"An added benefit of having a battery is if the power goes out, the battery can work as a backup power source."},{"start":681,"end":687,"text":"Instead of a mouse, laptops usually have a built-in touchpad, also known as a trackpad."},{"start":687,"end":692,"text":"You can control the pointer on the screen by using a drawing motion with your finger."},{"start":692,"end":699,"text":"If you haven''t used a touchpad before, the experience is a little bit different from using a mouse, and it may take a while to get used to."},{"start":700,"end":706,"text":"If you''re buying a desktop computer, you can mix and match almost any monitor, keyboard, and mouse that you want."},{"start":706,"end":710,"text":"With a laptop, you won''t have quite as much freedom since everything is built in."},{"start":710,"end":718,"text":"However, if you want to have the best of both worlds, you can use your laptop''s ports to connect a separate monitor, keyboard, and mouse,"},{"start":718,"end":721,"text":"basically turning your laptop into a desktop."},{"start":721,"end":727,"text":"And of course, whenever you want to, you can simply disconnect everything and take your laptop with you."},{"start":729,"end":733,"text":"As you can see, there are some important differences between laptops and desktops,"},{"start":733,"end":737,"text":"so depending on your preferences, you can decide which one best suits your needs."},{"start":741,"end":745,"text":"Did you know that you and your computer speak different languages?"},{"start":745,"end":750,"text":"It doesn''t speak Spanish, or Swedish, or Chinese."},{"start":750,"end":753,"text":"It speaks in ones and zeros."},{"start":753,"end":759,"text":"You can''t communicate directly with your computer, but that''s where your operating system comes in."},{"start":759,"end":765,"text":"The operating system, or OS, is the program that lets you interact with your computer."},{"start":765,"end":772,"text":"Together, the operating system and computer hardware form a complete system that determines what your computer can do."},{"start":772,"end":775,"text":"There are many different operating systems."},{"start":775,"end":780,"text":"Two of the most common ones are Microsoft Windows and Mac OS."},{"start":780,"end":787,"text":"Windows comes preloaded on most personal computers, while Mac OS runs on all new Macs."},{"start":787,"end":791,"text":"Operating systems aren''t just for desktop and laptop computers."},{"start":791,"end":797,"text":"Mobile devices run mobile operating systems, like Apple iOS or Google Android,"},{"start":797,"end":801,"text":"which are designed for interactions with smaller touchscreens."},{"start":802,"end":808,"text":"Before downloading a new program or application, be aware that it may not be available for your operating system."},{"start":808,"end":814,"text":"Some applications work on all devices, while others only work on certain ones."},{"start":814,"end":818,"text":"So get to know your operating system to see how it works."},{"start":821,"end":823,"text":"And what it can do."},{"start":829,"end":833,"text":"If you woke up this morning thanks to the alarm on your smartphone,"},{"start":833,"end":837,"text":"or if you like watching videos or playing games on your tablet,"},{"start":837,"end":841,"text":"you''re using applications, also known as apps."},{"start":841,"end":846,"text":"An app is a software program that lets you do things for lack of a better word."},{"start":846,"end":852,"text":"You''ll find apps on all of your devices, including smartphones, tablets, and computers."},{"start":852,"end":857,"text":"Some apps help you complete tasks, while others are just for fun."},{"start":857,"end":861,"text":"Here''s some examples of ways you can use apps."},{"start":861,"end":865,"text":"Mobile apps are apps that run on your smartphone or tablet."},{"start":865,"end":868,"text":"They can make many things in life more convenient."},{"start":868,"end":871,"text":"For instance, if you''re looking for a place to buy coffee,"},{"start":871,"end":874,"text":"an app like Google Maps can determine your current location,"},{"start":874,"end":877,"text":"and then recommend your by-coffee shops."},{"start":877,"end":880,"text":"Apps aren''t just for mobile devices, though."},{"start":880,"end":884,"text":"The programs and applications on your computer can also be considered apps."},{"start":884,"end":888,"text":"If you''ve ever used Microsoft Word to create a document,"},{"start":888,"end":891,"text":"or a web browser to visit a website or check your email,"},{"start":891,"end":894,"text":"guess what? You''ve used an app."},{"start":895,"end":900,"text":"Some apps come already installed, but you can easily download or buy more online."},{"start":900,"end":907,"text":"Apps are about communication, productivity, entertainment, and more."},{"start":907,"end":912,"text":"With so many possibilities, you''re sure to find several apps that are perfect for the things you do."},{"start":921,"end":924,"text":"Are you having trouble putting your computer together?"},{"start":924,"end":927,"text":"Are you feeling overwhelmed?"},{"start":927,"end":930,"text":"Don''t worry. Take a deep breath."},{"start":930,"end":936,"text":"We''re going to show you, step by step, how to set up a desktop computer."},{"start":936,"end":942,"text":"First, unpack everything from the box, and remove any plastic covering or protective tape."},{"start":942,"end":945,"text":"Think about where you want your workspace to go,"},{"start":945,"end":950,"text":"and how you want to arrange the different components before you start plugging things in."},{"start":950,"end":953,"text":"Next, let''s connect the monitor."},{"start":953,"end":958,"text":"If you have an all-in-one computer where everything is built in, for example, an iMac,"},{"start":958,"end":963,"text":"you can skip this step. Otherwise, locate your monitor cable."},{"start":963,"end":968,"text":"Newer monitors often use HDMI or USB-C connections."},{"start":968,"end":976,"text":"While older monitors may use VGA, DVI, or another type of connection, it just depends."},{"start":976,"end":981,"text":"Now find the monitor port on the back of your computer case and plug the cable in."},{"start":981,"end":987,"text":"Most cables are designed to fit a certain way, so if it''s not working, don''t force it."},{"start":987,"end":991,"text":"When you''re done, connect the other end to your monitor."},{"start":991,"end":995,"text":"Now it''s time to plug in your keyboard and mouse."},{"start":995,"end":1002,"text":"If they''re wired, they most likely have a USB connector, so you can use any of the ports you see here."},{"start":1002,"end":1007,"text":"You could also plug your mouse into the USB port on your keyboard if it has one."},{"start":1007,"end":1012,"text":"If you have a wireless mouse or keyboard, it''s going to work a little differently."},{"start":1012,"end":1020,"text":"Some wireless devices connect using technology that''s built into your computer, while others need an adapter."},{"start":1020,"end":1025,"text":"You''ll also need to pair the device with your computer before you can use it."},{"start":1025,"end":1030,"text":"You may want to read the instructions that came with your wireless device to learn more about pairing."},{"start":1030,"end":1034,"text":"At this point, you can plug in your speakers or headphones."},{"start":1034,"end":1042,"text":"If it uses a typical audio plug, look for the green audio port on the front or back of your computer case."},{"start":1042,"end":1048,"text":"However, some speakers, headphones, and microphones use USB connectors."},{"start":1048,"end":1053,"text":"Finally, it''s time to connect the power supply cables and plug the computer in."},{"start":1053,"end":1055,"text":"You should have two cables."},{"start":1055,"end":1061,"text":"One goes with your monitor and the other plugs into the back of your computer case."},{"start":1061,"end":1065,"text":"Now plug both cables into a power outlet."},{"start":1065,"end":1070,"text":"We recommend using a surge protector to keep your equipment safe in the event of a power surge."},{"start":1070,"end":1075,"text":"When you''re ready, plug the surge protector into a regular outlet."},{"start":1075,"end":1079,"text":"If it has a power switch, you may need to switch it on."},{"start":1079,"end":1081,"text":"That''s all there is to it."},{"start":1081,"end":1085,"text":"Now take a minute to make sure you''re happy with your workspace."},{"start":1085,"end":1090,"text":"Then turn your computer on."},{"start":1091,"end":1097,"text":"There are lots of reasons to set up a home internet connection."},{"start":1097,"end":1104,"text":"For example, you''ll have access to email, news, shopping, TV shows, and much more."},{"start":1104,"end":1109,"text":"And once you have a working internet connection, you can create a wireless home network,"},{"start":1109,"end":1115,"text":"which will let your whole family connect their computers, smartphones, and other internet-ready devices."},{"start":1115,"end":1120,"text":"Let''s look at a few different types of internet connections that you can have."},{"start":1120,"end":1123,"text":"Dial-up connects to your phone line."},{"start":1123,"end":1126,"text":"It''s usually much slower than other types of internet connections,"},{"start":1126,"end":1130,"text":"but in some areas it may be the only option available."},{"start":1130,"end":1135,"text":"Generally, DSL and cable are better options."},{"start":1135,"end":1141,"text":"DSL plugs into your phone line, and cable uses your cable TV connection."},{"start":1141,"end":1147,"text":"These are both known as broadband internet connections, because they offer much faster speeds than dial-up."},{"start":1147,"end":1153,"text":"This makes it easier to watch videos, play games, or browse the web."},{"start":1153,"end":1157,"text":"Fiber is the fastest type of broadband currently available."},{"start":1157,"end":1163,"text":"Using fiber optic cables, it can provide speeds that exceed even DSL or cable."},{"start":1163,"end":1170,"text":"However, it may not be available where you live, and it tends to be more expensive."},{"start":1170,"end":1177,"text":"Cellular is sold under a few different names, including 4G, LTE, and 5G."},{"start":1177,"end":1181,"text":"They''re types of wireless internet connections often used by smartphones,"},{"start":1181,"end":1185,"text":"but you can also get these types of connections for your home."},{"start":1185,"end":1191,"text":"Depending on where you live, a cellular connection may be a good broadband alternative."},{"start":1191,"end":1198,"text":"No matter what kind of internet service you choose, you''ll need to purchase it from an internet service provider,"},{"start":1198,"end":1200,"text":"or ISP."},{"start":1200,"end":1204,"text":"Chances are, you can buy internet service from your phone or cable company,"},{"start":1204,"end":1207,"text":"or you may want to shop around for a better price."},{"start":1207,"end":1212,"text":"Your ISP will guide you through the entire process of connecting to the internet."},{"start":1212,"end":1217,"text":"They will usually need to send a technician to your home to turn on your connection."},{"start":1217,"end":1222,"text":"Your ISP may also give you a modem and settle up for you."},{"start":1222,"end":1229,"text":"But if you prefer, you can buy a modem from a computer store and use the included instructions to settle up yourself."},{"start":1229,"end":1236,"text":"These instructions will vary, but the basic idea is that you''ll connect the modem to your phone jack or cable TV connection,"},{"start":1236,"end":1241,"text":"and then connect your computer to the modem using an ethernet cable."},{"start":1241,"end":1247,"text":"Once you have everything set up, you can open your web browser and begin using the internet."},{"start":1247,"end":1255,"text":"If you want to connect several devices to the internet, you can create a wireless home network, also known as a Wi-Fi network."},{"start":1255,"end":1263,"text":"To do this, you''ll need a wireless router, which takes the internet connection from your modem and broadcasts it throughout your home."},{"start":1263,"end":1269,"text":"Your modem may already have a wireless router built in, so you may not need to buy one."},{"start":1269,"end":1274,"text":"To set up your wireless connection, follow the instructions included with your router."},{"start":1274,"end":1279,"text":"You''ll need to choose a network name, also known as an SSID."},{"start":1279,"end":1287,"text":"Also, for security, you should turn on WPA2 or WPA3 encryption, depending on what your router supports."},{"start":1287,"end":1291,"text":"Then, make sure you choose a strong password."},{"start":1291,"end":1301,"text":"After you''ve set up your wireless network, go into each device''s Wi-Fi or network settings, select your network name, and type your password."},{"start":1301,"end":1310,"text":"If any of your devices are not wireless ready, you can simply plug them into your router with an ethernet cable, or you can purchase a wireless card."},{"start":1310,"end":1322,"text":"Setting up an internet connection and Wi-Fi network takes a little bit of work, but once you get it set up, your family will be able to use the internet without being limited to one computer."},{"start":1322,"end":1333,"text":"So you''re at your computer working on some important files."},{"start":1333,"end":1338,"text":"Suddenly, a meter I burst through the window and flattens the computer."},{"start":1338,"end":1342,"text":"But as you stare into the crater, you smile and think,"},{"start":1342,"end":1349,"text":"at least my photos, music, and important documents are stored online in the cloud."},{"start":1349,"end":1355,"text":"When something is stored in the cloud, that means it''s saved on internet servers instead of on your computer."},{"start":1355,"end":1361,"text":"It''s like having an extra hard drive you can access anytime you''re connected to the internet."},{"start":1361,"end":1366,"text":"You can access your files anywhere by using cloud-based apps."},{"start":1366,"end":1371,"text":"Some run inside your computer''s web browser. These are called web apps."},{"start":1371,"end":1375,"text":"And some of them can also be installed on your mobile device."},{"start":1375,"end":1379,"text":"For instance, Google Docs is a cloud-based app that you may already use."},{"start":1379,"end":1385,"text":"It''s free, and it allows you to view, create, and edit many types of projects."},{"start":1385,"end":1390,"text":"You can access Google Docs from almost any device with an internet connection."},{"start":1390,"end":1397,"text":"Since you only need a connected device to access the cloud, you can take your files wherever you like."},{"start":1397,"end":1405,"text":"You can take a photo on your smartphone and upload it to a cloud-based photo storage service like Google Photos or Dropbox."},{"start":1405,"end":1411,"text":"Then you can access that photo on any of your other devices like your computer or TV."},{"start":1411,"end":1419,"text":"You can even work on a document when you''re far away from your desk and share it with anyone you want, instantly."},{"start":1419,"end":1425,"text":"Storing files in the cloud is a great way to protect them from accidents, viruses, and more."},{"start":1425,"end":1432,"text":"You can use cloud-based storage services like iDrive or Backblaze to back up the contents of your computer."},{"start":1432,"end":1436,"text":"These services run continually and back up automatically."},{"start":1436,"end":1443,"text":"This way, you will always have the most recent versions of your files stored in secure online servers."},{"start":1443,"end":1451,"text":"If something bad happens to your device, you can easily transfer your backup files from the cloud to another device."},{"start":1452,"end":1460,"text":"Whether you''re backing up photos and music that you love, or using a file on the go, the cloud has a lot to offer."},{"start":1460,"end":1469,"text":"Plus, when your files are stored in the cloud, you won''t need to worry about losing them to a computer malfunction or a rogue meteorite."},{"start":1470,"end":1475,"text":"It''s important to keep your computer clean."},{"start":1475,"end":1481,"text":"Not only because it looks nice, but also because things like dust and dirt can affect your computer''s performance."},{"start":1481,"end":1484,"text":"But there''s a right way and a wrong way to do it."},{"start":1484,"end":1489,"text":"Here''s the right way to clean your computer case, monitor, mouse, and keyboard."},{"start":1489,"end":1494,"text":"First, always turn off or unplug the item before you clean it, just to be safe."},{"start":1494,"end":1502,"text":"If it has a PS2 connector like this, make sure the computer is shut down, both when you unplug the cable and when you plug it back in."},{"start":1502,"end":1508,"text":"To clean your keyboard, turn it upside down and gently shake it to remove any dust, dirt, or crumbs."},{"start":1508,"end":1512,"text":"It''s not uncommon for stuff to get stuck inside, which can affect the way your keyboard works."},{"start":1512,"end":1517,"text":"You can also use a can of compressed air to really get between the keys."},{"start":1517,"end":1522,"text":"To clean the surface, use a cotton cloth or paper towel that''s moistened with rubbing alcohol."},{"start":1522,"end":1526,"text":"Never actually pour alcohol or any other liquid on your keyboard."},{"start":1526,"end":1529,"text":"If you spill something by accident, don''t panic."},{"start":1529,"end":1535,"text":"Shut your computer down immediately, then disconnect the keyboard and turn it upside down so the liquid can drain."},{"start":1535,"end":1541,"text":"If the liquid is sticky, you can rinse your keyboard under running water just like this, turn to the side."},{"start":1541,"end":1545,"text":"Then let it drain upside down for two days before reconnecting it."},{"start":1545,"end":1548,"text":"It may not be repairable at this point, but it''s worth a try."},{"start":1548,"end":1553,"text":"The best way to avoid this is to keep drinks away from the computer area altogether."},{"start":1553,"end":1556,"text":"Next, take a look at your mouse."},{"start":1556,"end":1561,"text":"If you have an optical mouse, good news, these don''t require much cleaning at all because they don''t have any moving parts."},{"start":1561,"end":1564,"text":"Just keep an eye on the light emitter underneath."},{"start":1564,"end":1569,"text":"If something gets stuck here, even a piece of dust, it can keep your mouse from working smoothly."},{"start":1569,"end":1573,"text":"To clean a mechanical mouse, again, make sure it''s unplugged."},{"start":1573,"end":1578,"text":"Then remove the tracking ball by turning the ring counterclockwise. It should pop right out."},{"start":1578,"end":1582,"text":"Use a cotton cloth or paper towel to wipe it with a little rubbing alcohol."},{"start":1582,"end":1585,"text":"You can wipe the inside of the mouse too."},{"start":1585,"end":1589,"text":"Make sure all the parts are dry before you put them back together."},{"start":1591,"end":1597,"text":"Here''s an easy tip. You can give your mouse a quick cleaning by rubbing it back and forth on a clean white sheet of paper."},{"start":1597,"end":1602,"text":"Sometimes this is enough to remove the dust and dirt that can get stuck underneath."},{"start":1602,"end":1607,"text":"Your monitor is going to be even easier to clean, but there are a few things to keep in mind."},{"start":1607,"end":1615,"text":"Never spray the screen directly. With water, cleaner, or any other kind of liquid, it can leak into the monitor and damage the components inside."},{"start":1615,"end":1621,"text":"Never use glass cleaner, like Windex. This can damage your screen if it has an anti-glare coating."},{"start":1621,"end":1627,"text":"The safest method is to unplug the monitor, then wipe it with a soft cloth moistened with water."},{"start":1628,"end":1634,"text":"You should also give some thought to cleaning other parts of your workspace, like the back of your monitor and your computer case."},{"start":1634,"end":1637,"text":"These areas can get pretty dusty if you''re not careful."},{"start":1637,"end":1642,"text":"A lint-free cloth, sometimes called a microfiber cloth, is great for wiping the casings."},{"start":1642,"end":1648,"text":"If you see a lot of build-up in the ventilation fans, you can use a can of compressed air to clean them out."},{"start":1648,"end":1652,"text":"Never use furniture cleaner or strong solvents on any of these surfaces."},{"start":1652,"end":1657,"text":"Instead, take your cloth or even a paper towel and spray it with glass cleaner."},{"start":1657,"end":1662,"text":"Now wipe the case and monitor housing, but not the monitor screen, in a downward motion."},{"start":1662,"end":1667,"text":"You can make your own solution using ammonia diluted with water, the milder the better."},{"start":1667,"end":1673,"text":"One more thing you can do to make sure your computer stays physically healthy is to watch the airflow around the case."},{"start":1673,"end":1681,"text":"That means no books, no stacks of paper, nothing that might block the fans in the back, which are designed to keep your computer from overheating."},{"start":1681,"end":1687,"text":"In fact, if you have a desk with a compartment for the case, you may want to position the case a little towards the front,"},{"start":1687,"end":1690,"text":"or leave the compartment open if it has a door."},{"start":1690,"end":1693,"text":"Both of these steps will help your computer stay cool."},{"start":1697,"end":1699,"text":"Looks good to me!"},{"start":1699,"end":1705,"text":"Just remember to clean your equipment regularly, the right way, and your computer is sure to stay healthy for years to come."},{"start":1706,"end":1710,"text":"We rely on our computers for many different things."},{"start":1710,"end":1716,"text":"We trust them to keep our information safe, including our files and personal data."},{"start":1716,"end":1722,"text":"That''s why it''s important to protect your computer, and do your best to keep it running smoothly."},{"start":1722,"end":1725,"text":"Here are some tips that can help."},{"start":1725,"end":1729,"text":"One of the biggest threats to computer safety is malware."},{"start":1729,"end":1737,"text":"Malware is any type of software that''s designed to damage your computer or gain unauthorized access to your personal info."},{"start":1737,"end":1742,"text":"This can include viruses, spyware, Trojan horses, and other malicious software."},{"start":1742,"end":1747,"text":"Windows computers, Macs, and even Chromebooks can get malware."},{"start":1747,"end":1754,"text":"To protect your computer, you should use an antivirus program, like Casper."},{"start":1754,"end":1761,"text":"This helps prevent viruses from being installed, and also lets you scan your computer and remove any viruses that are found."},{"start":1761,"end":1765,"text":"Keep in mind, no antivirus program is perfect."},{"start":1765,"end":1770,"text":"To stay safe, you should still avoid suspicious looking ads or downloads."},{"start":1770,"end":1775,"text":"Run regular updates to your antivirus program, and you should be able to use it."},{"start":1775,"end":1782,"text":"To keep your computer running smoothly, the latest version of Windows offers a couple useful features, including storage sense and defragment and optimized drives."},{"start":1782,"end":1788,"text":"You can access both of these in settings, or you can find them using the search bar."},{"start":1788,"end":1793,"text":"When you use the search bar, you can access both of these in settings, or you can find them using the search bar."},{"start":1793,"end":1798,"text":"You can access both of these in settings, or you can find them using the search bar."},{"start":1798,"end":1805,"text":"When you turn it on, storage sense helps you free up space on your hard drive by scanning for temporary files and other files that can be deleted."},{"start":1805,"end":1809,"text":"Once on, it will run automatically in the background."},{"start":1809,"end":1814,"text":"Older versions of Windows offer a similar feature, called disk cleanup."},{"start":1814,"end":1820,"text":"Defragment and optimized drives rearranges the data on your hard drive to help you save time."},{"start":1820,"end":1827,"text":"It should be running automatically on a weekly basis, but you can easily check or change the schedule anytime."},{"start":1827,"end":1832,"text":"If something bad does happen to your computer, you could lose all of your important files."},{"start":1832,"end":1836,"text":"To prevent this, you should back up your computer regularly."},{"start":1836,"end":1841,"text":"If you have a problem with your computer, you can use the search bar to help you save time."},{"start":1841,"end":1845,"text":"If this happened to your computer, you could lose all of your important files."},{"start":1845,"end":1850,"text":"To prevent this, you should back up your computer regularly."},{"start":1850,"end":1855,"text":"One option is to buy an external hard drive and copy your files to it."},{"start":1855,"end":1863,"text":"To make this process even easier, you can use software like Windows Backup or Time Machine if you''re using a Mac."},{"start":1863,"end":1870,"text":"Of course, if something happens to your computer and your backup drive, you''ll still lose all of your files."},{"start":1870,"end":1876,"text":"For more security, you can use an online backup service like iDrive or Carbonite."},{"start":1876,"end":1886,"text":"You may have to pay a monthly fee to use these services, but the advantage is that your files will stay safe in the cloud, no matter what happens to your computer."},{"start":1886,"end":1892,"text":"Following these tips can help you protect your computer and keep your information safe."},{"start":1892,"end":1898,"text":"You can rest easy knowing that all of your files will be there when you need them."},{"start":1901,"end":1912,"text":"The staring at the computer for hours make you feel tired? Do you suffer from frequent aches and pains?"},{"start":1912,"end":1916,"text":"Looks like you could use some help with ergonomics."},{"start":1916,"end":1925,"text":"Ergonomics is a big subject, but basically it''s about you and the things that you can do to make your workspace more comfortable."},{"start":1925,"end":1932,"text":"As strange as it sounds, sitting at a desk all day is actually very hard on your body."},{"start":1932,"end":1940,"text":"But if you arrange your workspace with ergonomics in mind, you can avoid things like eye strain and neck and back pain."},{"start":1940,"end":1947,"text":"Here are some tips to help you stay safe, comfortable, and productive all day long."},{"start":1947,"end":1954,"text":"Keyboard position is important. When you''re typing, your wrist should be straight and relaxed to avoid any strain."},{"start":1954,"end":1961,"text":"If you do start to feel any wrist pain, you might want to look into certain products that can give you extra support."},{"start":1961,"end":1965,"text":"For example, an ergonomic keyboard."},{"start":1965,"end":1971,"text":"Next, raise and lower your chair so that your wrists are in the correct position."},{"start":1971,"end":1975,"text":"If your feet no longer reach the floor, you can find a foot rest."},{"start":1975,"end":1981,"text":"When you''re in your chair, you should be sitting in a natural, comfortable position."},{"start":1981,"end":1985,"text":"Try to avoid hunching or sitting too straight."},{"start":1985,"end":1993,"text":"Many office chairs are adjustable and designed to give you extra support in places where you need it, like the lower back."},{"start":1993,"end":1996,"text":"Take the time to learn how your chair works."},{"start":1996,"end":2007,"text":"Your monitor should be a comfortable distance away from your eyes, somewhere between 20 to 40 inches, or about an arm''s length."},{"start":2007,"end":2014,"text":"The top of the screen should be about eye level, but this may vary depending on the size of the monitor."},{"start":2014,"end":2021,"text":"If you are working from a laptop, consider purchasing an external mouse and keyboard."},{"start":2021,"end":2030,"text":"That way, you can still place your screen at the proper distance and height while still being able to type comfortably."},{"start":2030,"end":2036,"text":"Adjust the screen brightness on your monitor so that it matches your surroundings."},{"start":2036,"end":2043,"text":"If you''re looking at your screen and it feels like you''re looking into a bright light, it''s too bright."},{"start":2043,"end":2047,"text":"If it looks dark and murky, it''s too dim."},{"start":2047,"end":2054,"text":"Some monitors also allow you to change the color so that the screen emits less blue light."},{"start":2054,"end":2062,"text":"This feature might be called night mode or night shift, and some people find that it greatly reduces eye strain."},{"start":2062,"end":2067,"text":"Another way to avoid strain and fatigue is to take frequent breaks."},{"start":2067,"end":2072,"text":"For example, look away from your monitor every once in a while."},{"start":2072,"end":2076,"text":"2020 is a good rule to follow."},{"start":2076,"end":2084,"text":"Every 20 minutes, focus your eyes on an object 20 feet away for 20 seconds."},{"start":2084,"end":2089,"text":"You can even download apps that will remind you when it''s time to take a break."},{"start":2090,"end":2094,"text":"It''s also important to get up and move every hour or so."},{"start":2094,"end":2102,"text":"Walk around, have a snack, whatever it takes to avoid sitting in the same position for too long."},{"start":2102,"end":2109,"text":"Even if you work at a standing desk, it''s still important to move every now and then."},{"start":2109,"end":2117,"text":"Clutter is another common problem, and it can lead to strainer injury if you''re not careful."},{"start":2117,"end":2123,"text":"In some cases, like loose power cords, it can even be a tripping hazard."},{"start":2123,"end":2132,"text":"If you have paperwork or supplies that can be put away, it''s best to store them somewhere else instead of leaving them on your desk."},{"start":2132,"end":2134,"text":"Let''s review."},{"start":2134,"end":2139,"text":"Sitting at a desk all day is surprisingly hard work,"},{"start":2139,"end":2148,"text":"but a little attention to ergonomics will help you stay safe, comfortable, and productive all day long."},{"start":2153,"end":2161,"text":"While you''re using the internet, you may be picking up spyware, downloading malware, or using fraudulent sites without even knowing it."},{"start":2161,"end":2167,"text":"But don''t worry, your browser does a number of things to help make sure you avoid running into malicious websites."},{"start":2167,"end":2171,"text":"And there are also some precautions you can take to stay safe."},{"start":2171,"end":2178,"text":"Something as simple as double-checking domain names can save you from accidentally visiting a site with unsafe content."},{"start":2178,"end":2184,"text":"Malicious sites often use deceptive web addresses to trick users into believing they are on a legitimate site."},{"start":2184,"end":2189,"text":"Many web browsers will highlight the domain when you''re typing in a site''s web address."},{"start":2189,"end":2193,"text":"In this case, it''s just a darker font than the rest of the web address."},{"start":2193,"end":2199,"text":"Being able to clearly read the domain name makes it easier to double-check and make sure it''s correct."},{"start":2199,"end":2206,"text":"This will help make sure you''re going to the real, trusted site and not a phony site with a similar web address."},{"start":2206,"end":2215,"text":"And if you are about to access a site that contains malware or other malicious content, many web browsers will show you a warning."},{"start":2217,"end":2221,"text":"Some websites will display this padlock image or a similar image."},{"start":2221,"end":2228,"text":"When you see this, you know that that site has added additional layers of protection by making sure your connection to the site is secure,"},{"start":2228,"end":2232,"text":"so third parties can''t see your personal information."},{"start":2232,"end":2237,"text":"This is most commonly seen on certain types of sites, like banking sites."},{"start":2237,"end":2243,"text":"You won''t see this on all websites, and that''s okay. Not all sites need the extra security."},{"start":2244,"end":2250,"text":"Finally, another easy way to make sure your browser is providing as much protection for you as possible"},{"start":2250,"end":2253,"text":"is by making sure you have the most recent version of your browser."},{"start":2253,"end":2258,"text":"Your browser will usually notify you when it has a new version or if there''s an update available."},{"start":2258,"end":2264,"text":"But if you think you''ve missed or ignored updates, you can manually check for updates."},{"start":2264,"end":2267,"text":"In Chrome, click the menu button."},{"start":2268,"end":2271,"text":"Then select About Google Chrome."},{"start":2274,"end":2280,"text":"By practicing just a few simple safety measures, you can browse the Internet more safely."},{"start":2283,"end":2292,"text":"The Internet has become an essential tool for communicating, which is partly why it has also become a popular target among scammers and cybercriminals."},{"start":2292,"end":2298,"text":"In order to safeguard yourself from email scams, harmful software, or identity theft,"},{"start":2298,"end":2302,"text":"it''s essential that you understand the ways you might be at risk."},{"start":2302,"end":2308,"text":"In this video, we''ll go over the basics of identifying and avoiding potentially harmful content on the Internet."},{"start":2309,"end":2312,"text":"The first line of defense begins with your email inbox."},{"start":2312,"end":2317,"text":"You''ve probably heard the term spam before in reference to junk email."},{"start":2317,"end":2323,"text":"Spammers can send an email to thousands of people at the same time, and they can do so anonymously,"},{"start":2323,"end":2326,"text":"making anti-spam laws hard to enforce."},{"start":2326,"end":2330,"text":"So it''s important to be cautious when it comes to opening emails."},{"start":2330,"end":2337,"text":"Fortunately, though, many email services now provide customizable features to help you protect your inbox."},{"start":2337,"end":2341,"text":"For example, the ability to turn off email images."},{"start":2341,"end":2344,"text":"Spam contains images that senders can track."},{"start":2344,"end":2352,"text":"When you open the email, the images load, and the spammer will be able to tell if your email works, possibly resulting in more spam."},{"start":2353,"end":2360,"text":"If you''re using Gmail like I am, you can turn off email images by clicking the gear icon,"},{"start":2362,"end":2365,"text":"and then selecting settings from the drop-down menu."},{"start":2368,"end":2372,"text":"Choose Ask Before Displaying External Images."},{"start":2378,"end":2380,"text":"Then click Save."},{"start":2383,"end":2389,"text":"Now if I get an email with images, Gmail will ask if I want the images to be displayed."},{"start":2393,"end":2397,"text":"Most email services also check to see if incoming messages are spam."},{"start":2397,"end":2405,"text":"If it finds spam, it will store the mail in a spam folder, so you don''t accidentally open it when you''re checking your email."},{"start":2406,"end":2413,"text":"Spam blocking systems aren''t perfect, though, and there may be times when legitimate emails end up in your spam folder,"},{"start":2413,"end":2418,"text":"so it''s a good idea to regularly check and make sure you aren''t missing important emails."},{"start":2421,"end":2426,"text":"To check your spam folder in Gmail, click More in the left pane."},{"start":2426,"end":2428,"text":"Then select Spam."},{"start":2429,"end":2434,"text":"And here you can see all the emails that have ended up in your spam folder."},{"start":2436,"end":2440,"text":"Many email services have a feature you can use to mark emails as spam."},{"start":2440,"end":2447,"text":"In Gmail, I can just select the email, and then click this button to mark it as spam."},{"start":2447,"end":2452,"text":"This helps your email provider to filter out these types of messages in the future."},{"start":2453,"end":2457,"text":"Some spam emails are simply annoying advertisements."},{"start":2458,"end":2466,"text":"Others will claim to be contacting you about something important when what they''re really trying to do is steal your personal information."},{"start":2466,"end":2468,"text":"This is known as phishing."},{"start":2468,"end":2473,"text":"It''s a type of scam in which an email pretends to be from a bank or another trusted source"},{"start":2473,"end":2479,"text":"in order to trick you into handing over your personal information by asking you to complete some sort of action."},{"start":2479,"end":2488,"text":"They may want you to re-enter a password, verify or update sensitive information like phone numbers, addresses, or credit card numbers,"},{"start":2488,"end":2493,"text":"and they almost always tell you to do so by following links they provide."},{"start":2493,"end":2497,"text":"It''s a good idea to avoid clicking links in emails."},{"start":2497,"end":2504,"text":"Instead of clicking the link, re-type the URL into your browser''s address bar to ensure that you go to the correct website."},{"start":2505,"end":2512,"text":"For example, here''s an email that looks like it''s from Bank of America, saying that some personal information has been changed"},{"start":2512,"end":2516,"text":"and asking me to verify the changes by following a few links."},{"start":2516,"end":2523,"text":"It looks real enough at first glance, but it''s surprisingly easy for scammers to create deceiving details such as these."},{"start":2523,"end":2527,"text":"Remember, phishing emails won''t always look like they''re phishing."},{"start":2527,"end":2533,"text":"The whole purpose is to look like they''re from your bank, credit card, or another trusted company."},{"start":2533,"end":2535,"text":"Think of it this way."},{"start":2535,"end":2542,"text":"If someone came to your house saying they worked for your bank and they needed your social security number to verify that you''re the account holder,"},{"start":2542,"end":2544,"text":"would you give it to them?"},{"start":2544,"end":2547,"text":"Chances are you wouldn''t give out that information."},{"start":2547,"end":2549,"text":"Look at emails the same way."},{"start":2549,"end":2554,"text":"Just because an email says it''s from a familiar company doesn''t mean it really is."},{"start":2555,"end":2561,"text":"Spam, scams, and phishing schemes will keep evolving just as the technology to stop them does."},{"start":2561,"end":2567,"text":"But if you know what to look for and what to avoid, you can keep your inbox that much safer."},{"start":2584,"end":2588,"text":"I''m not going to do a kitten video, but first you have to watch a shoe ad."},{"start":2588,"end":2592,"text":"Later, you open the Facebook app on your phone and guess what?"},{"start":2592,"end":2595,"text":"Sponsored post about a shoe sale."},{"start":2595,"end":2599,"text":"How do all of these sites know that you''re shopping for shoes?"},{"start":2599,"end":2603,"text":"Well, websites use various methods to track your browsing habits."},{"start":2603,"end":2613,"text":"Each site may only gather a little bit of information, but together, it forms a sort of digital profile that advertisers can use to learn all kinds of things about you."},{"start":2613,"end":2618,"text":"An advertiser can plant a small file on your computer called a tracking cookie,"},{"start":2618,"end":2623,"text":"which they can use to identify you the next time you visit one of the sites they advertise on."},{"start":2623,"end":2629,"text":"They can also get a pretty good idea of which devices you use based on your social media and email accounts,"},{"start":2629,"end":2633,"text":"or by using a technique called probabilistic matching,"},{"start":2633,"end":2637,"text":"which makes educated guesses about which devices belong to the same person."},{"start":2637,"end":2641,"text":"So one way or another, all of your devices are connected to you,"},{"start":2641,"end":2647,"text":"and that means companies can send you targeted ads no matter which device you''re using."},{"start":2647,"end":2652,"text":"This does raise some privacy concerns since the information is collected without your knowledge,"},{"start":2652,"end":2656,"text":"and there is a fear of how this information could possibly be used."},{"start":2656,"end":2663,"text":"For instance, could an insurance company deny coverage based on a person''s browsing history?"},{"start":2663,"end":2669,"text":"You can take steps to limit the amount of data collected, such as blocking tracking cookies in your browser settings,"},{"start":2669,"end":2674,"text":"but with the current sophistication of tracking, they''re pretty easy to get around."},{"start":2674,"end":2677,"text":"However, there are potential upsides to all this data being collected."},{"start":2677,"end":2681,"text":"It allows sites to recommend articles and videos based on your interests,"},{"start":2681,"end":2686,"text":"and helps search engines more quickly find the results you''re looking for."},{"start":2686,"end":2692,"text":"As the technology continues to advance, sites will find new ways to tailor their content to better meet your needs."},{"start":2692,"end":2696,"text":"It''s hard to say exactly where this will lead, but for better or worse,"},{"start":2696,"end":2699,"text":"digital tracking is part of the modern online reality."},{"start":2706,"end":2712,"text":"If you''re just getting started with Windows, learning how to navigate the interface is a great place to start."},{"start":2712,"end":2716,"text":"Let''s take a look at the desktop, which is the screen you see here."},{"start":2716,"end":2724,"text":"It includes a desktop background, also known as your wallpaper, and the taskbar at the bottom of the screen."},{"start":2724,"end":2732,"text":"The taskbar is where you''ll find shortcuts to some of the applications on your computer, as well as the start button."},{"start":2732,"end":2740,"text":"In most versions of Windows, you can click the start button to see a list of applications, files, and settings."},{"start":2740,"end":2748,"text":"But if you''re using Windows 8, you can click the start button to return to the start screen."},{"start":2748,"end":2755,"text":"The taskbar is also where you''ll find File Explorer, which allows you to view and open files and folders."},{"start":2755,"end":2760,"text":"For now, I''m going to close the window by clicking the X."},{"start":2760,"end":2763,"text":"Let''s check out more features on the desktop instead."},{"start":2763,"end":2767,"text":"The desktop is the main workspace for your computer."},{"start":2767,"end":2773,"text":"To open a program, file, or folder, just double-click the icon."},{"start":2773,"end":2778,"text":"Each time you want to open something, it will appear in a new window."},{"start":2778,"end":2783,"text":"You have the ability to move windows by clicking and dragging the top of the window."},{"start":2783,"end":2786,"text":"When you''re done, just release the mouse."},{"start":2786,"end":2795,"text":"If you have more than one window open at a time, you can quickly switch between them by clicking the icon for that window on the taskbar."},{"start":2795,"end":2801,"text":"Almost all windows allow you to maximize the window so that it fills the entire screen."},{"start":2801,"end":2804,"text":"Just click the button here."},{"start":2804,"end":2809,"text":"Click the button again to return the window to its original size."},{"start":2809,"end":2815,"text":"When you''re finished, closing the window is easy. Just click the X."},{"start":2815,"end":2817,"text":"That covers the basics."},{"start":2817,"end":2827,"text":"Now that you know your way around windows, you can start taking advantage of everything it has to offer."},{"start":2827,"end":2834,"text":"If you are just getting started with OS X, learning how to navigate the interface is a great place to start."},{"start":2834,"end":2839,"text":"First, we''re going to take a look around at the desktop, which is the screen you see here."},{"start":2839,"end":2849,"text":"It includes a desktop background, also known as your wallpaper, the menu bar at the top, and the dock at the bottom."},{"start":2849,"end":2858,"text":"The dock is where you''ll find shortcuts to some of the folders and applications on your computer, for example, iTunes, Safari, and Finder."},{"start":2858,"end":2863,"text":"To open any of the items on your dock, just click the icon."},{"start":2863,"end":2869,"text":"There are actually several different ways that you can navigate to files, folders, and apps in OS X."},{"start":2869,"end":2871,"text":"The Finder feature is one of them."},{"start":2871,"end":2874,"text":"We''ll talk more about how to use the Finder later, though."},{"start":2874,"end":2880,"text":"For now, I''m going to close the window by clicking the red button in the upper left corner."},{"start":2880,"end":2885,"text":"Let''s check out Launchpad instead, which you can also find on your dock."},{"start":2885,"end":2894,"text":"As you can see, Launchpad gives you access to all of your applications at once, making it easier to find and access the programs on your computer."},{"start":2894,"end":2898,"text":"To open a program, click the one you want."},{"start":2899,"end":2902,"text":"Exiting applications is just as easy."},{"start":2902,"end":2906,"text":"Let''s zoom in on the menu bar so you can see how it works."},{"start":2906,"end":2912,"text":"To exit an application, click the name of the app in the upper left corner."},{"start":2912,"end":2916,"text":"Then, choose Quit from the menu."},{"start":2916,"end":2920,"text":"Also on the menu bar is the Apple icon."},{"start":2920,"end":2927,"text":"This gives you access to your system preferences, recent files, folders, apps, and much more."},{"start":2927,"end":2933,"text":"You''ll also use the Apple icon whenever you want to restart or shut down your computer."},{"start":2933,"end":2939,"text":"On the right side of the menu bar, you''ll find an icon that looks like a magnifying glass."},{"start":2939,"end":2946,"text":"This opens a feature called Spotlight, which you can use to search the contents of your computer if you''re having trouble finding something."},{"start":2946,"end":2953,"text":"Just type what you''re looking for, for example, a file or an app, and you''ll get a list of search results."},{"start":2955,"end":2963,"text":"The last icon in the menu bar opens the Notification Center, which has been included in each version of OS X since Mountain Lion."},{"start":2963,"end":2971,"text":"Here, you can keep track of the alerts you receive for different applications, including events on your calendar, reminders, and more."},{"start":2971,"end":2977,"text":"The Notification Center can be customized to show as few or as many alerts as you want."},{"start":2977,"end":2984,"text":"The desktop itself is one more place where you can store files, folders, and even shortcuts for easy access."},{"start":2984,"end":2992,"text":"This time, however, to open an item, you''ll need to double-click your mouse."},{"start":2992,"end":2999,"text":"Some apps have a full-screen mode that you can activate by clicking the double arrow in the upper right corner."},{"start":2999,"end":3006,"text":"This causes the window to expand, so you can focus on the application without any other distractions."},{"start":3006,"end":3012,"text":"To return to normal view, press Ctrl-Cmd-F on your keyboard."},{"start":3013,"end":3021,"text":"Not all apps support this feature, but it''s available in several of the apps that come pre-installed on your computer."},{"start":3021,"end":3028,"text":"The last thing I''d like to talk about is using your mouse in OS X, specifically a feature called natural scrolling."},{"start":3028,"end":3038,"text":"You can learn more about how it works by going to System Preferences, then choosing Mouse or Trackpad depending on what you have."},{"start":3038,"end":3044,"text":"In this case, we''ll choose Mouse."},{"start":3044,"end":3049,"text":"As you can see from the demo, natural scrolling is basically the reverse of traditional scrolling."},{"start":3049,"end":3054,"text":"It''s almost like you''re pushing the content up and down on the page."},{"start":3054,"end":3059,"text":"This may seem awkward at first, but it''s actually how many touchscreen devices work."},{"start":3059,"end":3065,"text":"Natural scrolling is the default setting, but you can always disable it by checking the box here."},{"start":3065,"end":3070,"text":"I recommend trying it both ways to see which one you prefer."},{"start":3070,"end":3076,"text":"While you''re in this window, you can also take a look at multi-touch gestures."},{"start":3076,"end":3082,"text":"For example, here''s one that lets you go back and forth between pages using a simple swipe."},{"start":3082,"end":3092,"text":"OS X supports many different types of gestures, including pinches, taps, and double taps, depending on what your mouse or trackpad is capable of."},{"start":3092,"end":3095,"text":"Each gesture performs a specific task."},{"start":3095,"end":3101,"text":"To learn more, I recommend visiting this resource again once you become more familiar with OS X."},{"start":3101,"end":3103,"text":"That covers the basics."},{"start":3103,"end":3113,"text":"Now that you know your way around, you can start using OS X and taking advantage of everything it has to offer."},{"start":3113,"end":3117,"text":"A web browser is a tool you use to access the Internet."},{"start":3117,"end":3123,"text":"In order to make the most out of the Internet, it''s important to understand the basics of using a web browser."},{"start":3123,"end":3130,"text":"There are many different web browsers, including Chrome, Safari, Firefox, and Internet Explorer."},{"start":3130,"end":3138,"text":"All of them allow you to view websites, but they each have a different look and feel, so picking one will depend mostly on your personal preference."},{"start":3138,"end":3140,"text":"Right now, I''m using Chrome."},{"start":3140,"end":3145,"text":"When you open your browser, at the top of the window, you''ll see the address bar."},{"start":3145,"end":3152,"text":"This is where you''ll type the web address of the page that you want to visit."},{"start":3152,"end":3159,"text":"If you''ve been to a website before, your browser may suggest it, or even automatically complete the address for you."},{"start":3159,"end":3168,"text":"If you see the address you''re looking for in the suggestions, you can just click it, or press Enter when you''re done typing."},{"start":3168,"end":3175,"text":"Most of the time, you''re going to go from one page to another by clicking on links."},{"start":3175,"end":3181,"text":"To go back to the page you were just on, you can click the Back button."},{"start":3181,"end":3188,"text":"To return to the first page, click the Forward button."},{"start":3188,"end":3195,"text":"If you see a link that you want to click but you don''t want to navigate away from the page that you''re on, you can open the link in a new tab."},{"start":3195,"end":3202,"text":"Just right-click the link and select Open in New Tab."},{"start":3202,"end":3208,"text":"This opens the page behind the current page so it doesn''t take you away from the original site."},{"start":3208,"end":3220,"text":"You can also create a new tab by clicking here, and then typing in the address or name of any site you want to visit."},{"start":3221,"end":3225,"text":"To close a tab, just click the X."},{"start":3225,"end":3232,"text":"If you''re on a website that you know you''ll want to visit again later, or a website that you go to frequently, you can bookmark it."},{"start":3232,"end":3242,"text":"Most browsers have a button right next to the address bar that lets you easily bookmark any site."},{"start":3242,"end":3246,"text":"Once you''ve bookmarked a page, you''ll be able to go to it again."},{"start":3246,"end":3258,"text":"In Chrome, you''ll click the Settings button, select Bookmarks, and then select the website you''re looking for from the list."},{"start":3258,"end":3262,"text":"Even if you don''t bookmark a site, there''s still a way to find it again later."},{"start":3262,"end":3267,"text":"Your browser keeps track of all the websites you visit in a feature called History."},{"start":3267,"end":3270,"text":"All browsers allow you to access your history."},{"start":3270,"end":3277,"text":"In Chrome, you can access this by clicking the Settings button."},{"start":3277,"end":3281,"text":"You can then click on a site to go to it."},{"start":3281,"end":3287,"text":"And as you may remember from before, you can begin typing in the address bar and your browser will make suggestions."},{"start":3287,"end":3291,"text":"These suggestions come from your history and bookmarks."},{"start":3291,"end":3297,"text":"The locations of these buttons and other options may vary a little depending on which browser you''re using."},{"start":3297,"end":3303,"text":"But you should be able to perform all of the same actions, no matter which browser you decide to use."}]'::jsonb
) AS segment
WHERE l.youtube_video_id = 'y2kg3MOk1sY';